-- Poems batch 287
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8c718cef-ad2b-4b07-88b4-1383549ccc19','鴻門','張碧','宋','宋诗','song-poetry','','[]','毒龍銜日天地昏，八紘靉靆生愁雲。',272,'全唐诗/poet.song.252000.json','["毒龍銜日天地昏，八紘靉靆生愁雲。", "秦原走鹿無藏處，紛紛爭處圍成群。", "四溟波立鯨相吞，薄摇五嶽崩山根。", "魚蝦舞浪狂鰍鯤，龍蛇膽戰登鴻門。", "星旗羽簇强者尊，黑風白雨東西屯。", "山河欲拆人烟分，壯士鼓勇君王存。", "項莊憤氣吐不得，亞父斗聲天上聞，玉光墜地驚崑崙。", "留侯氣魄吞太平，舌頭一寸生陽春。", "神農女媧愁不言，蛇枯老嫗啼淚痕。", "星曹定秤稱王孫，項籍骨輕迷精魂，沛公仰面爭乾坤。", "須臾垓下賊星起，歌聲繚繞淒人耳。", "吳娃捧酒橫秋波，霜天月照空城壘。", "力拔山兮忽到此，騅嘶懶渡烏江水。", "新豐瑞氣生樓臺，西楚寒蒿哭愁鬼。", "三尺霜鳴金匣裏，神光一照八千里。", "漢皇驟馬意氣生，西南掃地迎天子。"]'),
('1026df3f-7d09-4908-849a-f0b8a1ad611a','通真觀','李堅','宋','宋诗','song-poetry','','[]','璇璿非復舊宮壇，獨向徐碑識二難。',32,'全唐诗/poet.song.252000.json','["璇璿非復舊宮壇，獨向徐碑識二難。", "井底丹靈勿輕汲，昔年曾壽兩蒼官。"]'),
('b97dd782-c719-4133-b0da-bd65b874e930','沖寂觀','李堅','宋','宋诗','song-poetry','','[]','玉兔朝天去不回，空餘露井薦晨杯。',32,'全唐诗/poet.song.252000.json','["玉兔朝天去不回，空餘露井薦晨杯。", "屋鈴不語湖如掌，無復凌空逸士來。"]'),
('36442b59-a6c6-40bb-8f77-3d02cf35ec4b','余皮','李堅','宋','宋诗','song-poetry','','[]','小試屠龍技已成，遺蹤千載讋英靈。',32,'全唐诗/poet.song.252000.json','["小試屠龍技已成，遺蹤千載讋英靈。", "舳艫不駭風波惡，煙雨時聞草木腥。"]'),
('a02a6a95-5e2d-4a26-9981-4acd9c323951','離群村','李堅','宋','宋诗','song-poetry','','[]','好風吹句落煙村，便作棠陰記使君。',32,'全唐诗/poet.song.252000.json','["好風吹句落煙村，便作棠陰記使君。", "渠有平生絕塵想，群居那得似離群。"]'),
('f37f4e8a-5459-457a-8985-7f2423c4406b','句','李堅','宋','宋诗','song-poetry','','[]','勿訝韋郎誇酷似，情知蘇子賦歸來。',16,'全唐诗/poet.song.252000.json','["勿訝韋郎誇酷似，情知蘇子賦歸來。"]'),
('5675cc57-ef06-4316-af76-2d2a836e1c22','句','吳僧','宋','宋诗','song-poetry','','[]','到江吳地盡，隔岸越山多。',12,'全唐诗/poet.song.252000.json','["到江吳地盡，隔岸越山多。"]'),
('229618c2-2eab-43f7-8d49-77a165961b6e','偶成','吳明老','宋','宋诗','song-poetry','','[]','西風颯颯動長林，斗酒沽來伴月斟。',64,'全唐诗/poet.song.252000.json','["西風颯颯動長林，斗酒沽來伴月斟。", "慷慨未應憂短褐，悲歌元不爲秋砧。", "誰云塞馬年年健，自是君門浩浩深。", "世祖丰神似高帝，楚囚珍重莫霑襟。"]'),
('83d7f53a-9708-4376-bfcd-34c910dba4ad','閣皁山','劉遂初','宋','宋诗','song-poetry','','[]','春山靈草百花香，誰識仙家日月長。',32,'全唐诗/poet.song.252000.json','["春山靈草百花香，誰識仙家日月長。", "滿院莓苔綠陰匝，棋聲何處隔宮牆。"]'),
('9a92bd43-074a-4ecc-842d-c60b63cd332b','句  其一','武允蹈','宋','宋诗','song-poetry','','[]','露萱鉗宿蝶，風木撼鳴鳩。',12,'全唐诗/poet.song.252000.json','["露萱鉗宿蝶，風木撼鳴鳩。"]'),
('9a2e1b1e-dbc9-4d14-9f00-3df4fcff8584','句  其二','武允蹈','宋','宋诗','song-poetry','','[]','屋頭風過雁，燈背月移窗。',12,'全唐诗/poet.song.252000.json','["屋頭風過雁，燈背月移窗。"]'),
('130bda86-944b-48f5-a9ed-aef099804e6d','句  其三','武允蹈','宋','宋诗','song-poetry','','[]','霜林五色錦，烟渡一縈絲。',12,'全唐诗/poet.song.252000.json','["霜林五色錦，烟渡一縈絲。"]'),
('a280584a-b3eb-407d-b062-8a4b1d18e950','句  其四','武允蹈','宋','宋诗','song-poetry','','[]','午簟展風供睡課，夜窗扃雨辦詩逋。',16,'全唐诗/poet.song.252000.json','["午簟展風供睡課，夜窗扃雨辦詩逋。"]'),
('1ec37cf4-9c4c-4698-887b-5ed7e4a0a297','句  其五','武允蹈','宋','宋诗','song-poetry','','[]','眼昏書字不著紙，耳重聽言常問人。',16,'全唐诗/poet.song.252000.json','["眼昏書字不著紙，耳重聽言常問人。"]'),
('18c4c2f2-28fd-4309-bd4a-5cd947d7e080','題壁','無名氏','宋','宋诗','song-poetry','','[]','山行險而脩，老我驂且羸。',84,'全唐诗/poet.song.252000.json','["山行險而脩，老我驂且羸。", "獨驅六月暑，躡此千仞梯。", "世故不貸人，牽去復挽歸。", "茗盌參世味，甘苦常相持。", "白雲抱溪石，令人心愧之。", "豈無趺座處，逸固不療饑。", "大叫天上人，凉風爲吹衣。"]'),
('9830e552-86ba-4cfd-9893-2a85ce40ef52','句','劉清軒','宋','宋诗','song-poetry','','[]','可笑吳癡亡越憾，却誇范蠡作三高。',16,'全唐诗/poet.song.252000.json','["可笑吳癡亡越憾，却誇范蠡作三高。"]'),
('b9abeacc-36bb-4e9e-828c-82457a06a4dd','句','淮安守','宋','宋诗','song-poetry','','[]','一從楚客死，淮山無顔色。',12,'全唐诗/poet.song.252000.json','["一從楚客死，淮山無顔色。"]'),
('afb9c778-58a3-4d6a-babd-b70fbc4499ac','小說引子  其一','羅燁','宋','宋诗','song-poetry','','[]','靜坐閑窗對短檠，曾將往事廣搜尋。',64,'全唐诗/poet.song.252000.json','["靜坐閑窗對短檠，曾將往事廣搜尋。", "也題流水高山句，也賦陽春白雪吟。", "世上是非難入耳，人間名利不關心。", "編成風月三千卷，散與知音論古今。"]'),
('26a5ce84-ad47-418a-96ac-47d6c80e57c0','小說引子  其二','羅燁','宋','宋诗','song-poetry','','[]','傳自鴻荒判古初，羲農黄帝立規模。',128,'全唐诗/poet.song.252000.json','["傳自鴻荒判古初，羲農黄帝立規模。", "無爲少昊更顓帝，相授高辛唐及虞。", "位禪夏商周列國，權歸秦漢楚相誅。", "兩京中亂生王莽，三國爭雄魏蜀吳。", "西晉洛陽終四世，再興建鄴復其都。", "宋齊梁魏分南北，陳滅周亡隋易孤。", "唐世末年稱五代，宋承周禪握乾符。", "子孫神聖膺天命，萬載昇平復版圖。"]'),
('7adfdd44-590d-4219-8aa8-993e841aa3d9','小說引子  其三','羅燁','宋','宋诗','song-poetry','','[]','破盡詩書泣鬼神，發揚義士顯忠臣。',32,'全唐诗/poet.song.252000.json','["破盡詩書泣鬼神，發揚義士顯忠臣。", "試開戛玉敲金口，說與東西南北人。"]'),
('9a7b1434-a06d-4cf2-a218-b07294535f25','小說引子  其四','羅燁','宋','宋诗','song-poetry','','[]','春濃花艷佳人膽，月黑風寒壯士心。',32,'全唐诗/poet.song.252000.json','["春濃花艷佳人膽，月黑風寒壯士心。", "講論只憑三寸舌，秤評天下淺和深。"]'),
('7fdac0b4-8dbd-4484-a62f-728028713a24','小說開闢','羅燁','宋','宋诗','song-poetry','','[]','小說紛紛皆有之，須憑實學是根基。',96,'全唐诗/poet.song.252000.json','["小說紛紛皆有之，須憑實學是根基。", "開天闢地通經史，博古明今歷傳奇。", "藏藴滿懷風與月，吐談萬卷曲和詩。", "辨論妖怪精靈話，分別神仙達士機。", "涉案鎗刀并鐵騎，閨情雲雨共偷期。", "世間多少無窮事，歷歷從頭說細微。"]'),
('b7327ef7-0c03-4297-aba8-645a0bfe5590','嘲林叔茂私挈楚娘','無名氏','宋','宋诗','song-poetry','','[]','三山城內有神仙，一個夫人一個偏。',64,'全唐诗/poet.song.252000.json','["三山城內有神仙，一個夫人一個偏。", "開口笑時真似品，直身眠處恰如川。", "並頭難敘胸中事，欹枕須防背後拳。", "王愷石崇池裏藕，分明兩個大家蓮。"]'),
('aeb5c115-db69-4ab6-b8eb-01a14a2728be','上元','田太靖','宋','宋诗','song-poetry','','[]','元宵燈火照樓臺，車馬駢駢去又來。',32,'全唐诗/poet.song.252000.json','["元宵燈火照樓臺，車馬駢駢去又來。", "田郎試向樓上望，燈前好個阿孩孩。"]'),
('7123355a-5ccd-4f69-9c0a-3f6606dc08d1','繙帙得菊葉','劉元茂','宋','宋诗','song-poetry','','[]','何年霜後黄花葉，色蠹猶存舊卷詩。',32,'全唐诗/poet.song.252000.json','["何年霜後黄花葉，色蠹猶存舊卷詩。", "曾是往來籬下讀，一枝閑弄被風吹。"]'),
('52198c14-13d2-4cf0-9aa0-bd54d08ef65f','次花翁覽鏡韻','劉元茂','宋','宋诗','song-poetry','','[]','世事磨礲石退稜，此心何愛復何憎。',64,'全唐诗/poet.song.252000.json','["世事磨礲石退稜，此心何愛復何憎。", "門因候客時時掃，樓爲看山日日登。", "分粟可留巢樹鶴，種蔬堪供在家僧。", "形容每笑臨清鏡，相對駸駸作老朋。"]'),
('ce54ba50-ac8e-4e89-9b9e-8528566960c2','冷泉亭','曹既明','宋','宋诗','song-poetry','','[]','朱簷日轉軒窗冷，碧嶂雲低草樹香。',32,'全唐诗/poet.song.252000.json','["朱簷日轉軒窗冷，碧嶂雲低草樹香。", "山影倒沈波底月，夜闌相對寫寒光。"]'),
('d94123b4-30da-482d-b53f-bc5901344022','過林和靖舊址','曹既明','宋','宋诗','song-poetry','','[]','短棹不歸雙鶴去，一邱煙草寄山陰。',32,'全唐诗/poet.song.252000.json','["短棹不歸雙鶴去，一邱煙草寄山陰。", "水邊疏影黄昏月，無限風騷在客心。"]'),
('75c49fd0-bf6e-4e01-adfb-5821d93c8538','夜宿浙江亭','曹既明','宋','宋诗','song-poetry','','[]','夜半潮聲撼客牀，卧聽柔櫓閙空江。',32,'全唐诗/poet.song.252000.json','["夜半潮聲撼客牀，卧聽柔櫓閙空江。", "驚回倦枕鄉關夢，海日烘山上曉窗。"]'),
('0168a534-1392-4a5b-8ab0-7e40af200baf','胥山廟  其一','曹既明','宋','宋诗','song-poetry','','[]','貫弓執矢一亡臣，未洗昭關客路塵。',64,'全唐诗/poet.song.252000.json','["貫弓執矢一亡臣，未洗昭關客路塵。", "道上乞飧逢漂女，江邊款渡得漁人。", "致君豈謂初無術，賣國由來別有因。", "文種墓空山脅冷，怒潮朝夕怨江濱。"]'),
('7255880e-0da5-4335-9b92-5c3f1a8facc1','胥山廟  其二','曹既明','宋','宋诗','song-poetry','','[]','間關欲雪父兄讎，底用平生錫蓋侯。',64,'全唐诗/poet.song.252000.json','["間關欲雪父兄讎，底用平生錫蓋侯。", "冤骨未沈吳月曉，征魂初返楚雲秋。", "西施正倚承恩貌，范蠡將移去國舟。", "尚向松陵親却敵，藁砧依舊在層樓。"]'),
('a54ec74e-a43c-40ba-9006-d8d3ea5f499f','胥山廟  其三','曹既明','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','堂堂武烈與文英，引劍呼天氣未平。',64,'全唐诗/poet.song.252000.json','["堂堂武烈與文英，引劍呼天氣未平。", "身後端知司禍福，生前直欲就功名。", "胥山未盡吳儂意，郢水猶傷楚客情。", "井里滿前靈宇壯，長江千古带高情。"]'),
('7c907282-1e6c-44c6-9ac9-1735e8c914c3','有懷湖山留題惠因院','曹既明','宋','宋诗','song-poetry','','[]','湖山平生親，松竹亦瓜葛。',48,'全唐诗/poet.song.252000.json','["湖山平生親，松竹亦瓜葛。", "深期說情話，跬步成契闊。", "豈無朝夕思，或以塵累奪。", "何當淡相從，長年席不割。"]'),
('3c186874-1401-4ce1-ae6d-36a3855bcecb','與同舍待浴靈芝寺','曹既明','宋','宋诗','song-poetry','','[]','一雨洗秋色，湖山增眼明。',48,'全唐诗/poet.song.252000.json','["一雨洗秋色，湖山增眼明。", "番番水中荷，作此凄凉聲。", "我輩等憔悴，客飯千里程。", "願言滌塵土，冠蓋臨華京。"]'),
('d8ee0f9f-ecf4-4a21-b1dd-63688c03b44e','釣臺題壁','無名氏','宋','宋诗','song-poetry','','[]','生涯千頃水雲寬，舒卷乾坤一釣竿。',32,'全唐诗/poet.song.252000.json','["生涯千頃水雲寬，舒卷乾坤一釣竿。", "夢裏偶然伸隻脚，渠知天子是何官。"]'),
('f21159f7-adfb-41b5-a6b5-c11cbc77d30a','題岳陽飛吟亭','無名氏','宋','宋诗','song-poetry','','[]','覓官千里赴神京，鍾老相傳蓋更傾。',32,'全唐诗/poet.song.252000.json','["覓官千里赴神京，鍾老相傳蓋更傾。", "未必無心唐事業，金丹一粒誤先生。"]'),
('4f27d78e-f067-4054-a96d-5c965ecdf7d3','夜雨剪春韮','劉允成','宋','宋诗','song-poetry','','[]','杜老情何恨，東風夜雨春。',24,'全唐诗/poet.song.252000.json','["杜老情何恨，東風夜雨春。", "炊粱留客款，剪韮薦時新。"]'),
('350d690f-04e4-44fc-9bdd-39cd237b72b6','嘲教授','徐用亨','宋','宋诗','song-poetry','','[]','誰把先生號冷官，令名深愧馥秋蘭。',64,'全唐诗/poet.song.252000.json','["誰把先生號冷官，令名深愧馥秋蘭。", "孟公豈是陳驚座，子夏元非杜小冠。", "涇渭合流雖若混，雲泥敻絕不相干。", "寄言世上多風鑑，一笑何妨改眼看。"]'),
('d7a09f48-5ce9-4d5e-9490-f58e1be1a79d','句','史文昌','宋','宋诗','song-poetry','','[]','閑雲盡日相隨逐，只有朱雲挽不來。',16,'全唐诗/poet.song.252000.json','["閑雲盡日相隨逐，只有朱雲挽不來。"]'),
('b1bb1395-dbda-4297-aa71-47f5ee2cae2d','題雪獵圖','王平子','宋','宋诗','song-poetry','','[]','烽火一息三千年，漢家將軍畫凌煙。',160,'全唐诗/poet.song.252000.json','["烽火一息三千年，漢家將軍畫凌煙。", "胡兒不識征戰事，龍沙萬里今桑田。", "麗譙聲裏梅花角，雲暗雪深風色惡。", "長嘶一騎驄蟬聯，狼帽氈裘寒矍鑠。", "韝鷹走犬登平岡，狂狐剔眼魂飛揚。", "貫鵰落雁真戲劇，高鳥略盡良弓藏。", "鳳鳴居士雙眼碧，少年讀書勇無敵。", "但知橫行翰墨場，豈料一禽終不獲。", "向來百非今已無，筆端有口聊自娛。", "故將胸中磊落事，寫作人間雪獵圖。"]'),
('f8e9bc24-1a3d-4d8f-8db5-09056345372c','句','□革','宋','宋诗','song-poetry','','[]','醉輕浮世事，老重故鄉人。',12,'全唐诗/poet.song.252000.json','["醉輕浮世事，老重故鄉人。"]'),
('1b18c68b-8b79-4bd8-809c-2ecef7e406e9','夢魚','無名氏','宋','宋诗','song-poetry','','[]','玉燭和薰日，金穰瑞應初。',24,'全唐诗/poet.song.252000.json','["玉燭和薰日，金穰瑞應初。", "豐年知有象，吉夢兆維魚。"]'),
('f511f26e-74f8-40df-9f03-b270b26b15a7','斬蛇','無名氏','宋','宋诗','song-poetry','','[]','皇統承堯運，朱旗啟漢家。',24,'全唐诗/poet.song.252000.json','["皇統承堯運，朱旗啟漢家。", "未誅秦始鹿，先斬沛中蛇。"]'),
('5676409f-ed7c-4d32-91e5-6c4c0a3ba4df','賦以鶴羽代銀甲','琴士','宋','宋诗','song-poetry','','[]','嶧陽孤桐鳴素絲，玉爲軫兮金爲徽。',96,'全唐诗/poet.song.252000.json','["嶧陽孤桐鳴素絲，玉爲軫兮金爲徽。", "四珍合就已奇絕，猶嫌指聲未清徹。", "負金翅管長且尖，剪成爪樣鸞膠粘。", "輕絃入手剩超越，却笑彈箏後銀甲。", "要知妙處豈在聲，一撫一拍如淵明。", "勸君會此不須話，世不宜真只宜假。"]'),
('52910243-11d1-40aa-a28b-f5c920b833e0','登科後解嘲','詹文','宋','宋诗','song-poetry','','[]','讀盡詩書五六擔，老來方得一青衫。',32,'全唐诗/poet.song.252000.json','["讀盡詩書五六擔，老來方得一青衫。", "佳人問我年多少，五十年前二十三。"]'),
('652a0371-3395-41e2-afdf-dc45db82e29e','戲悼如禪師','嵩禪師','宋','宋诗','song-poetry','','[]','繼祖當吾代，生緣行可規。',48,'全唐诗/poet.song.252000.json','["繼祖當吾代，生緣行可規。", "終身常在道，識病懶尋醫。", "貌古筆難寫，情高世莫知。", "慈雲布何處，孤月自相宜。"]'),
('a3bba1c7-b047-4115-afdd-4c4d0094fb57','答嵩禪師','如禪師','宋','宋诗','song-poetry','','[]','道契平生更有誰，閑卿於我最心知。',32,'全唐诗/poet.song.252000.json','["道契平生更有誰，閑卿於我最心知。", "當初未欲成相別，恐誤同參一首詩。"]'),
('bd86f806-d93e-41bf-9b8f-d956840a7f2a','梅花曲  其一','易士達','宋','宋诗','song-poetry','','[]','老樹槎芽知幾年，結根更在蒼崖巔。',32,'全唐诗/poet.song.252000.json','["老樹槎芽知幾年，結根更在蒼崖巔。", "雪深三尺凍不折，春條森森臨風前。"]'),
('cacb7857-ec72-44f6-b000-0c0a2ee4ebbc','梅花曲  其二','易士達','宋','宋诗','song-poetry','','[]','春脚移從何處來，未到百花先到梅。',32,'全唐诗/poet.song.252000.json','["春脚移從何處來，未到百花先到梅。", "南枝初着三兩蘂，北枝沍寒猶未開。"]'),
('2e47dc1b-27e8-4e44-903e-d2a40ad03c00','梅花曲  其三','易士達','宋','宋诗','song-poetry','','[]','昨夜東風破寒臘，南枝北枝盡披拂。',32,'全唐诗/poet.song.252000.json','["昨夜東風破寒臘，南枝北枝盡披拂。", "不須羯鼓喧春雷，一點陽和香自發。"]'),
('7ba49ae8-8896-403d-b183-8ac5bcef11bd','梅花','易士達','宋','宋诗','song-poetry','','[]','搜詩索笑傍簷梅，冷蕊疏花带雪開。',32,'全唐诗/poet.song.252000.json','["搜詩索笑傍簷梅，冷蕊疏花带雪開。", "莫把枯梢容易折，留看笑影上窗來。"]'),
('bb3d1f2a-0079-40ff-89e2-c58512927465','杜鵑花','易士達','宋','宋诗','song-poetry','','[]','輕剪梢頭薄薄羅，子規湔血恨難磨。',32,'全唐诗/poet.song.252000.json','["輕剪梢頭薄薄羅，子規湔血恨難磨。", "園林莫道香飛盡，嫩綠枝頭不用多。"]'),
('20ff495c-8c50-4562-a5cd-1c1f8c4151e5','虞美人草','易士達','宋','宋诗','song-poetry','','[]','霸業將衰漢業興，佳人玉帳醉難醒。',32,'全唐诗/poet.song.252000.json','["霸業將衰漢業興，佳人玉帳醉難醒。", "可憐血染原頭草，直至如今舞不停。"]'),
('c509dbe6-7525-4132-a704-1221c188c216','遊東湖','易士達','宋','宋诗','song-poetry','','[]','好是東湖近物華，微吟去路亦何賒。',64,'全唐诗/poet.song.252000.json','["好是東湖近物華，微吟去路亦何賒。", "兩堤柳影澹臺墓，十里荷香孺子家。", "淡淡煙籠僧寺靜，飄飄風颭酒旗斜。", "重來徙倚闌干久，天末殘陽噪暮鴉。"]'),
('c5b5f7cf-bbbe-44db-b051-5c6804dfa394','閑步西湖','易士達','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖風景絕繁華，兩岸荷香十萬家。',32,'全唐诗/poet.song.252000.json','["西湖風景絕繁華，兩岸荷香十萬家。", "除却孤山林處士，後來誰肯種梅花。"]'),
('bcb843db-f589-47c5-a46a-1f5836e4faa8','題鄧氏船齋','易士達','宋','宋诗','song-poetry','','[]','平生心樂水雲鄉，卜得書窗瞰碧塘。',32,'全唐诗/poet.song.252000.json','["平生心樂水雲鄉，卜得書窗瞰碧塘。", "自有濟川勳業在，不勞兩柁與風檣。"]'),
('611dda2d-3f1b-4c41-8f03-69474838cbac','化人臺','易士達','宋','宋诗','song-poetry','','[]','富貴功名一窖塵，白頭人送黑頭人。',32,'全唐诗/poet.song.252000.json','["富貴功名一窖塵，白頭人送黑頭人。", "若教總識玄玄理，劫火何曾焚法身。"]'),
('e3ba0b0e-e66d-4dca-b61a-b09b6bb3128d','莫愁村','易士達','宋','宋诗','song-poetry','','[]','千古行人說莫愁，荒村依舊石城頭。',32,'全唐诗/poet.song.252000.json','["千古行人說莫愁，荒村依舊石城頭。", "不知艇子今何在，漢水滔滔空自流。"]'),
('e9a50a12-b8f2-4710-988e-5440b560b08a','夜宿合塘舗借壁間韻  其一','易士達','宋','宋诗','song-poetry','','[]','對牀風雨話辛酸，客枕淒凉寐不安。',32,'全唐诗/poet.song.252000.json','["對牀風雨話辛酸，客枕淒凉寐不安。", "須信在家貧亦樂，征衫贏得带圍寬。"]'),
('e27bd34a-6f8c-49de-9d3c-75c6903266a1','夜宿合塘舗借壁間韻  其二','易士達','宋','宋诗','song-poetry','','[]','瀟瀟冷雨送昏黄，倫竹吟風到客窗。',32,'全唐诗/poet.song.252000.json','["瀟瀟冷雨送昏黄，倫竹吟風到客窗。", "短夢欲成腸已斷，明朝一嶺即旴江。"]'),
('933013a1-dd61-4298-9a33-d633439bf610','草屨','易士達','宋','宋诗','song-poetry','','[]','崎嶇只慣識羈情，足下忙穿子更輕。',32,'全唐诗/poet.song.252000.json','["崎嶇只慣識羈情，足下忙穿子更輕。", "近世宦途如紙薄，當知險處不須行。"]'),
('b7c4f32b-09b1-418f-b00e-685169f6047f','贈易數胡一鑑','易士達','宋','宋诗','song-poetry','','[]','學本先天造化中，希夷康節與磨礲。',32,'全唐诗/poet.song.252000.json','["學本先天造化中，希夷康節與磨礲。", "光明照破人心事，一片靈臺不是銅。"]'),
('34a8b366-0efd-4fd9-8882-8edb7d99ef3f','贈寫神吳子可','易士達','宋','宋诗','song-poetry','','[]','不數僧繇只數吳，丹青幻出活形模。',32,'全唐诗/poet.song.252000.json','["不數僧繇只數吳，丹青幻出活形模。", "問君寫盡人多少，寫得人心一片無。"]'),
('6c2065f0-da92-4b29-a15b-0b0f28a77b39','柳  其一','易士達','宋','宋诗','song-poetry','','[]','平生家住灞橋邊，別恨離愁總被牽。',32,'全唐诗/poet.song.252000.json','["平生家住灞橋邊，別恨離愁總被牽。", "輕薄老來猶不減，落花時節尚飛綿。"]'),
('0b780b33-4ea2-4cb4-93e5-fd0e21833a13','柳  其二','易士達','宋','宋诗','song-poetry','','[]','春工染就綠絲絛，織雨繰風拂灞橋。',32,'全唐诗/poet.song.252000.json','["春工染就綠絲絛，織雨繰風拂灞橋。", "可是韶光難繫着，暗教瘦損小蠻腰。"]'),
('da7cf78d-5430-4403-a9d3-6ebeb5d51d43','蘭花  其一','易士達','宋','宋诗','song-poetry','','[]','春到蘭芽分外長，不隨紅葉自低昂。',32,'全唐诗/poet.song.252000.json','["春到蘭芽分外長，不隨紅葉自低昂。", "梅花謝後知誰繼，付與幽花接續香。"]'),
('013a3121-df60-476e-9d4a-cfac222570d1','蘭花  其二','易士達','宋','宋诗','song-poetry','','[]','曲水流邊苔色浸，右軍遺墨動清吟。',32,'全唐诗/poet.song.252000.json','["曲水流邊苔色浸，右軍遺墨動清吟。", "蕙風和暢人非昔，香得山陰直到今。"]'),
('16b8d649-7b88-43cb-ba32-9c630b901c98','梅','易士達','宋','宋诗','song-poetry','','[]','月上吟窗疏影浮，暗香風動襲衣裘。',32,'全唐诗/poet.song.252000.json','["月上吟窗疏影浮，暗香風動襲衣裘。", "溫存留索巡簷笑，遮莫高樓起笛愁。"]'),
('47dce1f5-d59d-4098-9b8d-aa41d2a437a2','梅花吟','易士達','宋','宋诗','song-poetry','','[]','孤山和靖真奇士，繞屋種梅清徹底。',80,'全唐诗/poet.song.252000.json','["孤山和靖真奇士，繞屋種梅清徹底。", "暗香和月透寒窗，壓盡幾多紅與紫。", "挨排花品果爲魁，南枝向暖首先開。", "當時疏影橫斜句，幾度吟從筆底來。", "勸君莫奏城頭角，吹得梢頭花片落。"]'),
('77c468d2-42d4-47fd-a985-76753cb441d2','和梅花韻','易士達','宋','宋诗','song-poetry','','["\u897f\u6e56"]','生愛梅兄是淡交，每相逢處更吟嘲。',64,'全唐诗/poet.song.252000.json','["生愛梅兄是淡交，每相逢處更吟嘲。", "暗香疏影名千古，冷艷孤光雪幾梢。", "東閣詩才猶腹稿，西湖人物尚衡茅。", "風前有恨曾知否，不得隨泥上燕巢。"]'),
('aa4d1276-3012-40fb-bbda-9b00d86c4423','梨花','易士達','宋','宋诗','song-poetry','','[]','滿院朝來白雪香，傷心遥想舊阿房。',32,'全唐诗/poet.song.252000.json','["滿院朝來白雪香，傷心遥想舊阿房。", "故園弟子今何在，春雨溶溶空斷腸。"]'),
('36dbce5a-42c0-44ed-a62d-06aa647d51c8','琴','易士達','宋','宋诗','song-poetry','','[]','花間橫膝興何深，流水高山幾古今。',32,'全唐诗/poet.song.252000.json','["花間橫膝興何深，流水高山幾古今。", "一自杏壇聲響絕，不知誰解繼遺音。"]'),
('4904f74e-cecb-4f08-a865-e28c5b0ed589','花朝燃燈','易士達','宋','宋诗','song-poetry','','[]','喚起園丁葺小園，喜逢社友訪林泉。',64,'全唐诗/poet.song.252000.json','["喚起園丁葺小園，喜逢社友訪林泉。", "鶑花世界春方半，燈火樓臺月正圓。", "閑不待偷皆樂地，趣隨所得到吟邊。", "丁寧莫剗庭前翠，留與遊人伴醉眠。"]'),
('ea7b65c6-9133-4adc-86c7-be15e94cc082','觀傀儡','易士達','宋','宋诗','song-poetry','','[]','刻出形骸假像真，一絲牽動便精神。',32,'全唐诗/poet.song.252000.json','["刻出形骸假像真，一絲牽動便精神。", "堪嗤鼓笛收聲後，依舊當時木偶人。"]'),
('c6401357-f169-427f-a04c-75c7b7c5bdb7','題雲石耕夫道院','易士達','宋','宋诗','song-poetry','','[]','片雲塊石一耕夫，耕得情田數畝餘。',64,'全唐诗/poet.song.252000.json','["片雲塊石一耕夫，耕得情田數畝餘。", "不用木金爲耒耜，祇將紙墨當菑畬。", "塞茅心撤猶芟草，翻水文成若决渠。", "三歲一番供貢籍，平時不用納王租。"]'),
('42962faf-9ce7-44e1-bdbf-6c62622989f2','黄陵廟','易士達','宋','宋诗','song-poetry','','[]','帝輦南遊竟不還，二妃望斷九疑山。',32,'全唐诗/poet.song.252000.json','["帝輦南遊竟不還，二妃望斷九疑山。", "森森萬古祠前竹，猶带當時粉淚斑。"]'),
('10586d30-e133-4351-9df3-e260c5c1ed59','洛陽','易士達','宋','宋诗','song-poetry','','[]','季龍方始是童時，視志觀聲已嘆奇。',32,'全唐诗/poet.song.252000.json','["季龍方始是童時，視志觀聲已嘆奇。", "嘯倚上都門外者，如何夷甫却先知。"]'),
('69f7471e-4fa6-48ab-a054-94bf5668d0f3','道中','易士達','宋','宋诗','song-poetry','','[]','梅雨絲絲未放晴，泥途賸作幾程行。',32,'全唐诗/poet.song.252000.json','["梅雨絲絲未放晴，泥途賸作幾程行。", "客懷方此無聊頼，更著啼鵑兩三聲。"]'),
('3d547c85-75cf-4dcd-be9c-87521c385df1','旴江道中','易士達','宋','宋诗','song-poetry','','[]','翠烟濃處著啼鵑，喚得韶光上柳綿。',32,'全唐诗/poet.song.252000.json','["翠烟濃處著啼鵑，喚得韶光上柳綿。", "父老已知農事急，一蓑烟雨辨秧田。"]'),
('bd87f031-d46f-47d8-a007-4c2bcadcc860','途間偶成','易士達','宋','宋诗','song-poetry','','[]','拂曉挑藤去路忙，倦投野店午炊香。',32,'全唐诗/poet.song.252000.json','["拂曉挑藤去路忙，倦投野店午炊香。", "閑看昔日題詩處，依舊榴花出短牆。"]'),
('f5b9c3b6-8933-4649-83c4-c3389bc52f26','小園','易士達','宋','宋诗','song-poetry','','[]','小園名涉趣，趣不在園花。',48,'全唐诗/poet.song.252000.json','["小園名涉趣，趣不在園花。", "樂水撐孤艇，愛山乘小車。", "淺深隨種藝，紅紫任交加。", "胸次藩籬剖，八荒同一家。"]'),
('44961e93-d7cf-47da-8ddf-073acd143ddd','金華山','易士達','宋','宋诗','song-poetry','','[]','岩室嵌空古洞天，初平曾此學昇仙。',32,'全唐诗/poet.song.252000.json','["岩室嵌空古洞天，初平曾此學昇仙。", "至今猶有爲羊石，散在蒼松夾道邊。"]'),
('5180e934-62f5-434f-bee9-c07add95d56d','古石磴','易士達','宋','宋诗','song-poetry','','[]','石磴嵌空不計年，青青薜荔带風烟。',32,'全唐诗/poet.song.252000.json','["石磴嵌空不計年，青青薜荔带風烟。", "謝公詩句今亡恙，祇有紅泉變玉泉。"]'),
('374c97ec-06c3-443c-94fb-e0425676ae4f','汴水','易士達','宋','宋诗','song-poetry','','[]','千里通渠竟達河，萬民力役怨聲多。',32,'全唐诗/poet.song.252000.json','["千里通渠竟達河，萬民力役怨聲多。", "錦帆不送龍舟返，併覆亡隋入巨波。"]'),
('c61f47f7-48e6-4987-a8d0-95a1c4321ace','漢陽渡','易士達','宋','宋诗','song-poetry','','[]','躍馬來遊漢水春，一杯聊買醮詩神。',32,'全唐诗/poet.song.252000.json','["躍馬來遊漢水春，一杯聊買醮詩神。", "茫茫鸚鵡洲邊渡，尺素誰能寄錦鱗。"]'),
('2f4f288d-f378-424e-95af-3ccde56d6824','江上','易士達','宋','宋诗','song-poetry','','[]','西風捲起五湖秋，萬頃波中幾白鷗。',32,'全唐诗/poet.song.252000.json','["西風捲起五湖秋，萬頃波中幾白鷗。", "好趁水雲深處隠，短蓬簑笠一扁舟。"]'),
('5a6ed4fd-294a-4208-882d-d8bdfb59873b','湖上','易士達','宋','宋诗','song-poetry','','[]','兩岸青帘簫鼓多，閑愁到此總消磨。',32,'全唐诗/poet.song.252000.json','["兩岸青帘簫鼓多，閑愁到此總消磨。", "湖光十里平如掌，穩泛輕舟擊楫歌。"]'),
('30f3ae52-5e80-4fce-a0fa-fa2973bf99a1','浯溪','易士達','宋','宋诗','song-poetry','','[]','阿瞞南幸國幾危，顛倒皆由豢祿兒。',32,'全唐诗/poet.song.252000.json','["阿瞞南幸國幾危，顛倒皆由豢祿兒。", "休說馬嵬當日事，浯溪且細讀元碑。"]'),
('f2db5ae4-7bcb-4ab2-9c26-b7fb738deb9e','題石溪偉觀','易士達','宋','宋诗','song-poetry','','[]','水共長天不盡頭，石溪奇處着危樓。',32,'全唐诗/poet.song.252000.json','["水共長天不盡頭，石溪奇處着危樓。", "我來倚徙闌干看，風撼蘆花葉葉秋。"]'),
('831e116c-03a3-4c42-bb07-d398cf28d598','溫泉','易士達','宋','宋诗','song-poetry','','[]','當日溫泉浴太真，豈知繡襪解塵生。',32,'全唐诗/poet.song.252000.json','["當日溫泉浴太真，豈知繡襪解塵生。", "更於洗滑凝脂處，尚憶胡兒在錦綳。"]'),
('da579015-6249-4e96-9cec-cb5c6d4bbab4','景陽井','易士達','宋','宋诗','song-poetry','','[]','白蓮閣下小方池，後主曾於此避隋。',32,'全唐诗/poet.song.252000.json','["白蓮閣下小方池，後主曾於此避隋。", "知擁二妃何處去，至今石脈带臙脂。"]'),
('f53faa7f-b227-4c02-850e-6b142e8c7f0d','柴桑山','易士達','宋','宋诗','song-poetry','','[]','千古先生節最高，功名識破等鴻毛。',32,'全唐诗/poet.song.252000.json','["千古先生節最高，功名識破等鴻毛。", "如今亦作柴桑隠，只把荷衣當綠袍。"]'),
('9a962195-0b71-448c-9465-c82071c283c3','山花','易士達','宋','宋诗','song-poetry','','[]','山花浥露靚晨粧，着向行邊自在香。',32,'全唐诗/poet.song.252000.json','["山花浥露靚晨粧，着向行邊自在香。", "遥想艷陽三二月，多應勾引蝶蜂忙。"]'),
('03d88b1d-30a7-4c32-9357-cc76bcd3311b','竺澗梅','易士達','宋','宋诗','song-poetry','','[]','疏枝冷蕊本清幽，不傍山林傍碧流。',32,'全唐诗/poet.song.252000.json','["疏枝冷蕊本清幽，不傍山林傍碧流。", "莫遣城頭吹畫角，恐驚花片動情愁。"]'),
('2e4d58fd-5e11-4820-90cf-5230ab9b9bb4','階笋','易士達','宋','宋诗','song-poetry','','[]','綠笋行春競着鞭，喜添嫩竹護階前。',32,'全唐诗/poet.song.252000.json','["綠笋行春競着鞭，喜添嫩竹護階前。", "兒童未識清風味，鋤取新苗供晚筵。"]'),
('517c245a-6f68-4273-8408-b6d227864d0e','二色桃','易士達','宋','宋诗','song-poetry','','[]','兩色桃花相映開，武陵移就小園栽。',32,'全唐诗/poet.song.252000.json','["兩色桃花相映開，武陵移就小園栽。", "玉環不奈蒲萄重，一半紅潮玉臉來。"]'),
('ff7727e1-cd8d-48dd-989c-806c724ca00c','苔錢','易士達','宋','宋诗','song-poetry','','[]','造化爲爐巧冶成，兒童指似五銖輕。',64,'全唐诗/poet.song.252000.json','["造化爲爐巧冶成，兒童指似五銖輕。", "買春無算空流地，潤屋何心望滿籝。", "祇恐癡人思宿債，枉教處士負貪聲。", "漢皇不吝銅山賜，羞殺申屠惡妒生。"]'),
('92827be1-665c-448d-8811-827490929eb2','途間觀野菊','易士達','宋','宋诗','song-poetry','','[]','林巒露骨草無芽，枯柳吟蟬蹟見沙。',32,'全唐诗/poet.song.252000.json','["林巒露骨草無芽，枯柳吟蟬蹟見沙。", "莫道西風全肅殺，行邊無處不黄花。"]'),
('207b7b56-f4d5-462a-81ae-e3779e67806f','和朋溪探梅韻','易士達','宋','宋诗','song-poetry','','[]','錦囊分付與溪奴，江路尋幽屬野夫。',64,'全唐诗/poet.song.252000.json','["錦囊分付與溪奴，江路尋幽屬野夫。", "暖信已傳春到未，暗香還動月明無。", "粧因底事偏清雅，態爲何人轉瘠癯。", "惹起詩魂禁不得，恍然飛越亦忘吾。"]'),
('e542dee6-48ef-4a9a-83ff-33cbbd93e78f','杜鵑  其一','易士達','宋','宋诗','song-poetry','','[]','一自連雲棧道開，杜鵑啼血濺莓苔。',32,'全唐诗/poet.song.252000.json','["一自連雲棧道開，杜鵑啼血濺莓苔。", "不如歸去無人聽，幾箇朝衣出蜀來。"]'),
('605617cd-903b-472d-b20d-1ceef68a941a','杜鵑  其二','易士達','宋','宋诗','song-poetry','','[]','西望茫茫濯錦磯，山川祇似舊家時。',32,'全唐诗/poet.song.252000.json','["西望茫茫濯錦磯，山川祇似舊家時。", "杜鵑苦勸人歸去，望帝有宮胡不歸。"]'),
('453391eb-13dd-40ea-a557-84ea8689e176','田野燕巢','易士達','宋','宋诗','song-poetry','','[]','莫問山村與水邊，何拘華屋且隨緣。',32,'全唐诗/poet.song.252000.json','["莫問山村與水邊，何拘華屋且隨緣。", "不成此地無王謝，枉了春光又一年。"]'),
('087ab839-4787-485b-a463-1af28df4a0a8','聞杜鵑再韻','易士達','宋','宋诗','song-poetry','','[]','片片桃花下釣磯，聲聲杜宇暮春時。',32,'全唐诗/poet.song.252000.json','["片片桃花下釣磯，聲聲杜宇暮春時。", "邇來夔峽多游子，正好從頭喚取歸。"]'),
('0fe11b64-e4df-460f-80e4-d8f1276196b6','題先月閣','易士達','宋','宋诗','song-poetry','','[]','新築亭臺分外凉，廣寒移下水雲鄉。',32,'全唐诗/poet.song.252000.json','["新築亭臺分外凉，廣寒移下水雲鄉。", "纔當暝色千山合，便有簷前一點光。"]'),
('62604e6f-298e-46cb-90bd-04467d8e3d5e','山家','易士達','宋','宋诗','song-poetry','','[]','萬木回環八九家，挑藤去去路欹斜。',32,'全唐诗/poet.song.252000.json','["萬木回環八九家，挑藤去去路欹斜。", "無端杜宇催春急，葉落山頭躑躅花。"]'),
('26e28e4c-7155-44cc-a8df-333ed9dac7d6','後坑茅舍','易士達','宋','宋诗','song-poetry','','[]','三兩人家傍小溪，蕭蕭短竹插疏籬。',32,'全唐诗/poet.song.252000.json','["三兩人家傍小溪，蕭蕭短竹插疏籬。", "平生不識興亡事，只探春來種穀時。"]'),
('c9db39d4-9ff2-45f3-a705-ab87aeb73c13','峴山亭','易士達','宋','宋诗','song-poetry','','[]','峴山亭是昔人非，忍讀羊公墮淚碑。',32,'全唐诗/poet.song.252000.json','["峴山亭是昔人非，忍讀羊公墮淚碑。", "回首山翁花下處，淒淒芳草晚風悲。"]'),
('e0faafc6-2c4d-46b2-99e5-c3038ff5343c','鎖江亭','易士達','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','鎖江水下水悠悠，只鎖長江不鎖愁。',32,'全唐诗/poet.song.252000.json','["鎖江水下水悠悠，只鎖長江不鎖愁。", "但存一樽澆旅思，圖教沉醉泛扁舟。"]'),
('00c62dfe-c5fc-40a2-8a17-e2bd6e23a8fd','山居自道','易士達','宋','宋诗','song-poetry','','[]','山林清富貴，何在玉堂居。',48,'全唐诗/poet.song.252000.json','["山林清富貴，何在玉堂居。", "詩積囊中錦，家多几上書。", "碑文堪帳壁，薇蕨當盤蔬。", "安分簞瓢樂，雖貧綽有餘。"]'),
('05d14b40-c173-4d62-9160-ef87f6f832eb','青陽驛','易士達','宋','宋诗','song-poetry','','[]','錦綳繡襪兩無成，幾把唐家國祚傾。',32,'全唐诗/poet.song.252000.json','["錦綳繡襪兩無成，幾把唐家國祚傾。", "帝宿青陽鈴鐸響，起來疑是鼓鼙聲。"]'),
('b86be168-5018-47fd-bb6a-07c87ded59c9','上亭驛','易士達','宋','宋诗','song-poetry','','[]','霏霏風送鐸悲鳴，大駕南巡宿上亭。',32,'全唐诗/poet.song.252000.json','["霏霏風送鐸悲鳴，大駕南巡宿上亭。", "驚起三郎魂欲斷，梨園猶唱雨淋鈴。"]'),
('5a3c2050-4ac3-43a2-b662-adf367ace172','蓬山館','易士達','宋','宋诗','song-poetry','','[]','庭館飛翬氣象雄，兩山峙秀傍蒼穹。',32,'全唐诗/poet.song.252000.json','["庭館飛翬氣象雄，兩山峙秀傍蒼穹。", "我來檢點多奇勝，恍在蓬萊第一宮。"]'),
('089a3afc-e557-4e09-a601-9434b23f4c06','春閨','易士達','宋','宋诗','song-poetry','','[]','燕語鶑啼觸撥儂，院深懶傍繡簾櫳。',64,'全唐诗/poet.song.252000.json','["燕語鶑啼觸撥儂，院深懶傍繡簾櫳。", "一年春事半晴雨，萬里雲帆幾夕風。", "柳欠溫存牽怨恨，萍無拘束自西東。", "此情莫向桃花說，說與桃花也落紅。"]'),
('1d127731-3fa8-4483-95ea-bbca0ed6aa3a','題妙智不俗軒','易士達','宋','宋诗','song-poetry','','[]','亭亭修竹兩三竿，鼓動天風掠鬢寒。',32,'全唐诗/poet.song.252000.json','["亭亭修竹兩三竿，鼓動天風掠鬢寒。", "一點紅塵飛不到，滿窗冰雪自相看。"]'),
('13645700-a5d0-443a-bccf-e5a821b8915a','滕王閣','易士達','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王歌舞舊城樓，一度登臨一度愁。',32,'全唐诗/poet.song.252000.json','["滕王歌舞舊城樓，一度登臨一度愁。", "惟有西山南浦景，教人千古說洪州。"]'),
('fdc22669-9bde-4e71-8992-d167f00362c9','巴子臺','易士達','宋','宋诗','song-poetry','','[]','東郊青土尚崔嵬，疑是巴王築此臺。',32,'全唐诗/poet.song.252000.json','["東郊青土尚崔嵬，疑是巴王築此臺。", "回首當時歌舞地，六宮今盡沒黄埃。"]'),
('d5982e43-cb2f-4919-a530-dabd9bfe9548','古繙經臺','易士達','宋','宋诗','song-poetry','','[]','仙人何代此繙經，疊石成臺掌面平。',32,'全唐诗/poet.song.252000.json','["仙人何代此繙經，疊石成臺掌面平。", "好是松風明月夜，恍然吹下步虛聲。"]'),
('de41aa94-35b7-4618-addb-ba1ee738946d','竹林傷田家','易士達','宋','宋诗','song-poetry','','[]','陰陰沈沈雨霏霏，農夫把秧妻抱兒。',80,'全唐诗/poet.song.252000.json','["陰陰沈沈雨霏霏，農夫把秧妻抱兒。", "前村後村歌相答，上畝下畝泥正肥。", "新穀登場腹不飽，新絲出盎身不絲。", "膏粱紈袴一笑樂，粉白黛綠千金揮。", "農家升苗一寸稅，里正打門星火追。"]'),
('a51d707e-ca03-4aa7-96bb-43eed4afcadd','登擬峴臺','易士達','宋','宋诗','song-poetry','','[]','叔子聲名千古香，幾多遺愛在襄陽。',32,'全唐诗/poet.song.252000.json','["叔子聲名千古香，幾多遺愛在襄陽。", "後來景行瞻先哲，善政豐碑共久長。"]'),
('d5cc5506-4fdb-46e4-a4c2-e3c990552d89','金山寺','易士達','宋','宋诗','song-poetry','','[]','浮圖突兀起江中，鎮壓東南氣象雄。',32,'全唐诗/poet.song.252000.json','["浮圖突兀起江中，鎮壓東南氣象雄。", "除却金山餘外地，蒼波何處不龍宮。"]'),
('a4eadb83-c82d-45b2-aaa6-2a06a55b4c5f','牛心寺','易士達','宋','宋诗','song-poetry','','[]','玉環妖國禍胎深，鼙鼓漁陽帝莫禁。',32,'全唐诗/poet.song.252000.json','["玉環妖國禍胎深，鼙鼓漁陽帝莫禁。", "不怨錦綳當日事，如何歸咎鑿牛心。"]'),
('e3d5dbc7-0ba6-405e-b2ca-04661fd8c87e','和李潤父資聖寺壁間韻','易士達','宋','宋诗','song-poetry','','[]','古徑縈迂碧蘚深，瘦藤得得叩叢林。',64,'全唐诗/poet.song.252000.json','["古徑縈迂碧蘚深，瘦藤得得叩叢林。", "雪浮茗枕陪僧話，風度松窗奏法音。", "斷壁剔蟲傷古畫，拂塵揮兔斷清吟。", "留衣尚有重來約，一笑何妨載酒尋。"]'),
('cc6df803-fabe-4c29-a38d-df461b32e4b2','育王塔','易士達','宋','宋诗','song-poetry','','[]','誰向鄞江立法門，育王鐘鼓振朝昏。',32,'全唐诗/poet.song.252000.json','["誰向鄞江立法門，育王鐘鼓振朝昏。", "閻浮八萬四千塔，應合相推此塔尊。"]'),
('0c8f09b0-b55a-41c1-9897-68197675fa8f','赤土崗一層塔','易士達','宋','宋诗','song-poetry','','[]','山矮仙靈偏起敬，水無深淺有龍韜。',32,'全唐诗/poet.song.252000.json','["山矮仙靈偏起敬，水無深淺有龍韜。", "近來不數稱尖者，此塔雖低反自高。"]'),
('7b6a8049-d6fc-4a56-b8a0-af148d69b776','題錢翁楊伯傳竹浦吟稿','易士達','宋','宋诗','song-poetry','','[]','關西今喜有雲仍，冰雪相看一樣清。',32,'全唐诗/poet.song.252000.json','["關西今喜有雲仍，冰雪相看一樣清。", "最是晚來江上處，飽聽葉□助詩聲。"]'),
('28771c36-a200-4f16-9fc1-42184527774e','題陳巽齋寒窗聽雪詩卷','易士達','宋','宋诗','song-poetry','','[]','彤雲黯淡釀天寒，却向江頭理釣船。',32,'全唐诗/poet.song.252000.json','["彤雲黯淡釀天寒，却向江頭理釣船。", "雪打蓬窗眠不著，聲聲時送到吟邊。"]'),
('4b55f574-1ec0-4e2e-a56a-583dcaa49f0d','題秋江烟草詩卷','易士達','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里長江浸碧流，煙籠細草滿孤洲。',32,'全唐诗/poet.song.252000.json','["萬里長江浸碧流，煙籠細草滿孤洲。", "吟懷到此難排遣，獨立斜陽古渡頭。"]'),
('55b79928-2cfc-4215-865b-7828579d8043','梅碑','易士達','宋','宋诗','song-poetry','','[]','冷蕊誰回筆底春，不教花落更紛紛。',32,'全唐诗/poet.song.252000.json','["冷蕊誰回筆底春，不教花落更紛紛。", "自從揭在吟窗裏，常带催詩一片雲。"]'),
('e9c99a88-fd1b-4ab0-a1bd-dc4780ab7edd','和宦叔送往臨川','易士達','宋','宋诗','song-poetry','','[]','征衣何惜染塵埃，款段搜詩亦快哉。',64,'全唐诗/poet.song.252000.json','["征衣何惜染塵埃，款段搜詩亦快哉。", "百里亭長與亭短，一天雲合復雲開。", "傾茅柴酒和餘粕，彈接䍦巾去薄塺。", "不是剡溪清興盡，聲聲杜宇勸歸來。"]'),
('19514632-6c00-4c61-a1fa-ed4086babb3f','句  其一','易士達','宋','宋诗','song-poetry','','[]','催趲荼䕷交夏景，安排芍藥送春光。',16,'全唐诗/poet.song.252000.json','["催趲荼䕷交夏景，安排芍藥送春光。"]'),
('d339926b-d80d-4f5c-bcdf-53d2f939df8c','句  其二','易士達','宋','宋诗','song-poetry','','[]','可堪收拾歸屏枕，頗欲浮沈赴酒杯。',16,'全唐诗/poet.song.252000.json','["可堪收拾歸屏枕，頗欲浮沈赴酒杯。"]'),
('02a1cd89-4152-40ab-9936-68cfed48ea85','梅花','陳亦梅','宋','宋诗','song-poetry','','[]','江郊車馬滿斜輝，爭赴城南未掩扉。',32,'全唐诗/poet.song.252000.json','["江郊車馬滿斜輝，爭赴城南未掩扉。", "要識梅花無盡藏，人人襟袖带香歸。"]'),
('e41617c2-062a-4344-939e-4643232fb274','梅花','徐介軒','宋','宋诗','song-poetry','','[]','香梅爛漫見紅梅，白白朱朱取次開。',32,'全唐诗/poet.song.252000.json','["香梅爛漫見紅梅，白白朱朱取次開。", "料得故園春色滿，有人花下正徘徊。"]'),
('3ac30b38-e23d-451f-8e26-40b5e7f23415','紅梅  其一','徐介軒','宋','宋诗','song-poetry','','[]','寒梅冷艷綴輕枝，誤認夭桃未放時。',32,'全唐诗/poet.song.252000.json','["寒梅冷艷綴輕枝，誤認夭桃未放時。", "盛飾霓裳陪越女，不施粉黛抹胭脂。"]'),
('f174dc63-6fe6-4bda-a8cf-2d2134e6a7ab','紅梅  其二','徐介軒','宋','宋诗','song-poetry','','[]','輕盈弄月醉霞觴，嬌軟酡顔褪曉粧。',32,'全唐诗/poet.song.252000.json','["輕盈弄月醉霞觴，嬌軟酡顔褪曉粧。", "縞素叢中紅一點，好花終是不尋常。"]'),
('9848960a-82c0-47a8-9b94-584d42972dc7','菊花','徐介軒','宋','宋诗','song-poetry','','[]','獨向鄰園看菊回，隔籬驚見一枝梅。',32,'全唐诗/poet.song.252000.json','["獨向鄰園看菊回，隔籬驚見一枝梅。", "西風憐我太寂寞，特地遣花將句來。"]'),
('26467fe5-9d35-4085-923c-bcdaa3ca7ff6','巖桂花','徐介軒','宋','宋诗','song-poetry','','[]','翠葉金華小膽瓶，輕拈微嗅不勝情。',32,'全唐诗/poet.song.252000.json','["翠葉金華小膽瓶，輕拈微嗅不勝情。", "從教失陷沈烟冷，驀地薰心夢也清。"]'),
('80a4f61b-e3b9-4958-81d8-1a33df5e64cd','桐','徐介軒','宋','宋诗','song-poetry','','[]','灝氣行秋萬宇凉，玄姑新敕辦衣裳。',64,'全唐诗/poet.song.252000.json','["灝氣行秋萬宇凉，玄姑新敕辦衣裳。", "林爲機杼織無跡，月當膏油緝易長。", "謂爾索裘雖有日，到頭無褐可禁霜。", "工夫只有琵琶索，又在梧桐夜雨旁。"]'),
('faa7d28b-7230-4c1b-aaee-d2ee04c82996','梅花','王梅窗','宋','宋诗','song-poetry','','[]','月淡碧雲籠野水，稜稜瘦聲吟肩起。',32,'全唐诗/poet.song.252000.json','["月淡碧雲籠野水，稜稜瘦聲吟肩起。", "一天寒氣霞衣裳，人在石橋春影裏。"]'),
('e306573c-2d4d-4f39-a967-5c55c11c91c2','寄畊綠','王梅窗','宋','宋诗','song-poetry','','[]','孤坐忽嘆息，故人成闊疏。',48,'全唐诗/poet.song.252000.json','["孤坐忽嘆息，故人成闊疏。", "別三來箇月，不得一封書。", "晴雪添岩瀑，寒冰沍野蔬。", "何時分席地，與爾共耕鋤。"]'),
('875bf6aa-180a-4fcd-b793-3c75fa859c20','秋日山中','王梅窗','宋','宋诗','song-poetry','','[]','客疏吟友少，終日掩柴門。',48,'全唐诗/poet.song.252000.json','["客疏吟友少，終日掩柴門。", "冒雨自分菊，带泥移上盆。", "泉添渾井脈，砧響動山根。", "片片西風葉，飛來有病添。"]'),
('c3d2ab4f-e5e0-4141-b5bf-d1a8c77e8e5e','梅花','釋輝','宋','宋诗','song-poetry','','[]','我見庭梅六十春，當時初見已輪囷。',32,'全唐诗/poet.song.252000.json','["我見庭梅六十春，當時初見已輪囷。", "人老只道梅花老，不道梅花老笑人。"]'),
('3efa6e37-f086-4dfe-8bc6-4f1b166312fb','古藤','釋輝','宋','宋诗','song-poetry','','[]','翠蓋陰森高隠鶴，修條屈曲暗藏蛇。',32,'全唐诗/poet.song.252000.json','["翠蓋陰森高隠鶴，修條屈曲暗藏蛇。", "閑來兀坐莓苔石，時見山禽撲落花。"]'),
('809f195b-0e79-4c1d-b637-58755b671ef4','木芙蓉','釋輝','宋','宋诗','song-poetry','','[]','霜深纔吐艷，日暮更饒紅。',24,'全唐诗/poet.song.252000.json','["霜深纔吐艷，日暮更饒紅。", "掩映殘荷浦，馮夷敗菊叢。"]'),
('4b3c0eee-2c73-4d1d-979d-a0daec6f0f1d','潤州','釋輝','宋','宋诗','song-poetry','','[]','北固樓前一笛風，斷雲飛出建章宮。',32,'全唐诗/poet.song.252000.json','["北固樓前一笛風，斷雲飛出建章宮。", "江南二月多芳草，春在濛濛細雨中。"]'),
('0d29628c-24d2-4cd0-a8b8-7d8cf4c5eaab','題洞靈觀','釋輝','宋','宋诗','song-poetry','','[]','古觀多松檜，幽期近暮秋。',48,'全唐诗/poet.song.252000.json','["古觀多松檜，幽期近暮秋。", "坐看新月上，閒見斷雲愁。", "野思同花鳥，鄉情隔島洲。", "輕寒披鶴氅，隠几自搔頭。"]'),
('222104c0-28c7-44e3-87c4-184af8fdf8c7','句','釋輝','宋','宋诗','song-poetry','','[]','丁寧童子休教掃，留取窗前當雪看。',16,'全唐诗/poet.song.252000.json','["丁寧童子休教掃，留取窗前當雪看。"]'),
('42912aae-6a29-4909-82e3-00f2df8565a2','梅花','楊平洲','宋','宋诗','song-poetry','','[]','支頤半睡月明中，仿佛仙人薄霧籠。',32,'全唐诗/poet.song.252000.json','["支頤半睡月明中，仿佛仙人薄霧籠。", "喚起夢魂簾幙悄，天香自到不因風。"]'),
('d42b3521-ef97-4820-815e-d9100bd6ecc4','紅梅','楊平洲','宋','宋诗','song-poetry','','[]','誰將醉裏春風面，換却平生玉雪身。',32,'全唐诗/poet.song.252000.json','["誰將醉裏春風面，換却平生玉雪身。", "頼得月明留瘦影，芳心香骨見天真。"]'),
('8482d3bf-eb44-424e-88f4-8c024661b750','芍藥','鄭雲林','宋','宋诗','song-poetry','','[]','與春相識亦多年，今歲春胡不到園。',32,'全唐诗/poet.song.252000.json','["與春相識亦多年，今歲春胡不到園。", "一任階前無芍藥，免教蜂蝶兩爭喧。"]'),
('909fe13c-cfbb-48f4-a85a-86242cc49779','海棠','鄭雲林','宋','宋诗','song-poetry','','[]','貪詩閑費一生心，水際雲崖到處尋。',32,'全唐诗/poet.song.252000.json','["貪詩閑費一生心，水際雲崖到處尋。", "可惜春花吾老矣，海棠烟雨閉門深。"]'),
('930d7cc0-25ef-452f-85da-0d7b4c6ef34b','含笑花','徐月溪','宋','宋诗','song-poetry','','[]','瓜香濃欲爛，蓮莟碧初勻。',24,'全唐诗/poet.song.252000.json','["瓜香濃欲爛，蓮莟碧初勻。", "含笑知何處，低頭似愧人。"]'),
('73b06271-f4d9-41fb-a20e-40d0ef7e7de9','山茶花','徐月溪','宋','宋诗','song-poetry','','[]','山茶又晚出，舊不聞圖經。',144,'全唐诗/poet.song.252000.json','["山茶又晚出，舊不聞圖經。", "花深嫌少態，曾入蘇公評。", "邇來亦變怪，紛然著名稱。", "黄香開最早，與菊爲輩朋。", "紛紅更妖艷，玉環带春酲。", "偉哉紅百葉，花重枝不勝。", "猶愛並山茶，開花一尺盈。", "日丹又其亞，不減紅带鞓。", "吐絲心抽鬚，鋸齒葉剪稜。", "白茶亦數品，玉磬尤精明。", "桃葉何從來，派別疑武陵。", "愈出愈奇怪，一見一欲驚。"]'),
('f4293b8f-ad48-4e1b-9b54-d2cad93a29c2','智果庵','徐月溪','宋','宋诗','song-poetry','','[]','居廛終是俗，飯罷即禪房。',48,'全唐诗/poet.song.252000.json','["居廛終是俗，飯罷即禪房。", "竹蔭一庭綠，荷分兩岸香。", "拙鳩呼雨緩，老衲補衣忙。", "不厭頻來此，巖深風自凉。"]'),
('91a4fb78-4b1a-45c4-a042-d366d7ef65f5','句  其一','徐月溪','宋','宋诗','song-poetry','','[]','要是此花清絕處，端如醉面讀離騷。',16,'全唐诗/poet.song.252000.json','["要是此花清絕處，端如醉面讀離騷。"]'),
('7180b8e2-5bb5-40b7-9fbc-52147336f218','句  其二','徐月溪','宋','宋诗','song-poetry','','[]','青蛟煖晝拏雲上，白雪深春壓架香。',16,'全唐诗/poet.song.252000.json','["青蛟煖晝拏雲上，白雪深春壓架香。"]'),
('519a75a2-ea69-408b-bc30-1e586505fd17','句  其三','徐月溪','宋','宋诗','song-poetry','','[]','照眼粧新就，扶頭酒半醒。',24,'全唐诗/poet.song.252000.json','["照眼粧新就，扶頭酒半醒。", "妖姿隨變化，薄命易飄零。"]'),
('a183eca1-61cf-49c2-a46f-4ad6077e648c','句  其四','徐月溪','宋','宋诗','song-poetry','','[]','嬌困扶頭憐半醒，淡濃宜面鬬新粧。',32,'全唐诗/poet.song.252000.json','["嬌困扶頭憐半醒，淡濃宜面鬬新粧。", "並肩罌粟多含怨，具體牡丹惟欠香。"]'),
('90b9ac2a-e21a-45ea-9dc1-1ecdbe99218a','句  其五','徐月溪','宋','宋诗','song-poetry','','[]','礬弟墮小白，梅兄憐老蒼。',24,'全唐诗/poet.song.252000.json','["礬弟墮小白，梅兄憐老蒼。", "仲氏似白眉，表表金玉相。"]'),
('a64b6752-449e-4d05-9c64-ef7fcc43bdfb','句  其六','徐月溪','宋','宋诗','song-poetry','','[]','鮮鮮金鳳花，得時亦自媚。',24,'全唐诗/poet.song.252000.json','["鮮鮮金鳳花，得時亦自媚。", "物生無貴賤，罕見乃爲貴。"]'),
('9c384ac7-1c7f-404d-b8d5-3360d3c8f8b5','句  其七','徐月溪','宋','宋诗','song-poetry','','[]','薤葉秀且聳，蘭香細而幽。',12,'全唐诗/poet.song.252000.json','["薤葉秀且聳，蘭香細而幽。"]'),
('55c9a50e-377d-4c1e-b6f4-5349f0b2b682','蠟梅','吳永濟','宋','宋诗','song-poetry','','["\u897f\u6e56"]','惹得西湖處士疑，如何顔色到鵝兒。',32,'全唐诗/poet.song.252000.json','["惹得西湖處士疑，如何顔色到鵝兒。", "清香全與江梅似，只欠橫斜照水枝。"]'),
('ac47ee42-5eb4-4a24-bd74-236279c283bc','蠟梅','姚西巖','宋','宋诗','song-poetry','','[]','花簇柔枝疑蜜竅，蒂含新蘂似蜂房。',32,'全唐诗/poet.song.252000.json','["花簇柔枝疑蜜竅，蒂含新蘂似蜂房。", "外無梅粉鉛花飾，中有蘭心紫暈香。"]'),
('5933484c-b94a-471d-ad30-46700318c4d6','金櫻子','姚西巖','宋','宋诗','song-poetry','','[]','三月花如薝蔔香，霜中採實似金黄。',32,'全唐诗/poet.song.252000.json','["三月花如薝蔔香，霜中採實似金黄。", "煎成風味亦不淺，潤色猶煩顧長康。"]'),
('10b62ae7-c95c-4279-b1d0-e2e3ad71b110','句','姚西巖','宋','宋诗','song-poetry','','[]','根盤龍骨瘦，葉聳虎鬚長。',12,'全唐诗/poet.song.252000.json','["根盤龍骨瘦，葉聳虎鬚長。"]'),
('b17501cd-8dc7-4fea-9a70-c58321e95283','蠟梅','楊巽齋','宋','宋诗','song-poetry','','[]','香蜜栽葩分外工，疏枝數點綴雛蜂。',32,'全唐诗/poet.song.252000.json','["香蜜栽葩分外工，疏枝數點綴雛蜂。", "嬌黄染就宮妝樣，香暖猶宜愛日烘。"]'),
('db18ea5a-bbcc-4c59-aec6-c392e609a864','荷花','楊巽齋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','翠蓋紅幢耀日鮮，西湖佳麗會群仙。',32,'全唐诗/poet.song.252000.json','["翠蓋紅幢耀日鮮，西湖佳麗會群仙。", "波平十里鋪雲錦，風度清香趁畫船。"]'),
('2a5013b6-f001-4e5d-a100-cd4c93220867','一丈紅','楊巽齋','宋','宋诗','song-poetry','','[]','紅白青黄弄淺深，旌分幢列自成陰。',32,'全唐诗/poet.song.252000.json','["紅白青黄弄淺深，旌分幢列自成陰。", "但疑承露驚殊色，誰識傾陽無二心。"]'),
('42c6e748-8599-4423-b7c5-00ae66965e89','牽牛花','楊巽齋','宋','宋诗','song-poetry','','[]','青青柔蔓繞修牆，刷翠成花著處芳。',32,'全唐诗/poet.song.252000.json','["青青柔蔓繞修牆，刷翠成花著處芳。", "應是折從河鼓手，天孫斜插鬢雲香。"]'),
('2b1be36d-5fc3-410f-96c7-3bd6678f76ac','杜鵑花','楊巽齋','宋','宋诗','song-poetry','','[]','鮮紅滴滴映霞明，盡是冤禽血染成。',32,'全唐诗/poet.song.252000.json','["鮮紅滴滴映霞明，盡是冤禽血染成。", "羈客有家歸未得，對花無語兩含情。"]'),
('baaba4c6-afa5-4b17-9a1c-00098508782f','壽春花','楊巽齋','宋','宋诗','song-poetry','','[]','花間碧玉最敷腴，看挹南薫景又殊。',32,'全唐诗/poet.song.252000.json','["花間碧玉最敷腴，看挹南薫景又殊。", "天賦芳姿長不老，命名爲壽定非誣。"]'),
