('adc5ed86-cd0c-4523-b20e-c446fd36a4f1','楊柳','徐橘隠','宋','宋诗','song-poetry','','[]','陰陰垂柳亂蟬嘶，柳外嬌鶑自在啼。',32,'全唐诗/poet.song.252000.json','["陰陰垂柳亂蟬嘶，柳外嬌鶑自在啼。", "心事太平山色好，開軒坐到日沈西。"]'),
('02264308-d81b-4486-8dc9-67f6b79fe073','溪灣','趙訥軒','宋','宋诗','song-poetry','','[]','曬網漁人路，高低四五家。',48,'全唐诗/poet.song.252000.json','["曬網漁人路，高低四五家。", "半篙春水竹，一樹夕陽花。", "鷗靜機忘鷺，牛行背立鴉。", "白頭村叟醉，茅店酒仍賒。"]'),
('c04a70de-585b-46ae-98e5-3b9e9e79dc90','句  其一','趙訥軒','宋','宋诗','song-poetry','','[]','門外須臾風竹定，櫓聲摇曳出蘆花。',16,'全唐诗/poet.song.252000.json','["門外須臾風竹定，櫓聲摇曳出蘆花。"]'),
('e75b5c82-2256-47a9-ba65-4d16d03fa4d1','句  其二','趙訥軒','宋','宋诗','song-poetry','','[]','白鳥一雙簾外去，蘆花風靜釣舟閑。',16,'全唐诗/poet.song.252000.json','["白鳥一雙簾外去，蘆花風靜釣舟閑。"]'),
('fc63d71b-8d1f-40a6-9bc6-8bdbfe870afd','荼䕷','任拙齋','宋','宋诗','song-poetry','','[]','一年春事到荼䕷，香雪紛紛又撲衣。',32,'全唐诗/poet.song.252000.json','["一年春事到荼䕷，香雪紛紛又撲衣。", "盡把檀心好看取，與留春住莫教歸。"]'),
('e24e688b-92a4-45a0-a852-984b565c9c98','荼䕷','王庵僧','宋','宋诗','song-poetry','','[]','雨後荼䕷將結局，風前芍藥正催粧。',32,'全唐诗/poet.song.252000.json','["雨後荼䕷將結局，風前芍藥正催粧。", "道人不管春深淺，贏得山中歲月長。"]'),
('8065d84a-34c0-437c-af46-909fdc99113e','句','張谷山','宋','宋诗','song-poetry','','[]','可惜荼䕷都過了，近來猶自有薔薇。',16,'全唐诗/poet.song.252000.json','["可惜荼䕷都過了，近來猶自有薔薇。"]'),
('ce161684-5e75-492b-b15f-490e6ebc41a9','華嚴寺望樊川','釋子蘭','宋','宋诗','song-poetry','','[]','萬木葉初紅，人家樹色中。',48,'全唐诗/poet.song.252000.json','["萬木葉初紅，人家樹色中。", "疏鐘摇雨脚，積水浸雲容。", "雪磧迴寒雁，村燈促夜舂。", "舊山歸未得，生計欲何從。"]'),
('598f5fe5-0e40-4798-b6b2-07a2112cfae6','句','釋子蘭','宋','宋诗','song-poetry','','[]','本是無情物，南飛又北飛。',12,'全唐诗/poet.song.252000.json','["本是無情物，南飛又北飛。"]'),
('6b1ffb76-456b-42ed-8451-419677f475c0','句','孫月境','宋','宋诗','song-poetry','','[]','莫欺春到荼䕷盡，更有楊花落後飛。',16,'全唐诗/poet.song.252000.json','["莫欺春到荼䕷盡，更有楊花落後飛。"]'),
('7ec63cf5-6247-4539-87f0-87f0154f72a1','句','齊賢良','宋','宋诗','song-poetry','','[]','依微謝女吟來雪，零落襄王夢後雲。',16,'全唐诗/poet.song.252000.json','["依微謝女吟來雪，零落襄王夢後雲。"]'),
('1792a831-b191-4a5d-aede-d03ba1db392a','山丹花二首  其一','無名氏','宋','宋诗','song-poetry','','[]','烟紅露綠曉風香，燕舞鶑啼春日長。',32,'全唐诗/poet.song.252000.json','["烟紅露綠曉風香，燕舞鶑啼春日長。", "誰道使君貧且老，繡屏錦帳咽笙簧。"]'),
('67d8f74e-a9cc-4545-903d-1283ec95b3df','山丹花二首  其二','無名氏','宋','宋诗','song-poetry','','[]','人間花木眼曾經，未識斯花狀與名。',32,'全唐诗/poet.song.252000.json','["人間花木眼曾經，未識斯花狀與名。", "丹却青山暮春色，續他紅樹墜時英。"]'),
('7547cb74-a53e-41b6-8821-ba3a51c4486a','含笑花','無名氏','宋','宋诗','song-poetry','','[]','薄薄沈熏骨，英英玉煉顔。',24,'全唐诗/poet.song.252000.json','["薄薄沈熏骨，英英玉煉顔。", "惱人風味別，斗帳夢中閒。"]'),
('c835278b-5358-4635-90dc-e2725f12eb63','水仙花二首  其一','來氏','宋','宋诗','song-poetry','','[]','瑶池來宴老仙家，醉倒風流萼綠華。',32,'全唐诗/poet.song.252000.json','["瑶池來宴老仙家，醉倒風流萼綠華。", "白玉斷笄金暈頂，幻成癡絕女兒花。"]'),
('590b39d9-b5bd-49b7-91ce-ad03f6433ca5','水仙花二首  其二','來氏','宋','宋诗','song-poetry','','[]','花盟平日不曾寒，六月曝根高處安。',32,'全唐诗/poet.song.252000.json','["花盟平日不曾寒，六月曝根高處安。", "待得秋殘親手種，萬姬圍繞雪中看。"]'),
('0cf1cc4d-36fe-47fc-971a-7070ca8b144e','薝蔔花','潘鄭臺','宋','宋诗','song-poetry','','[]','未說司花刻玉工，已知名與佛相同。',32,'全唐诗/poet.song.252000.json','["未說司花刻玉工，已知名與佛相同。", "可憐結了薰風子，依舊身歸色界中。"]'),
('0b81bbce-441e-42f5-b04d-9cd8f4234406','薝蔔花','蔣梅邊','宋','宋诗','song-poetry','','[]','清淨法身如雪瑩，肯來林下見孤芳。',32,'全唐诗/poet.song.252000.json','["清淨法身如雪瑩，肯來林下見孤芳。", "樹花六月無炎暑，省爇銅匜幾炷香。"]'),
('27d56c93-df54-4b31-aa33-1950e6b52799','句','蔣梅邊','宋','宋诗','song-poetry','','[]','引蔓閒花欲透雲，托身下倚老松身。',16,'全唐诗/poet.song.252000.json','["引蔓閒花欲透雲，托身下倚老松身。"]'),
('9b4e63f7-cd0f-492d-8cdf-8796322469eb','茉莉花','徐千里','宋','宋诗','song-poetry','','[]','炎洲綠女雪爲肌，十二朱闌月未移。',32,'全唐诗/poet.song.252000.json','["炎洲綠女雪爲肌，十二朱闌月未移。", "香逼簟紋眠不得，爲渠醒過打鐘時。"]'),
('c5bc399e-5dd1-4a51-b42e-d24cac8b3bc1','茉莉花  其一','王右丞','宋','宋诗','song-poetry','','[]','欹烟裛露暗香濃，曾記瑶臺月下逢。',32,'全唐诗/poet.song.252000.json','["欹烟裛露暗香濃，曾記瑶臺月下逢。", "萬里春回人寂寞，玉顔知復爲誰容。"]'),
('b3915a5c-5d3b-4e1e-b7f5-904a45c24263','茉莉花  其二','王右丞','宋','宋诗','song-poetry','','[]','香嚴童子沈薰鼻，姑射仙人雪作膚。',32,'全唐诗/poet.song.252000.json','["香嚴童子沈薰鼻，姑射仙人雪作膚。", "誰向天涯收落蕊，發君顔色四時朱。"]'),
('1f413c81-b4be-4cd0-abd9-d070bccd1943','句','王右丞','宋','宋诗','song-poetry','','[]','尋得天花伴衆芳。',8,'全唐诗/poet.song.252000.json','["尋得天花伴衆芳。"]'),
('8eda4831-2ea1-4636-ab14-a93e1c1501c0','玉簪花','吳震齋','宋','宋诗','song-poetry','','[]','素娥昔日宴仙家，醉裏從他寶髻斜。',32,'全唐诗/poet.song.252000.json','["素娥昔日宴仙家，醉裏從他寶髻斜。", "遺下玉簪無覓處，如今化作一枝花。"]'),
('6e190758-d9ad-4810-bd61-2269d3d2ab92','句','鄭內翰','宋','宋诗','song-poetry','','[]','西風吹得一枝生，昂首風前飛不去。',16,'全唐诗/poet.song.252000.json','["西風吹得一枝生，昂首風前飛不去。"]'),
('0199601f-4b48-4438-a87c-6adfa3c787c4','散水花','無名氏','宋','宋诗','song-poetry','','[]','盈枝點綴雪花鮮，環映清流分外妍。',32,'全唐诗/poet.song.252000.json','["盈枝點綴雪花鮮，環映清流分外妍。", "應是東君歸騎速，不知墜下玉絲鞭。"]'),
('e6ef1267-50f7-4a1f-88c9-c514220cc4e1','玉手爐花','無名氏','宋','宋诗','song-poetry','','[]','習習東風二月餘，此花宜近玉庭除。',32,'全唐诗/poet.song.252000.json','["習習東風二月餘，此花宜近玉庭除。", "美人雲鬢不宜插，獻與觀音作手爐。"]'),
('a4e816b6-a542-4b71-b7d6-4e314513b012','孩兒花','無名氏','宋','宋诗','song-poetry','','[]','纖穠初見似嬌癡，鼓舞春風二月時。',32,'全唐诗/poet.song.252000.json','["纖穠初見似嬌癡，鼓舞春風二月時。", "何事自開還自落，可憐造化亦兒嬉。"]'),
('781eff1c-f78b-4d84-a3aa-bcf1acf9baad','望仙花','無名氏','宋','宋诗','song-poetry','','[]','風捲珠簾挂玉鈎，綵雲開處望仙儔。',32,'全唐诗/poet.song.252000.json','["風捲珠簾挂玉鈎，綵雲開處望仙儔。", "妍姿不逐東君去，日照斜暉上小樓。"]'),
('6db3d731-4cca-462f-8a51-5f6bbee9814e','句','張無咎','宋','宋诗','song-poetry','','[]','水晶肉白殻皮紅，色變香移味不同。',16,'全唐诗/poet.song.252000.json','["水晶肉白殻皮紅，色變香移味不同。"]'),
('cd0f4056-c8b3-457b-be96-421939ef7a91','句  其一','雲隠','宋','宋诗','song-poetry','','[]','刺分玉蛹堆盤脆，嚼破冰蠶饒齒凉。',16,'全唐诗/poet.song.252000.json','["刺分玉蛹堆盤脆，嚼破冰蠶饒齒凉。"]'),
('7127a2c4-f38c-43e3-8f6e-81aec573ad66','句  其二','雲隠','宋','宋诗','song-poetry','','[]','綠宮袍裏素中單，全身却作如來色。',16,'全唐诗/poet.song.252000.json','["綠宮袍裏素中單，全身却作如來色。"]'),
('7ed5274d-38e3-4a28-b70f-889368ab0e1b','萍','釋可齋','宋','宋诗','song-poetry','','[]','盆池本不種青萍，春杪無根也自生。',32,'全唐诗/poet.song.252000.json','["盆池本不種青萍，春杪無根也自生。", "人道一宵生九葉，不知誰數得分明。"]'),
('8b32612b-a60d-47c4-ada7-42de187c90b7','句','張遜初','宋','宋诗','song-poetry','','[]','可惜年年明月夜，漁家只作等閑看。',16,'全唐诗/poet.song.252000.json','["可惜年年明月夜，漁家只作等閑看。"]'),
('7ce7680b-b46c-41db-8ba2-9df7ce17dd27','梧桐','陳葺芷','宋','宋诗','song-poetry','','[]','夢回歷歷雨聲中，窗影分明曉色紅。',32,'全唐诗/poet.song.252000.json','["夢回歷歷雨聲中，窗影分明曉色紅。", "出戶方知是黄葉，更無一片在梧桐。"]'),
('fcd69b34-b234-4c25-8b89-f2678beaef5e','蒿','周吟軒','宋','宋诗','song-poetry','','[]','野蔬山芋慣寒酸，羹綠虀黄頓頓餐。',32,'全唐诗/poet.song.252000.json','["野蔬山芋慣寒酸，羹綠虀黄頓頓餐。", "直到新年立春日，却無生菜上春盤。"]'),
('5a5f5485-6e6e-4d63-88c6-960e94820226','句','王西澗','宋','宋诗','song-poetry','','[]','古木鴉銜楮，空山人採茶。',12,'全唐诗/poet.song.252000.json','["古木鴉銜楮，空山人採茶。"]'),
('14a65292-338b-407b-861b-4461f608ffd0','閏中秋','趙大成','宋','宋诗','song-poetry','','[]','桂影中秋特地圓，况當餘閏魄澄鮮。',64,'全唐诗/poet.song.252000.json','["桂影中秋特地圓，况當餘閏魄澄鮮。", "因懷勝賞初經月，免使詩人歎隔年。", "萬象斂光增浩蕩，四溟收夜助嬋娟。", "鮮雲清廓心田豫，乘興能無賦詠篇。"]'),
('e4609e00-a97f-4b4e-b38e-ce29c9c85c1e','寄外','太學生妻','宋','宋诗','song-poetry','','[]','數日相望極，須知意思迷。',24,'全唐诗/poet.song.252000.json','["數日相望極，須知意思迷。", "夢魂不怕險，飛過大江西。"]'),
('7d141ba9-5fc8-4333-8d6f-f30cd50a559b','贈李安撫','徐伉','宋','宋诗','song-poetry','','[]','尚書八座貴，大使十州雄。',36,'全唐诗/poet.song.252000.json','["尚書八座貴，大使十州雄。", "欲得瘡痍痤，先憐杼軸空。", "仁民兼愛物，時雨及春風。"]'),
('44e84540-cce8-4891-9e71-096396799937','梨花','阮南溪','宋','宋诗','song-poetry','','[]','繽紛紫雪浮鬚細，冷淡清姿奪玉光。',32,'全唐诗/poet.song.252000.json','["繽紛紫雪浮鬚細，冷淡清姿奪玉光。", "剛笑何郎曾傅粉，絕憐荀令愛薰香。"]'),
('3711a48a-2891-4391-8156-e7413c38abc1','答賈支使寄鶴','薛然','宋','宋诗','song-poetry','','[]','瑞羽奇姿踉蹌形，稱爲仙馭過蒼冥。',64,'全唐诗/poet.song.252000.json','["瑞羽奇姿踉蹌形，稱爲仙馭過蒼冥。", "何年厚祿曾居衛，幾世前身本姓丁。", "幸有遠雲兼遠水，莫臨華表與華亭。", "勞君贈我清歌侶，將去田園夜坐聽。"]'),
('a4f7eb5e-4be7-41fd-9eaa-6b4e3c87b815','新鶑歌','釋瑩徹','宋','宋诗','song-poetry','','[]','新鶑傍簷曉更悲，孤音清吟囀柔枝。',170,'全唐诗/poet.song.252000.json','["新鶑傍簷曉更悲，孤音清吟囀柔枝。", "口邊血出語未盡，豈是怨恨人不知。", "不食枯桑椹，不銜苦李花。", "偶然弄樞機，宛轉凌烟霞。", "衆雛飛鳴何跼促，自覘遊鱗啄枯木。", "玄猿何事朝夜啼，白鷺長在汀洲宿。", "黑鵰黄鶴豈不高，金籠玉鉤傷羽毛。", "三江七澤去不得，風烟日暮生波濤。", "飛去來，莫上高城頭，莫下空園裏。", "城頭饑烏食腥羶，空園燕雀爭泥滓。", "願爲結舌含白雲，五月六月一聲不可聞。"]'),
('85d92d10-752d-4314-81fa-8605fa3748f6','秋蝶','李方敬','宋','宋诗','song-poetry','','[]','粉蝶爾何知，秋深尚戲飛。',48,'全唐诗/poet.song.252000.json','["粉蝶爾何知，秋深尚戲飛。", "憐渠迷節物，猶若弄春暉。", "露葉今非昔，霜叢疇可依。", "籬邊菊無幾，薄命寄餘菲。"]'),
('512bb8eb-9a79-4d5d-bcab-0f833590ef30','南郊迴仗','唐觀','宋','宋诗','song-poetry','','[]','傳警千門寂，南郊綵仗迴。',48,'全唐诗/poet.song.252000.json','["傳警千門寂，南郊綵仗迴。", "但驚龍再見，誰識日雙開。", "德澤施雲雨，恩光變燼灰。", "閲兵貔武振，聽樂鳳凰來。"]'),
('685c3b4e-b266-4924-8add-c475adaaeee8','慶元府額上牌致語口號','無名氏','宋','宋诗','song-poetry','','[]','慶元天子舊名藩，寶祐元戎新榜顔。',64,'全唐诗/poet.song.252000.json','["慶元天子舊名藩，寶祐元戎新榜顔。", "鬰鬰蛟纏三大字，停停虹貫四明山。", "百年老穉歡聲沸，千古山河旺氣還。", "便挾島仙天上去，再提此筆福人間。"]'),
('e0e54e6c-1a91-4c84-b5b4-6a68453460a5','句','閻伯才','宋','宋诗','song-poetry','','[]','魚貫羸師堪坐縛，爾時可歎蜀無人。',16,'全唐诗/poet.song.252000.json','["魚貫羸師堪坐縛，爾時可歎蜀無人。"]'),
('61e7d4a8-b2e8-47a4-83b6-1328866b79c8','天津橋  其一','周彥夫','宋','宋诗','song-poetry','','[]','下車聊復問何如，尚憶重來四紀餘。',32,'全唐诗/poet.song.252000.json','["下車聊復問何如，尚憶重來四紀餘。", "鍾阜秦淮俱好在，祇憐雙鬢自蕭疏。"]'),
('6b211bb4-9564-44c6-b95d-232a5ce8c519','天津橋  其二','周彥夫','宋','宋诗','song-poetry','','[]','聯鑣去作蔣山遊，路轉天津遶御溝。',32,'全唐诗/poet.song.252000.json','["聯鑣去作蔣山遊，路轉天津遶御溝。", "忽作故都禾黍恨，洛陽宮殿鎖千秋。"]'),
('20709686-85f2-4256-81fe-2005547063c9','天津橋','石逢龍','宋','宋诗','song-poetry','','[]','下馬過天津，聽傳禁漏頻。',48,'全唐诗/poet.song.252000.json','["下馬過天津，聽傳禁漏頻。", "惟憐一橋月，曾照六朝人。", "金制剝門字，紅飛粉壁塵。", "中官來宿內，因問帝鄉親。"]'),
('57de3272-b196-41f9-b0b6-ed8f6f218dd9','過齊山人居','石逢龍','宋','宋诗','song-poetry','','[]','自說住居年，山靈夙有緣。',48,'全唐诗/poet.song.252000.json','["自說住居年，山靈夙有緣。", "看經醫病鶴，祭土鑿新泉。", "食相過饑歲，眠簑度雪天。", "所言非釋老，難與世人傳。"]'),
('167f7dd2-2fff-4ca7-81f5-8f0de774a1f1','官滿借居','石逢龍','宋','宋诗','song-poetry','','[]','盡裝家具已回京，便覺身如片葉輕。',64,'全唐诗/poet.song.252000.json','["盡裝家具已回京，便覺身如片葉輕。", "近市借居人語雜，閉門獨處自心清。", "雨中躡屣青苔滑，燭下梳頭白髪明。", "余亦傍人簷底住，新來巢燕不須驚。"]'),
('23cb35c9-1379-48fa-bf79-d2262180ffa0','華陽洞','林逋叟','宋','宋诗','song-poetry','','[]','華陽山雨拂輕塵，獨步烟霞訪隠真。',64,'全唐诗/poet.song.252000.json','["華陽山雨拂輕塵，獨步烟霞訪隠真。", "笑傲太平雲外客，安閑清世夢中身。", "金章名重人稱貴，布褐才高道不貧。", "吟罷洞天風正淡，自知凡骨定逢人。"]'),
('db2abb46-691f-4a3c-8819-55b884c653d7','鳳凰臺','王渭卿','宋','宋诗','song-poetry','','[]','江山還似六朝時，老盡梧桐鳳不知。',64,'全唐诗/poet.song.252000.json','["江山還似六朝時，老盡梧桐鳳不知。", "保大空存前殿佛，元嘉已沒舊廊碑。", "幾年何德之衰也，曷日覽輝而下之。", "不見長安豪傑恨，諸公忍讀謫仙詩。"]'),
('59c9d853-7ecf-4275-bead-9639063764ca','鳳凰臺  其一','徐棫翁','宋','宋诗','song-poetry','','[]','只合臺前賸種桐，萬柯摇碧護春風。',32,'全唐诗/poet.song.252000.json','["只合臺前賸種桐，萬柯摇碧護春風。", "縱無丹鳳重來此，且障長安落日中。"]'),
('15dc9e8b-db52-415a-98f3-fa38577796f0','鳳凰臺  其二','徐棫翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','臺前煙草接青徐，臺後風花滿殿廡。',32,'全唐诗/poet.song.252000.json','["臺前煙草接青徐，臺後風花滿殿廡。", "千里暮濤空寂寞，醉人春色正西湖。"]'),
('07dc35a8-59b5-4b05-a408-1bcefa55f2a1','雨花臺','張湯','宋','宋诗','song-poetry','','[]','不譚仁義只譚空，一着參差在箇中。',64,'全唐诗/poet.song.252000.json','["不譚仁義只譚空，一着參差在箇中。", "臺上繽紛花正雨，城邊一陣已西風。", "君王自有君王業，何事區區翻貝葉。", "雨花名臺非識奇，要使後人知覆轍。"]'),
('25385354-5edb-43e6-b708-5c67a9939bfc','雨花臺','盧壽老','宋','宋诗','song-poetry','','[]','輶車行曉快新遊，更上雨花臺上頭。',64,'全唐诗/poet.song.252000.json','["輶車行曉快新遊，更上雨花臺上頭。", "看不厭人渾是景，清無極處奈何秋。", "地完龍虎堂堂立，江泊鯨鯢滾滾流。", "一带黄山是淮土，依然望弗見神州。"]'),
('249af838-c43c-43c8-9101-63b315dc7e2b','金陵作','施文焴','宋','宋诗','song-poetry','','[]','紫蓋東南久寂寥，石城烟霧壓岧嶢。',64,'全唐诗/poet.song.252000.json','["紫蓋東南久寂寥，石城烟霧壓岧嶢。", "登臺倦客懷千古，宿內閑人夢六朝。", "御苑雲浮曾拾翠，舊樓月落尚吹簫。", "諸公不說新亭事，目斷空江半日潮。"]'),
('b74edd61-1e92-4a2a-bf58-2a19c1275f1c','棲霞寺','谷倪子','宋','宋诗','song-poetry','','[]','去郭六十里，閑遊避世譁。',72,'全唐诗/poet.song.252000.json','["去郭六十里，閑遊避世譁。", "不將仙鶴伴，還用白牛車。", "草木隠君宅，香燈古佛家。", "幾多吟景致，無限筆光華。", "泉想尋新眼，茶應發嫩芽。", "遥知碧巖上，舉手拂烟霞。"]'),
('af5e57a3-f960-47d1-9b44-87141182261c','瀑布','黄居萬','宋','宋诗','song-poetry','','[]','龍梭織處人難見，地軸舒來尺莫量。',32,'全唐诗/poet.song.252000.json','["龍梭織處人難見，地軸舒來尺莫量。", "定是水仙工性巧，逐時裁去補滄浪。"]'),
('40444798-7aa8-4056-b2dc-da0c7b3beea8','禽言二首  其一','無名氏','宋','宋诗','song-poetry','','[]','剛道故鄉如許好，其如遊子不歸何。',32,'全唐诗/poet.song.252000.json','["剛道故鄉如許好，其如遊子不歸何。", "自從五柳先生死，空染千山淚血多。"]'),
('62dc8b6f-c272-4e69-aafb-bb7f72cf1e45','禽言二首  其二','無名氏','宋','宋诗','song-poetry','','[]','蠶繭方成四月初，鳥能早計巧相呼。',32,'全唐诗/poet.song.252000.json','["蠶繭方成四月初，鳥能早計巧相呼。", "誰知機杼聲纔息，已有王官來索租。"]'),
('73a03e75-0e0b-471e-826e-850bfdc55a95','句','無名氏','宋','宋诗','song-poetry','','[]','贏得兒童叫夫子，可憐名位只都官。',16,'全唐诗/poet.song.252000.json','["贏得兒童叫夫子，可憐名位只都官。"]'),
('4e2ada44-eeaf-4f17-b867-65b337cd0d0e','嘲張乂','林叔弓','宋','宋诗','song-poetry','','[]','中分爻兩段，風使十橫斜。',24,'全唐诗/poet.song.252000.json','["中分爻兩段，風使十橫斜。", "文上元無分，人前强出些。"]'),
('c2055944-bdca-4dae-9e18-7df598065385','記化蝶異聞','李商','宋','宋诗','song-poetry','','[]','碧梧翠竹名家兒，今作栩栩蝴蝶飛。',32,'全唐诗/poet.song.252000.json','["碧梧翠竹名家兒，今作栩栩蝴蝶飛。", "山川阻深網羅密，君從何處化飛歸。"]'),
('53e184d6-d8ce-49b8-8868-9af73f479bc0','汴河','林曾','宋','宋诗','song-poetry','','[]','一千八百隋家路，兩岸青青入帝都。',32,'全唐诗/poet.song.252000.json','["一千八百隋家路，兩岸青青入帝都。", "可惜翠華南渡後，舊時楊柳一株無。"]'),
('c8b0f813-446d-425a-8702-d7d60ca01a76','溪上謠','林曾','宋','宋诗','song-poetry','','[]','溪翁兒女枕溪住，時把釣竿倚芳樹。',32,'全唐诗/poet.song.252000.json','["溪翁兒女枕溪住，時把釣竿倚芳樹。", "沉吟獨坐忍傷心，釣得魚來放將去。"]'),
('337e3e32-9ffc-42f1-8a5f-1b8f32557fe6','句','林曾','宋','宋诗','song-poetry','','[]','魚頭紅結魫，土面白生硝。',12,'全唐诗/poet.song.252000.json','["魚頭紅結魫，土面白生硝。"]'),
('07984ee5-94b6-42e7-9e9f-1076840c2af1','絕句','王勝之','宋','宋诗','song-poetry','','[]','蛙鼓鳴時月滿川，斷螢飛處草迷烟。',32,'全唐诗/poet.song.252000.json','["蛙鼓鳴時月滿川，斷螢飛處草迷烟。", "敲門欲向田家宿，猶有青燈人未眠。"]'),
('bce80e73-8423-4bd1-bb6f-d1687a7085fd','題畫扇','吳白','宋','宋诗','song-poetry','','[]','風枝露葉有餘清，轉盼還從玉筍生。',32,'全唐诗/poet.song.252000.json','["風枝露葉有餘清，轉盼還從玉筍生。", "願得此君長在眼，子猷雖老未忘情。"]'),
('11e9ba39-44d6-42b5-aa8e-848cbb5acee7','題震澤寺壁','無名氏','宋','宋诗','song-poetry','','[]','民力久已竭，天乎不見憐。',48,'全唐诗/poet.song.252000.json','["民力久已竭，天乎不見憐。", "三年兩遭水，十室九無烟。", "田沒官徵賦，家貧子賣錢。", "秋風江上路，忽見渡江船。"]'),
('f984a83e-b9e1-4cb7-ad36-430401cb3b16','潭州四通館題梁','無名氏','宋','宋诗','song-poetry','','[]','蝸角名，蠅頭利。',48,'全唐诗/poet.song.252000.json','["蝸角名，蠅頭利。", "老天術何巧，以此役斯世。", "昨日一替死，今日一替生。", "暗裏換人人不悟，門前每日見人行。"]'),
('f38ba1bf-1f65-4222-9d2a-a2c480f5dc44','題貴池驛壁','無名氏','宋','宋诗','song-poetry','','[]','昨日雨，今朝晴。',56,'全唐诗/poet.song.252000.json','["昨日雨，今朝晴。", "前月小，後月大。", "君欲問百年，百年如此過。", "孰爲辱，孰爲榮。", "何者福，何者禍。", "山中多白雲，莫教脚一蹉。"]'),
('f85a06c8-37c2-48d5-8f99-397793f10251','過瑩公房','沈規','宋','宋诗','song-poetry','','[]','悟得楞伽理，塵函久不開。',48,'全唐诗/poet.song.252000.json','["悟得楞伽理，塵函久不開。", "遊絲瑩定石，馴雀下生臺。", "境寂從朝暮，心空了去來。", "行看舊庭柏，自說少時栽。"]'),
('8fa7d219-7faa-4b7e-acb1-769097f30c5a','九月一日','沈規','宋','宋诗','song-poetry','','[]','門外行蹊落葉遮，西風寒入野人家。',32,'全唐诗/poet.song.252000.json','["門外行蹊落葉遮，西風寒入野人家。", "重陽日近秋光足，開遍閑庭帝女花。"]'),
('b67a92da-40d9-4af4-a3a9-88bbe962445b','舟回練塘','蔣恢','宋','宋诗','song-poetry','','[]','柁轉秋塘逈，寒光徹萬尋。',48,'全唐诗/poet.song.252000.json','["柁轉秋塘逈，寒光徹萬尋。", "葉聲風外急，吟思雨中深。", "白髪存公道，青山適素心。", "疏鐘何處起，暝色正沈沈。"]'),
('8411e979-07ce-486b-93a3-5eb0e17d90a3','野色','蔣恢','宋','宋诗','song-poetry','','[]','幽事每堪娛，秋深晚霽初。',48,'全唐诗/poet.song.252000.json','["幽事每堪娛，秋深晚霽初。", "帆分江影破，風勒鳥行疏。", "山色美無度，稻花香可書。", "逍遥今夕意，未厭短轅車。"]'),
('d0bce057-569e-4a22-9315-1090bbafcd93','三月晦日偶成','蔣恢','宋','宋诗','song-poetry','','[]','一年芳信雨消磨，負此吟懷奈若何。',64,'全唐诗/poet.song.252000.json','["一年芳信雨消磨，負此吟懷奈若何。", "倚檻忽驚新綠暗，掃軒更惜落紅多。", "春歸惟有時禽覺，睡足從渠日影蹉。", "閑裏工夫閑受用，惜無閑客肯相過。"]'),
('d6261868-ba4a-464b-930d-e591e2784650','行山','蔣恢','宋','宋诗','song-poetry','','[]','六尺枯筇度遠岑，野花啼鳥助清吟。',64,'全唐诗/poet.song.252000.json','["六尺枯筇度遠岑，野花啼鳥助清吟。", "雲低似覺天根近，磵遠因知地脈深。", "閲世豈容無正眼，窮源須要識初心。", "春寒局促良堪厭，一笑陽和破積陰。"]'),
('b599ad33-8b39-46c3-bad6-f8ed3bb7b981','甲辰臘日遣興','蔣恢','宋','宋诗','song-poetry','','[]','臘裏春前日日陰，西疇彌覺水雲深。',64,'全唐诗/poet.song.252000.json','["臘裏春前日日陰，西疇彌覺水雲深。", "梅邊句好無人覓，竹外烟輕有鳥吟。", "發興合窮千里目，著書聊寄百年心。", "翻雲覆雨誰能問，納納乾坤古復今。"]'),
('417d74fa-9f6c-49cf-b76d-4fae8f27a06f','秋夜讀書','蔣恢','宋','宋诗','song-poetry','','[]','白紵烏紗不耐凉，晚風吹月上莓牆。',32,'全唐诗/poet.song.252000.json','["白紵烏紗不耐凉，晚風吹月上莓牆。", "舊書重讀添新味，二尺檠邊夜正長。"]'),
('1d1e3649-e99b-4222-895e-a352e432b574','秋吟','蔣恢','宋','宋诗','song-poetry','','[]','落葉紛紛捲地來，手持六角障黄埃。',32,'全唐诗/poet.song.252000.json','["落葉紛紛捲地來，手持六角障黄埃。", "何人真解知秋意，與上凌虛百尺臺。"]'),
('38c4dd47-bae4-4a9d-9ef4-fdd9c7cd674e','重午','蔣恢','宋','宋诗','song-poetry','','[]','逝水光陰不肯停，又從菰黍重尋盟。',32,'全唐诗/poet.song.252000.json','["逝水光陰不肯停，又從菰黍重尋盟。", "平生不學採蓮曲，只讀離騷配酒兵。"]'),
('cc5af87a-73de-4923-860d-cfa86d7021fb','睡起','蔣恢','宋','宋诗','song-poetry','','[]','幽鳥無言啄落花，風吹榆莢打窗紗。',32,'全唐诗/poet.song.252000.json','["幽鳥無言啄落花，風吹榆莢打窗紗。", "先生酒醒綠陰裏，笑聽蜂兒報晚衙。"]'),
('f57786ee-95b2-42c7-a5dd-7c8c9f7b13e3','獨客','蔣華子','宋','宋诗','song-poetry','','[]','獨客秋江上，蕭蕭髪欲華。',48,'全唐诗/poet.song.252000.json','["獨客秋江上，蕭蕭髪欲華。", "終風撼紅樹，甚雨老黄花。", "丘壠應無恙，音書不到家。", "眠孤怨遥夜，歸夢遶鷗沙。"]'),
('b02e11c6-8fac-4d85-8131-7a560a70757d','題孫得休居室','蔣華子','宋','宋诗','song-poetry','','[]','住世百來年，童顔只儼然。',48,'全唐诗/poet.song.252000.json','["住世百來年，童顔只儼然。", "道心丹竈外，詩趣筆牀邊。", "甕牖清虛府，盆池小有天。", "雲關誰剝啄，端是問神仙。"]'),
('7119b365-25e3-4525-b92e-f8d2382c85c5','筍','蔣華子','宋','宋诗','song-poetry','','[]','頭角嶄嶄露，江南四月時。',48,'全唐诗/poet.song.252000.json','["頭角嶄嶄露，江南四月時。", "定應孤竹子，未脫老萊衣。", "怒長搘苔石，旁行過棘籬。", "不來能幾日，漸學翠鸞飛。"]'),
('a05df143-d52e-4fd0-b275-3d33147500d5','春晚謠','蔣華子','宋','宋诗','song-poetry','','[]','汀洲三月楊花飛，河魨出水江鱭肥。',64,'全唐诗/poet.song.252000.json','["汀洲三月楊花飛，河魨出水江鱭肥。", "雨聲翻作斷腸曲，薄寒戀戀輕羅衣。", "新愁壓眉雙碧聚，作意挽春春不住。", "無情恨殺蜀帝魂，不勸歸來勸歸去。"]'),
('5812df43-2786-4824-b4a7-582daa15cbcf','題釣臺','何宗斗','宋','宋诗','song-poetry','','[]','貧賦漁蓑却耐交，故人牽率政徒勞。',32,'全唐诗/poet.song.252000.json','["貧賦漁蓑却耐交，故人牽率政徒勞。", "十分拂袖歸來是，何似當時莫去高。"]'),
('f4638ec3-da60-4f84-b30e-e5ac0485f2c7','喜逢靈江贇禪師','江朝卿','宋','宋诗','song-poetry','','[]','兩世吟邊友，分携二紀餘。',96,'全唐诗/poet.song.252000.json','["兩世吟邊友，分携二紀餘。", "獨憐身老去，及見頂圓初。", "閒晝烹茶數，炎天入定疏。", "久依蓮社泊，晤語勝鄰居。", "括州尊宿後，學業貫儒緇。", "自說先師筆，曾抄謬客詩。", "石蒲抽水上，樹蔓與雲垂。", "何處風埃滾，無營不用知。"]'),
('df7f2b51-742f-4516-8971-121f9edd85fd','畫不如亭','朱詵','宋','宋诗','song-poetry','','[]','環遶皆山遠勝滁，地無炎瘴氣清虛。',64,'全唐诗/poet.song.252000.json','["環遶皆山遠勝滁，地無炎瘴氣清虛。", "十亭留詠誇前輩，八景搜奇出故墟。", "拍岸驚濤通海道，插天峭壁壯侯居。", "烟雲變態無窮極，百幅生綃畫不如。"]'),
('32a098ac-05c0-4469-a839-15fdaf6043fb','丁巳春勸農','朱詵','宋','宋诗','song-poetry','','[]','勸農小隊出東禪，春事平分花柳天。',67,'全唐诗/poet.song.252000.json','["勸農小隊出東禪，春事平分花柳天。", "亂石藏雲蒼玉洞，小溪流水紫{艹縹}田。", "農忙處處扶犁雨，社近家家煮酒烟。", "野興未厭歸興促，公餘猶擬一橫鞭。"]'),
('c130482e-e1b9-4736-a4d4-92b965e8a38f','春歸二絕和高希遠韻  其一','蕭炎','宋','宋诗','song-poetry','','[]','晴窗如暝樹雲遮，紅紫成埃減陌車。',32,'全唐诗/poet.song.252000.json','["晴窗如暝樹雲遮，紅紫成埃減陌車。", "不信春歸無綰繫，尚存一架木香花。"]'),
('e06c142d-f5d2-4f31-847f-9815d627a603','春歸二絕和高希遠韻  其二','蕭炎','宋','宋诗','song-poetry','','[]','厨供櫻笋上春盤，把酒留春少住難。',32,'全唐诗/poet.song.252000.json','["厨供櫻笋上春盤，把酒留春少住難。", "祇是簷花前夜雨，明朝便作釀梅看。"]'),
('0aa5e783-25a0-43bd-8f2d-01f95fc86430','春愁','張元道','宋','宋诗','song-poetry','','[]','烟翠飽青實，雨紅黏綠苔。',48,'全唐诗/poet.song.252000.json','["烟翠飽青實，雨紅黏綠苔。", "楊花隨夢去，鶑語喚愁來。", "吟事春三月，風光酒一杯。", "芳心久消歇，已作蕙爐灰。"]'),
('4a59d1bd-248c-4a7d-913e-fdc21cfd9f08','摇落','張元道','宋','宋诗','song-poetry','','[]','摇落梧桐恨，哀吟絡緯愁。',48,'全唐诗/poet.song.252000.json','["摇落梧桐恨，哀吟絡緯愁。", "星河橫靜夜，天地入新秋。", "冉冉歲云邁，滔滔江自流。", "驚風和雁影，吹夢過南樓。"]'),
('9bd586e1-8b7e-4bfe-ac8c-a05238ed9bc9','不如歸去','張元道','宋','宋诗','song-poetry','','[]','岷峨路遠萬重雲，錦水繁華一聚塵。',32,'全唐诗/poet.song.252000.json','["岷峨路遠萬重雲，錦水繁華一聚塵。", "帝子但知歸去好，故家城闕已他人。"]'),
('43bcc159-2bfd-427d-90e6-279e778a797f','春深見雁','張元道','宋','宋诗','song-poetry','','[]','杜若生洲荻已芽，隨陽片影向天涯。',32,'全唐诗/poet.song.252000.json','["杜若生洲荻已芽，隨陽片影向天涯。", "如今不用思歸去，江北江南是一家。"]'),
('7ba4cf99-005b-4d42-8861-b26ae0943406','秋意','張元道','宋','宋诗','song-poetry','','[]','古鐸摇風語夜凉，露漙莎徑咽寒螀。',32,'全唐诗/poet.song.252000.json','["古鐸摇風語夜凉，露漙莎徑咽寒螀。", "更長展轉難成寐，擬問希夷覓睡方。"]'),
('54f610fe-8820-4b3e-ab06-8120a1330134','洛陽橋觀水','朱正中','宋','宋诗','song-poetry','','[]','點點風帆底處還，似無似有海門山。',32,'全唐诗/poet.song.252000.json','["點點風帆底處還，似無似有海門山。", "白鷗却怕潮頭惡，閑卧汀花野草間。"]'),
('9e9a29ab-a415-41ae-9489-d3a1c221b5b1','題蕪湖夢日亭','無名氏','宋','宋诗','song-poetry','','[]','樓船犀甲下荆州，蜂目將軍駐碧油。',64,'全唐诗/poet.song.252000.json','["樓船犀甲下荆州，蜂目將軍駐碧油。", "虎帳覺來驚日墮，龍媒嘶去逐星流。", "姦萌問鼎終何在，計落遺鞭始可羞。", "幽草亂花荒故壘，無人能作晉春秋。"]'),
('aa07e1d5-9383-45e0-b524-c152b58db74a','立春寄梅壇楊逸老','范太中','宋','宋诗','song-poetry','','[]','仕路蹉跎又見春，區區深厭走紅塵。',64,'全唐诗/poet.song.252000.json','["仕路蹉跎又見春，區區深厭走紅塵。", "未能解脫無窮事，長憶逍遥自在人。", "瓦缶汲泉朝灌藥，羽衣濛露夜朝真。", "灑然物外清虛境，呼吸淳元養氣神。"]'),
('627568cf-09d0-4563-8b78-1e92ccc3d6a0','遊梅壇有感','吳季先','宋','宋诗','song-poetry','','[]','小立仙壇挹斗箕，著身高處覺天低。',32,'全唐诗/poet.song.252000.json','["小立仙壇挹斗箕，著身高處覺天低。", "南昌吏隠清風在，喚醒時人局面迷。"]'),
('c55a85db-17a4-4a5f-a991-325a54f17906','賡梅山壁間韻','鄧夢杰','宋','宋诗','song-poetry','','[]','愧我身名墮褐冠，無因安得到仙壇。',32,'全唐诗/poet.song.252000.json','["愧我身名墮褐冠，無因安得到仙壇。", "子真雖隠名難隠，萬古高風凜凜寒。"]'),
('ab9600fb-8c3b-43f7-80dc-717dc2daa417','宿梅仙壇','張廣漢','宋','宋诗','song-poetry','','[]','夜宿梅壇境，山寒萬籟空。',48,'全唐诗/poet.song.252000.json','["夜宿梅壇境，山寒萬籟空。", "無才供吏隠，有夢憶仙翁。", "石齒含殘雪，松髯奮急風。", "竈煙如可舐，跨鶴問鴻濛。"]'),
('71b03772-e0ff-4a59-bd1b-f83d9b098ecc','題梅壇  其一','張異','宋','宋诗','song-poetry','','[]','上疏歸來日已西，山中旋製薜蘿衣。',64,'全唐诗/poet.song.252000.json','["上疏歸來日已西，山中旋製薜蘿衣。", "謀身豈爲金丹祕，去國應知火祚移。", "風露滿林蟬幾蛻，松杉遶屋鶴孤飛。", "瓣香僕僕非公願，自有忠誠天地知。"]'),
('e05eff38-8f47-4b0f-9825-5389c1559701','題梅壇  其二','張異','宋','宋诗','song-poetry','','[]','古樹枯藤知幾年，衣冠來此豈徒然。',64,'全唐诗/poet.song.252000.json','["古樹枯藤知幾年，衣冠來此豈徒然。", "波濤平地難回首，風雨深山且熟眠。", "吾道有靈終用世，此心無愧可通天。", "功名分定從吾好，未許驅馳效執鞭。"]'),
('0f948044-1573-4a20-8377-2cfe0f163a85','題梅壇','鍾訧','宋','宋诗','song-poetry','','[]','萬松護嶺與天齊，中有真人舊隠棲。',64,'全唐诗/poet.song.252000.json','["萬松護嶺與天齊，中有真人舊隠棲。", "井冷尚留丹汞暖，壇高近拜斗星低。", "回思漢室成惆悵，浪費今人爲品題。", "我欲從之無路去，同昇不似許仙雞。"]'),
('e86f2b7e-a253-4a8a-9a21-ce1f2ad3b290','題梅山雲悅樓','鍾訧','宋','宋诗','song-poetry','','[]','我匪悅雲雲悅我，雲兮與我一無心。',32,'全唐诗/poet.song.252000.json','["我匪悅雲雲悅我，雲兮與我一無心。", "知君只愛雲中隠，不肯出山無處尋。"]'),
('02612960-761f-4d72-8319-bc19d4334bf8','題梅仙壇','劉霆午','宋','宋诗','song-poetry','','[]','吏隠清風幾百年，長松脩竹滿壇前。',32,'全唐诗/poet.song.252000.json','["吏隠清風幾百年，長松脩竹滿壇前。", "漢皇若聽三書諫，未必先生便肯仙。"]'),
('b48ad8e2-13b5-44f3-b2d8-efe192ea0459','題梅壇','劉霆午','宋','宋诗','song-poetry','','[]','火德中微否未傾，朝陽一疏鳳先鳴。',64,'全唐诗/poet.song.252000.json','["火德中微否未傾，朝陽一疏鳳先鳴。", "如公忠論能旋聽，彼莽姦謀未可成。", "萬古仙名香宇宙，幾人遺臭腐公卿。", "至今風吼松聲怒，似爲先生訴不平。"]'),
('ceb0a3e8-4953-4a2e-bcd8-78ebfdb5aa6b','題梅山  其一','范仁仲','宋','宋诗','song-poetry','','[]','袖凜摧姦劍拂霜，奈何不報疏三章。',64,'全唐诗/poet.song.252000.json','["袖凜摧姦劍拂霜，奈何不報疏三章。", "南昌一尉孤忠日，西漢諸王百沸湯。", "便覓赤松爲伴去，何求青史把名揚。", "想疑九轉丹成後，憤吐精衷訴玉皇。"]'),
('01edc7ff-0a14-4bd4-acf9-1b27aca2dbf0','題梅山  其二','范仁仲','宋','宋诗','song-poetry','','[]','說到神仙事渺茫，壽春亙古此靈場。',64,'全唐诗/poet.song.252000.json','["說到神仙事渺茫，壽春亙古此靈場。", "松邊白隠千年鶴，嶺外紅拖幾夕陽。", "霞馭月寒時弄影，斗壇風冷夜聞香。", "先生不必真人號，自與乾坤共久長。"]'),
('13fa133a-b4a8-4200-b5b5-f28a69546a16','乙卯禱雨梅壇','嚴椿齡','宋','宋诗','song-poetry','','[]','大隠清名格帝閽，真人新寵粲王言。',64,'全唐诗/poet.song.252000.json','["大隠清名格帝閽，真人新寵粲王言。", "南昌補吏官雖小，北極通班道更尊。", "諫疏不容强漢室，仙風聊復傲吳門。", "我來物色朝元處，山繞星壇水繞村。"]'),
('a0eb9993-38e1-478b-b84d-57bcd7c54dcf','題梅山雲悅樓','崔次周','宋','宋诗','song-poetry','','[]','仙人好樓居，天上多瓊樓。',166,'全唐诗/poet.song.252000.json','["仙人好樓居，天上多瓊樓。", "祥氛結紫炁，磅礴常周流。", "道人仙之裔，居然梅山頭。", "山頭聳百尺，日與雲從游。", "靜默觀內景，繚繞雲氣浮。", "軒豁挹西爽，天淨雲影收。", "倚欄暢吟情，筆硯雲烟稠。", "領客譚又玄，滿吸雲腴甌。", "不用分半間，盤結任相繆。", "怡然自可悅，澹然亦何求。", "悅則動靜隨，呼吸聽去留。", "我欲乘之叩太虛，相與上下追仙斿。", "鞭鸞笞鳳汗漫去，下視八表揮斥凌九州。"]'),
('b51172e6-b813-4bf2-9a83-f8ad55bc9e9d','題梅壇','胡發','宋','宋诗','song-poetry','','[]','忠肝一點炳如月，世事難將道眼看。',32,'全唐诗/poet.song.252000.json','["忠肝一點炳如月，世事難將道眼看。", "駕取雲軿昇斗府，惟遺巖壑拱仙壇。"]'),
('80b9e3dc-1075-415c-83d6-ef6c8814eb43','題梅山雲悅樓','胡宏子','宋','宋诗','song-poetry','','[]','世人之所悅，多在紛華間。',84,'全唐诗/poet.song.252000.json','["世人之所悅，多在紛華間。", "毛仙得趣處，白雲滿青山。", "飛樓俯空曠，登眺長怡顔。", "迹與雲俱高，心與雲俱閑。", "八極梅真人，乘雲相往還。", "我亦懶出岫，時歸坐雲關。", "清吟抱幽獨，何當共凭欄。"]'),
('e7cff4a4-4158-4cef-9673-fb0c6038e90e','題梅壇','王伯範','宋','宋诗','song-poetry','','[]','朝喑仗馬夕箋天，漢事于今已幾年。',32,'全唐诗/poet.song.252000.json','["朝喑仗馬夕箋天，漢事于今已幾年。", "一片孤忠應尚在，定須耿耿斗牛邊。"]'),
('c642dde6-2b68-41a8-9a87-2e4a587de653','題梅山雲悅樓','羅永之','宋','宋诗','song-poetry','','[]','曾讀楊詩識懶雲，只今雲悅即雲孫。',64,'全唐诗/poet.song.252000.json','["曾讀楊詩識懶雲，只今雲悅即雲孫。", "龍無怒色常歸匣，鶴有懽顔獨守門。", "春態樂尋吟客伴，心閑喜共野人言。", "要知出岫晴方好，樓外濛濛烟雨昏。"]'),
('c2e6f8ae-962c-4510-8409-198cbde46f44','題梅山雲悅樓','李君式','宋','宋诗','song-poetry','','[]','無心出岫道人閑，身在虛無縹渺閒。',32,'全唐诗/poet.song.252000.json','["無心出岫道人閑，身在虛無縹渺閒。", "可惜雲霓人在望，捲將雲雨入梅山。"]'),
('13504186-1649-48ab-b222-142d6fe42cac','題梅山','薛修竹','宋','宋诗','song-poetry','','[]','薜荔壇高秋十分，漢時笙鶴杳無聞。',32,'全唐诗/poet.song.252000.json','["薜荔壇高秋十分，漢時笙鶴杳無聞。", "平明一覺西風夢，吹落人間半是雲。"]'),
('3225741f-ff2b-4bc1-8bf8-6bab3d7393bd','題梅壇','曹仙家','宋','宋诗','song-poetry','','[]','漢代梅君此鍊丹，古壇翠駮蘚花斑。',64,'全唐诗/poet.song.252000.json','["漢代梅君此鍊丹，古壇翠駮蘚花斑。", "目窮鳥道青天遠，榻轉松陰白日閑。", "烟隔樓臺分象外，風吹鐘磬落人間。", "不知乘詔沖昇後，幾度飛鸞到舊山。"]'),
('6100cc1b-03b0-4ccc-abec-bf8df2e1efee','贈鄒葆光道士','曹仙家','宋','宋诗','song-poetry','','[]','羅浮道士真仙子，躍出樊籠求不死。',384,'全唐诗/poet.song.252000.json','["羅浮道士真仙子，躍出樊籠求不死。", "冰壺皎潔水鑑清，洞然表裏無塵滓。", "叱咤雷霆發指端，馘邪役鬼篆飛丹。", "朝吞露氣松窗暖，夜禮星辰玉簡寒。", "琴心和雅胎仙舞，屏絕淫哇追太古。", "幽韻蕭深海島風，餘音繚繞江天雨。", "真居僻在海南邊，溪上簾櫳洞裏天。", "靈鳳九苞飛檻外，珍禽五色舞花前。", "金絲島露紫河車，青霓跨嶺鐵橋斜。", "羅浮自古神仙宅，萬里來尋况是家。", "我昔閨中方幼穉，當年曾覽羅浮記。", "形質雖拘一室間，精魂已出千山外。", "如今親見羅浮人，疑是朱明降上真。", "劍氣袖携三尺水，霞漿杖挂一壺春。", "松姿鶴步何蕭散，風調飄飄驚俗眼。", "吾師出處任高情，止則止兮行則行。", "富有溪山寧願利，貴懷道義不干名。", "我今寄跡都城裏，門外喧喧那入耳。", "上床布被日高眠，不爲公來不能起。", "問公去速來何遲，得接高談幾許時。", "白雲偶向帝鄉過，去住無蹤安可期。", "我亦韶華斷羈紲，何異飄蓬與翻葉。", "相逢邂逅即開顔，禮樂何曾爲吾設。", "志同笙磬合宮商，道乖肝膽成胡越。"]'),
('9d59ac56-c3f8-4fcb-a8fb-7e2de28936e8','西閣','釋志文','宋','宋诗','song-poetry','','[]','楊柳蒹葭覆水濱，徘徊南望倚闌頻。',64,'全唐诗/poet.song.252000.json','["楊柳蒹葭覆水濱，徘徊南望倚闌頻。", "年光似鳥翩翩過，世事如棋局局新。", "嵐積遠山秋氣象，月生高閣夜精神。", "驚飛一陣鳬鷖起，蓮葉舟中把釣人。"]'),
('49949b77-3e50-4529-ae6b-d1a8e9154fd3','大滌山','白元鑒','宋','宋诗','song-poetry','','[]','天壇絕頂山，彷彿翠微間。',48,'全唐诗/poet.song.252000.json','["天壇絕頂山，彷彿翠微間。", "跡久苔紋碎，雲根古木閒。", "丹成人已去，鶴駕未曾還。", "猶有簫吹響，時時下舊山。"]'),
('89281de1-66eb-438b-a414-2f2ef20347af','大滌洞','白元鑒','宋','宋诗','song-poetry','','[]','靈山實秀德，仙聖杳難親。',48,'全唐诗/poet.song.252000.json','["靈山實秀德，仙聖杳難親。", "水溜空沿石，雲扃不見人。", "川原世上異，日月洞中春。", "欲出虛無境，應修有待身。"]'),
('70c0d7c8-4d34-4f3c-aaac-d737cb0212c6','江湖偉觀','范希禹','宋','宋诗','song-poetry','','[]','望斷菰蒲烟水鄉，凭高不盡意蒼茫。',64,'全唐诗/poet.song.252000.json','["望斷菰蒲烟水鄉，凭高不盡意蒼茫。", "神州北去山川遠，王氣南來天地長。", "晴見白雲歸竺國，夜看紅日上扶桑。", "游人自擁笙歌醉，誰爲梅花酹一觴。"]'),
('2f6bec81-31d9-48f2-b072-7b415aa299bf','雙溪驛','翁世修','宋','宋诗','song-poetry','','[]','明月不隨雙派去，白雲長爲數峰留。',32,'全唐诗/poet.song.252000.json','["明月不隨雙派去，白雲長爲數峰留。", "夜窗星火歸漁艇，曉檻晴嵐映市橋。"]'),
('8d720495-dc2f-45c5-b973-c6d8cd77fb3b','題寶山廣嚴院','釋善建','宋','宋诗','song-poetry','','[]','垂手紅塵古所難，近天尺五啟禪關。',64,'全唐诗/poet.song.252000.json','["垂手紅塵古所難，近天尺五啟禪關。", "玉繩低轉簷楹外，宮漏微傳几席間。", "雲響度聲何處笛，翠稜當戶越州山。", "夢回露滴松梢冷，月在三茅萬境閒。"]'),
('6f8dd653-3090-4042-8dcc-e7b844b88edc','升香林洞','黄初庵','宋','宋诗','song-poetry','','[]','日射巖扉曉霧開，杖藜拄石破蒼苔。',32,'全唐诗/poet.song.252000.json','["日射巖扉曉霧開，杖藜拄石破蒼苔。", "一雙蛺蝶隨人去，知是香林洞裏來。"]'),
('2946f13d-f0d5-428f-94d1-9bd8b160a0b9','題靈鷲寺','黄初庵','宋','宋诗','song-poetry','','[]','屋畔危岑聳佛青，客歸僧定掩雲扃。',32,'全唐诗/poet.song.252000.json','["屋畔危岑聳佛青，客歸僧定掩雲扃。", "洞猿窣窣循牆過，几上偷翻貝葉經。"]'),
('9cde06d2-d338-4bf6-a861-690be5341e5c','題安隠院曲竹','林次麟','宋','宋诗','song-poetry','','[]','直節稜稜是此君，耳孫却以曲爲名。',32,'全唐诗/poet.song.252000.json','["直節稜稜是此君，耳孫却以曲爲名。", "首陽山下知難種，祇可斜封向管城。"]'),
('19c8b8d2-eed6-4ab7-abc7-e970f2aa8734','六和塔','何宋英','宋','宋诗','song-poetry','','[]','吳國山迎越國山，江流吳越兩山間。',64,'全唐诗/poet.song.252000.json','["吳國山迎越國山，江流吳越兩山間。", "兩山相對各無語，江自奔波山自閒。", "風帆烟棹知多少，東去西來何日了。", "江潮淘盡古今人，只有青山長不老。"]'),
('7bde1428-1c79-44d6-a0e1-cf3815f9f319','福勝院','趙仲藏','宋','宋诗','song-poetry','','[]','千騎踏清霜，東游古道場。',48,'全唐诗/poet.song.252000.json','["千騎踏清霜，東游古道場。", "雲籠山骨秀，風引水聲長。", "曉日依稀暖，寒花取次香。", "後隨吹管急，空谷答宮商。"]'),
('a5763d70-b347-4790-bd74-5c920d323ba8','題碧沼','裴極','宋','宋诗','song-poetry','','[]','一沼光涵四座寒，夕陽回首更凭欄。',32,'全唐诗/poet.song.252000.json','["一沼光涵四座寒，夕陽回首更凭欄。", "憑師早把香蓮種，他日期來結社看。"]'),
('3edcbe6e-7d05-4902-a24c-848eab2ff119','題章詡靜觀堂','李達可','宋','宋诗','song-poetry','','[]','君不見通都蕩蕩開九逵，肩摩轂擊人爭馳。',150,'全唐诗/poet.song.252000.json','["君不見通都蕩蕩開九逵，肩摩轂擊人爭馳。", "危樓百尺獨高卧，下看膠擾無休時。", "又不見滄江茫茫與天遠，輕舟出沒風濤險。", "此時著身平地人，遥憐櫂夫驚破膽。", "靜中有味知者希，紅塵拔脚與世違。", "世人顛倒墮醉夢，我獨坐照全天機。", "榮名弗羨計非拙，浮利勿爭癡更絕。", "騁巧不若拙有餘，役智何如癡且愚。", "高堂懸鏡收赴影，對此令人發深省。"]'),
('6283db38-b2c3-4f10-9a58-363354acca4f','首夏靜觀堂書懷','章詡','宋','宋诗','song-poetry','','[]','杖策下層嶺，來憩雲外莊。',120,'全唐诗/poet.song.252000.json','["杖策下層嶺，來憩雲外莊。", "簷低繞頹垣，澹泊在一堂。", "山高戶牖虛，風清長夏凉。", "翳翳動林影，瀲瀲浮溪光。", "心遠與世隔，獨有文史香。", "汲井資嚥漱，蒔藥助體强。", "園中橘爲奴，沼內芰堪裳。", "蒼官青不老，籬下明秋芳。", "陶情在庶物，養性歸琴觴。", "矯首起遐觀，是中有濠梁。"]'),
('283147ed-bd59-4337-b4f4-e14cf07c683b','閨怨','無名氏','宋','宋诗','song-poetry','','[]','有約未歸蠶結局，小軒空度牡丹春。',32,'全唐诗/poet.song.252000.json','["有約未歸蠶結局，小軒空度牡丹春。", "夜來揀盡鴛鴦繭，留織春衫寄遠人。"]'),
('cbc3900a-418e-4ad8-a3aa-a76cb54eb189','滄浪詠','胡理','宋','宋诗','song-poetry','','[]','昔聞滄浪亭，未濯滄浪水。',204,'全唐诗/poet.song.252000.json','["昔聞滄浪亭，未濯滄浪水。", "先賢渺遺跡，壯觀一何侈。", "飛橋跨木末，巨浸折胡壘。", "糟床行萬甕，繚牆周數里。", "廢興固在天，庶用觀物理。", "緬懷嘉祐世，周道平如砥。", "相君賢相君，子美東南美。", "如何一網盡，禍豈在故紙。", "青蠅變白黑，作俑茲焉始。", "所存醉翁文，垂耀信百世。", "無忘角弓詠，嘉樹猶仰止。", "同來二三子，感歎咸坐起。", "縹瓷酹新汲，毀譽均一洗。", "忽逢醒狂翁，一別垂二紀。", "雋哉老益壯，論事方切齒。", "我欲裂絳幔，推著明光裏。", "安得上天風，吹落君王耳。"]'),
('b57d20f3-77ab-44fe-b4ef-11d476a3a3ef','句','釋道川','宋','宋诗','song-poetry','','[]','我有一條鐵楖𣗖，縱橫妙用無人識。',32,'全唐诗/poet.song.252000.json','["我有一條鐵楖𣗖，縱橫妙用無人識。", "臨行撥轉上頭關，轟起一聲春霹靂。"]'),
('2998dc76-0dd5-4f8a-9873-aa36739102c6','句','劉浩','宋','宋诗','song-poetry','','[]','此中不醉又如何。',8,'全唐诗/poet.song.252000.json','["此中不醉又如何。"]'),
('e19c35f2-7005-4624-a326-932d5cc12833','丈亭館','釋義銛','宋','宋诗','song-poetry','','[]','青山歷歷映江流，半是明州半越州。',32,'全唐诗/poet.song.252000.json','["青山歷歷映江流，半是明州半越州。", "亭下寒潮亭上客，不知來往幾時休。"]'),
('31dc73d2-97de-420e-adee-b7a8cf0b55fe','句  其一','釋義銛','宋','宋诗','song-poetry','','[]','采石浪寒青冢暗。',8,'全唐诗/poet.song.252000.json','["采石浪寒青冢暗。"]'),
('39fda972-6dfc-417b-a500-08ff81d04d4f','句  其二','釋義銛','宋','宋诗','song-poetry','','[]','無熱天中第一仙。',8,'全唐诗/poet.song.252000.json','["無熱天中第一仙。"]'),
('150a9841-1d65-4163-8671-c317a19c316a','句  其三','釋義銛','宋','宋诗','song-poetry','','[]','風標高古漢唐無。',8,'全唐诗/poet.song.252000.json','["風標高古漢唐無。"]'),
('bcc0387a-79e3-48f2-a767-b3d4c6e4614d','句  其四','釋義銛','宋','宋诗','song-poetry','','[]','冰霜過了翩然去。',8,'全唐诗/poet.song.252000.json','["冰霜過了翩然去。"]'),
('60a64928-a0c3-4001-8a3c-fa80b696ae74','句  其五','釋義銛','宋','宋诗','song-poetry','','[]','平生一點調元意。',8,'全唐诗/poet.song.252000.json','["平生一點調元意。"]'),
('a114a866-6eb7-498d-b75c-fb59d3f62c7b','孟享仰瞻聖駕','釋必萬','宋','宋诗','song-poetry','','[]','輕塵不動馬蹄催，警蹕聲中聖輦來。',32,'全唐诗/poet.song.252000.json','["輕塵不動馬蹄催，警蹕聲中聖輦來。", "漢代威儀周禮樂，太平天子拜香回。"]'),
('7b49707b-b647-4e10-84db-820aa909f762','別衆','雲峰德師','宋','宋诗','song-poetry','','[]','澹然無累水雲僧，去住分明葉樣輕。',32,'全唐诗/poet.song.252000.json','["澹然無累水雲僧，去住分明葉樣輕。", "十字街頭休作夢，五湖依舊一枝藤。"]'),
('6d6e078f-8632-46ed-a73e-d0af0f2cd158','絕句','沈清友','宋','宋诗','song-poetry','','[]','昨天移棹泊垂虹，閑倚篷窗問釣翁。',32,'全唐诗/poet.song.252000.json','["昨天移棹泊垂虹，閑倚篷窗問釣翁。", "爲底鱸魚低價賣，年來朝市怕秋風。"]'),
('3d6c7bbf-5f46-4772-8158-57eddd672f59','句  其一','沈清友','宋','宋诗','song-poetry','','[]','起家紅蓼岸，傳世綠簑衣。',12,'全唐诗/poet.song.252000.json','["起家紅蓼岸，傳世綠簑衣。"]'),
('31c7be54-a1a8-40c6-b6d0-fa4d88167065','句  其二','沈清友','宋','宋诗','song-poetry','','[]','自便牛背穩，却笑馬蹄忙。',12,'全唐诗/poet.song.252000.json','["自便牛背穩，却笑馬蹄忙。"]'),
('277b7045-0b61-46cb-806b-34d98df16383','歸去詞','王仲素','宋','宋诗','song-poetry','','[]','種松雨濯髪，折筍春墮指。',24,'全唐诗/poet.song.252000.json','["種松雨濯髪，折筍春墮指。", "長嘯歸去來，滄江一天水。"]'),
('02b59b4e-e18a-444c-bcac-7b369c5f7f36','散策','何天定','宋','宋诗','song-poetry','','[]','孤坐忽不樂，出門聊散行。',48,'全唐诗/poet.song.252000.json','["孤坐忽不樂，出門聊散行。", "溪喧亂人語，樹偃礙農耕。", "雨徑莓苔積，陽陂草木明。", "道逢九十老，相對話承平。"]'),
('a71a11ce-e998-4711-8e4d-008326ce92a9','西窗','王曼之','宋','宋诗','song-poetry','','[]','西窗枕寒池，池邊老松樹。',24,'全唐诗/poet.song.252000.json','["西窗枕寒池，池邊老松樹。", "渴猿下偷泉，見影忽驚去。"]'),
('c8007526-545a-49e1-859b-13b3e7a5045b','春日郊行','王曼之','宋','宋诗','song-poetry','','[]','出門逢柳色，忽過野橋西。',48,'全唐诗/poet.song.252000.json','["出門逢柳色，忽過野橋西。", "坐石看潮長，隔花聞鳥啼。", "地隨芳草盡，樹與夕陽齊。", "不是桃源路，行人亦自迷。"]'),
('b255452b-fab3-4a23-b8e5-da6912d5a601','年年','范協','宋','宋诗','song-poetry','','[]','年年如燕一還家，又訪幽居過水涯。',32,'全唐诗/poet.song.252000.json','["年年如燕一還家，又訪幽居過水涯。", "風雨滿城春欲暮，山中猶有碧桃花。"]'),
('ffc8bd99-dc87-4562-8ba9-3ba50749f594','訪隠者不遇','吳子文','宋','宋诗','song-poetry','','[]','道人入山訪道人，山深俗朴雞犬馴。',32,'全唐诗/poet.song.252000.json','["道人入山訪道人，山深俗朴雞犬馴。", "道人不見道人去，𣰦毿草木無邊春。"]'),
('a24ccc9b-0557-4b36-b485-e76db23f5787','采菊','韓竹坡','宋','宋诗','song-poetry','','[]','擷我百結衣，爲君采東籬。',36,'全唐诗/poet.song.252000.json','["擷我百結衣，爲君采東籬。", "半日不盈掬，明朝還滿枝。", "悠然何處是，千古正如斯。"]'),
('e73905f6-c512-4eb7-849c-cdd72c792efa','美人','沈雲卿','宋','宋诗','song-poetry','','[]','十三學綉傍金窗，十六梳頭壓大拜。',32,'全唐诗/poet.song.252000.json','["十三學綉傍金窗，十六梳頭壓大拜。", "色比昭陽人第一，才同江夏士無雙。"]'),
('4af3c102-c3ac-4e41-9cae-f4517a4403dd','省試中式記夢','于觀文','宋','宋诗','song-poetry','','[]','東堂令史報來時，仙桂云攀第九枝。',64,'全唐诗/poet.song.252000.json','["東堂令史報來時，仙桂云攀第九枝。", "乍聽言音猶似夢，却思公道即無疑。", "寒門仿彿春將到，幽徑朦朧月漸移。", "殘漏聲中鞭馬去，紵袍重戴已相隨。"]'),
('81c1e998-06d8-4fb6-9b63-8ce1345ca9df','龍駒謠賀徐景醇生子','劉石庵','宋','宋诗','song-poetry','','[]','白虹流光橫太虛，蚌胎迸出明月珠。',98,'全唐诗/poet.song.252000.json','["白虹流光橫太虛，蚌胎迸出明月珠。", "紫瞳照席秋掣電，渥漥突出蒼龍駒。", "前年得子瘦如竹，失馬未必不爲福。", "今年得子燕頷豐，會看萬里飛食肉。", "徐君髪白顔且酡，晚而得子未足多。", "明年爲君招取杜陵老，來作徐卿二子歌。"]'),
('661a2342-e7ae-4ad2-8886-c0352de816cd','十月  其一','葉巽齋','宋','宋诗','song-poetry','','[]','維此十月，歲聿云暮。',80,'全唐诗/poet.song.252000.json','["維此十月，歲聿云暮。", "惟月之良，是謂盈數。", "陰極於坎，陽比於子。", "陰陽消長，否泰攸寓。", "亶生哲人，盛世基柱。", "文章機略，冊府武庫。", "承明厭居，雄藩外護。", "吏畏民愛，頌聲載路。"]'),
('270327a5-5df5-4522-b1b3-61fda1c924e6','十月  其二','葉巽齋','宋','宋诗','song-poetry','','[]','維此十月，稼穡孔實。',60,'全唐诗/poet.song.252000.json','["維此十月，稼穡孔實。", "黍稷稻粱，糜芑秠秬。", "取陳食農，遺秉伊婦。", "室家胥慶，小大饜飫。", "我公之德，穡寶是似。", "爲國珍粱，馨香薦祀。"]'),
('43d87c66-5e22-4bf2-9025-d0c957649749','十月  其三','葉巽齋','宋','宋诗','song-poetry','','[]','維此十月，可愛其日。',60,'全唐诗/poet.song.252000.json','["維此十月，可愛其日。", "光華朝升，融溫晏布。", "熙熙小春，物態和豫。", "清明在中，靡翳靡霧。", "我公之政，莫不休燠。", "衣服其和，悅我黎庶。"]'),
('a4657fa1-7510-49dc-a166-9bfbb44fec96','十月  其四','葉巽齋','宋','宋诗','song-poetry','','[]','維此十月，新霜始降。',60,'全唐诗/poet.song.252000.json','["維此十月，新霜始降。", "寒不折膠，凍不凝沍。", "凜然嚴師，少而慈父。", "戒示堅冰，衣裘蚤具。", "我公之威，伊教匪怒。", "不競不絿，無怨無惡。"]'),
('4ae013a6-1313-4ff4-bd56-c2fa0358b302','十月  其五','葉巽齋','宋','宋诗','song-poetry','','[]','維此十月，物寶全富。',60,'全唐诗/poet.song.252000.json','["維此十月，物寶全富。", "雪梅在嶺，霜菊盈圃。", "梧竹之高，椿松之固。", "賸馥郁芬，古根盤踞。", "我公之壽，此未足諭。", "峻峙精神，蜀江廬阜。"]'),
('b1e23f61-9ded-4c45-bc91-9502ef1269fb','十月  其六','葉巽齋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山岩岩，江水湯湯。',40,'全唐诗/poet.song.252000.json','["廬山岩岩，江水湯湯。", "磨而頌之，我公之功。", "釀而酌之，公福無窮。", "再拜稽首，以壽我公。"]'),
('5c30577f-a660-4251-847d-decb1d075fd5','十月  其七','葉巽齋','宋','宋诗','song-poetry','','[]','維此十月，其數無極。',40,'全唐诗/poet.song.252000.json','["維此十月，其數無極。", "自十而百，千萬及億。", "四百甲子，周而復始。", "書考中書，汾陽之比。"]'),
('ec4c0fda-9e3b-4303-9ed2-28d8bec893f9','壽主簿','吳申甫','宋','宋诗','song-poetry','','[]','武夷之山奇而青，九曲之水秀且清。',384,'全唐诗/poet.song.252000.json','["武夷之山奇而青，九曲之水秀且清。", "山奇水秀佳氣萃，孕毓多少名公卿。", "世運推來五百歲，岳瀆又應一賢生。", "相國蕭何儲大昴，謫仙李白扶長庚。", "拍塞家聲今幾載，雲來見此千人英。", "年少萬卷付一讀，胸中霜氣秋空橫。", "驊騮不作伏櫪態，夢寐抵掌收功名。", "屬時綠林肆分擾，鄰疆鼎沸無遑寧。", "笑看吳鈎應嚼齒，折衝不辭鞍馬塵。", "發輸紅腐活饑殍，呻吟變作謳歌聲。", "勾稽詎足究施設，直須舟楫濟通津。", "幕府籌功居第一，聯翩奏剡飛天庭。", "日邊消息清夜至，芝泥炳煥皇恩新。", "銓闈行脫囊中穎，佩玉鳴珂遊帝京。", "書雲過後兩旬及，還是霄躔初度辰。", "和氣恰隨陽氣轉，台星還並壽星明。", "北山底處香風動，湖山裏外祥烟輕。", "幃羅幙繡玳筵列，歌珠舞翠金壺傾。", "未祝修身如成子，未祝龐眉偕錢鏗。", "但願登金仍步玉，鹽梅商鼎早調羹。", "歸來武夷溪九曲，幔亭曾孫旋尋盟。", "眉壽堂中恣盤礴，摩挲銅狄細推評。", "武夷之山比公壽，與公千歲同崢嶸。", "九曲之水釀公酒，與公千歲供壽觥。"]'),
('9ce6a872-7f8b-4764-bdc0-cce78019c505','贈盡梅竹劉信可','李軏','宋','宋诗','song-poetry','','[]','劉兄胸次參元化，不發爲文發爲畫。',192,'全唐诗/poet.song.252000.json','["劉兄胸次參元化，不發爲文發爲畫。", "心工入妙手通神，聲名直與僧繇亞。", "月宮拔得玉兔毫，縛成篆筆銛如刀。", "紛然萬有類形役，竹梅兩品方清高。", "打一撇，籊爲寒筠灑爲葉。", "高低濃淡總相宜，不問風烟和雨雪。", "再一掃，清作疏花瘦作枝。", "向背斜陽俱造妙，任從籬落與垣池。", "君不見劉夢梁畫梅不畫竹，一枕清風長不足。", "又不見文與可畫竹不畫梅，千樹江頭空自開。", "爭如作者多精藝，庾嶺渭川俱著意。", "夢梁同姓表同文，却把信來更與字。"]'),
('0e24342e-d3cf-4308-86fd-ada9196abab6','贈寫神者  其一','李軏','宋','宋诗','song-poetry','','[]','弄墨調朱妙如神，底能瞥見寫吾真。',32,'全唐诗/poet.song.252000.json','["弄墨調朱妙如神，底能瞥見寫吾真。", "丁寧骨骼從渠灣，自有書生一樣人。"]'),
('a2590c78-ae1c-441d-adb4-c5427e8c6ce0','贈寫神者  其二','李軏','宋','宋诗','song-poetry','','[]','未信儒冠得誤儂，排雲消息夢魂中。',32,'全唐诗/poet.song.252000.json','["未信儒冠得誤儂，排雲消息夢魂中。", "君王若喚丹青手，畫我寒巖築晚風。"]'),
('29f5ed74-8a2b-4ce2-859f-7dcdfa3a98ac','畫楊妃扇','李軏','宋','宋诗','song-poetry','','[]','頗憶前身是謫仙，硯煩親捧玉堂前。',32,'全唐诗/poet.song.252000.json','["頗憶前身是謫仙，硯煩親捧玉堂前。", "如今再閲嬋娟面，不覺人間五百年。"]'),
('75862b92-8c6a-41fc-8aa9-7c588b53f245','贈畫僧鑑老  其一','王大受','宋','宋诗','song-poetry','','[]','累年投迹未知名，勝日相逢畫更精。',32,'全唐诗/poet.song.252000.json','["累年投迹未知名，勝日相逢畫更精。", "有思只愁人迫促，爲予拈出似平生。"]'),
('4b8eb238-3e0d-459a-a233-341a8b94bd97','贈畫僧鑑老  其二','王大受','宋','宋诗','song-poetry','','[]','高繫芒鞋聽學歸，一丘一壑自心知。',32,'全唐诗/poet.song.252000.json','["高繫芒鞋聽學歸，一丘一壑自心知。", "小窗閑憶經行處，貌得疏烟晚照時。"]'),
('3d60b49a-b4b6-4cf5-9cc1-032488d601d8','以疾止酒','王大受','宋','宋诗','song-poetry','','[]','分薄如雲可奈何，入秋榮氣欠平和。',64,'全唐诗/poet.song.252000.json','["分薄如雲可奈何，入秋榮氣欠平和。", "已於萬事都無念，只向三杯亦有魔。", "頓失花前多度醉，輕辜月下幾番歌。", "不留一物娛吾老，贏得東窗冷淡過。"]'),
('8e2ccb97-66b4-44d1-b648-8e99ec3f0656','寄甘孝先二首  其一','王大受','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黄金百鍊玉無瑕，水竹清風度歲華。',32,'全唐诗/poet.song.252000.json','["黄金百鍊玉無瑕，水竹清風度歲華。", "重到西湖非昨夢，唯餘清興對梅花。"]'),
('faf35464-9b15-45b9-9e83-45ec543ad03c','寄甘孝先二首  其二','王大受','宋','宋诗','song-poetry','','[]','古戍相從已許年，中間轉徙廢書傳。',32,'全唐诗/poet.song.252000.json','["古戍相從已許年，中間轉徙廢書傳。", "似聞南柵溪邊柳，準擬君來繫酒船。"]'),
('4e2c042e-8953-4be9-b4dd-011b1f46db73','客枕','王大受','宋','宋诗','song-poetry','','[]','山居猿狖最多情，嘯月旋風伴醉醒。',32,'全唐诗/poet.song.252000.json','["山居猿狖最多情，嘯月旋風伴醉醒。", "昨夜數聲霜雪外，元來不比在家聽。"]'),
('24c2a2d8-a3b1-4d6c-bc78-7e75db972a2b','玉山道中','王大受','宋','宋诗','song-poetry','','[]','夜夜還家夢，行行撲面風。',48,'全唐诗/poet.song.252000.json','["夜夜還家夢，行行撲面風。", "征塵添老色，酒病重詩窮。", "世路方行險，吾生且轉蓬。", "天涯重回首，愁滿夕陽中。"]'),
('fd2814dc-6847-4c3f-ba40-d565e37fc29a','焦山','王大受','宋','宋诗','song-poetry','','[]','自讀高陽贊隠君，便知名與此山存。',64,'全唐诗/poet.song.252000.json','["自讀高陽贊隠君，便知名與此山存。", "凭欄須及三更月，弔古空招千載魂。", "殿上風幡飛海燕，寺前石嶠過江豚。", "何人瘞鶴無蹤迹，猶有殘碑沒浪痕。"]'),
('db80b134-5df1-43f0-a7af-86b670dcbcb4','題道中觀梅','王大受','宋','宋诗','song-poetry','','["\u897f\u6e56"]','等雪不成花自開，是花飛雪不須猜。',64,'全唐诗/poet.song.252000.json','["等雪不成花自開，是花飛雪不須猜。", "一枝冷艷衝寒出，萬里春風破凍回。", "最愛橫斜無別樹，莫愁零落有蒼苔。", "幾年許却西湖醉，猶戀千巖未肯來。"]'),
('dfbfeed2-a6ab-4c82-b1fc-ad144f6d5d51','題亦足堂','王大受','宋','宋诗','song-poetry','','[]','舊聞有欲常難足，今日縱飽旋復饑。',64,'全唐诗/poet.song.252000.json','["舊聞有欲常難足，今日縱飽旋復饑。", "蟻穴夢濃方大妄，渭城歌斷正全癡。", "栽梅豈必萬株好，種竹何須千畝爲。", "想見午窗無欠剩，數杯家釀一枰棋。"]'),
('55f1534b-6bd7-47b4-80b0-4f35f6ac7802','曝書','王大受','宋','宋诗','song-poetry','','[]','歲月如流書似山，豈堪檢點鬢毛班。',64,'全唐诗/poet.song.252000.json','["歲月如流書似山，豈堪檢點鬢毛班。", "貧憂消耗記持少，場屋羈縻展拓難。", "事物無窮徒著眼，身心未了只長歎。", "直須種種從頭掃，掃到和書也不看。"]'),
('175a160e-67ec-44a1-be23-0bf446c500d0','遊洞霄山','裴相如','宋','宋诗','song-poetry','','[]','人間三十六洞天，各有邃道通神仙。',96,'全唐诗/poet.song.252000.json','["人間三十六洞天，各有邃道通神仙。", "茲山九鎖路曲折，中開五洞棲雲烟。", "東遊大滌望天柱，西登石室觀飛泉。", "窮幽討勝足未倦，明月忽墮青崖顛。", "山中道士借一榻，夜半猿鶴驚人眠。", "明朝又復出山去，白雲回首空悽然。"]'),
('043020f0-0f33-4139-8f6b-35e0caa50fe2','游洞霄','徐存','宋','宋诗','song-poetry','','[]','清真羽士舊仙官，日奉琳宮紫翠間。',64,'全唐诗/poet.song.252000.json','["清真羽士舊仙官，日奉琳宮紫翠間。", "五洞煙霞龍窟宅，一壺天地道家山。", "滌泉盤轉冰涵沼，隠石屏開玉敞關。", "可笑濯纓來覽勝，輸他高卧白雲閒。"]'),
('46c002de-877b-444a-9cd2-fdbc24a5eccd','題桂殿秋辭  其一','李仁本','宋','宋诗','song-poetry','','[]','飛翠蓋，走籃輿，亂山千疊爲先驅。',32,'全唐诗/poet.song.252000.json','["飛翠蓋，走籃輿，亂山千疊爲先驅。", "洞天迎目深且窈，滿耳天風吹步虛。"]'),
('1a050977-b448-45b1-a17f-572d7845d652','題桂殿秋辭  其二','李仁本','宋','宋诗','song-poetry','','[]','巑獸石，錯虬松，黛嵐終日下天風。',32,'全唐诗/poet.song.252000.json','["巑獸石，錯虬松，黛嵐終日下天風。", "杖藜携我恣遥望，縹緲霓裳飛碧空。"]'),
('d358d7c6-dccd-4989-bd7d-bfde3e23fa2f','題桂殿秋辭  其三','李仁本','宋','宋诗','song-poetry','','[]','金带重，紫袍寬，到頭不似羽衣閒。',32,'全唐诗/poet.song.252000.json','["金带重，紫袍寬，到頭不似羽衣閒。", "君王若許供香火，神武門前早挂冠。"]'),
('67398a6c-9b4e-49da-b0fe-38d4c2d7f491','游洞霄','駱安基','宋','宋诗','song-poetry','','[]','捫蘿探得雲根路，直入雲山最深處。',32,'全唐诗/poet.song.252000.json','["捫蘿探得雲根路，直入雲山最深處。", "主人心似青山閒，雲亦無心自來去。"]'),
('ddb0b117-9949-4dfb-89ca-5b4bc91eb618','洞霄山隠齋','聞九成','宋','宋诗','song-poetry','','[]','餘杭之西天柱峰，下有石洞蟠蒼龍。',128,'全唐诗/poet.song.252000.json','["餘杭之西天柱峰，下有石洞蟠蒼龍。", "齋居無塵山四合，仙人宴坐空翠中。", "夜捫北斗罡氣接，晨吸東日精光通。", "醉凌高風駕白鶴，笑視黄庭驅玉童。", "人間自有赤松子，方外或友洪崖公。", "丹泉吹陰曉霧碧，野果變色秋山紅。", "獻酬且盡琉璃鍾，談笑便是蓬萊宮。", "肯如金粟衰病翁，散花丈室談虛空。"]'),
('82eda58e-b052-43b3-8448-ce6369db6a8a','初入洞霄  其一','聞九成','宋','宋诗','song-poetry','','[]','擬借寒泉洗此心，幽亭曾屢謁清音。',64,'全唐诗/poet.song.252000.json','["擬借寒泉洗此心，幽亭曾屢謁清音。", "會須枕石伴龍睡，不爾吹簫學鳳吟。", "蟄地金丹聞往昔，插天琳宇盛當今。", "靈芝仙草寧無分，爲我山中試訪尋。"]'),
('5d30c2cd-3ae5-4951-b513-ed16e6473262','初入洞霄  其二','聞九成','宋','宋诗','song-poetry','','[]','胎仙舞處疊琴心，壇月高時聞佩音。',64,'全唐诗/poet.song.252000.json','["胎仙舞處疊琴心，壇月高時聞佩音。", "九鎖山扉元不閉，對閑詩句爲誰吟。", "長生可學凡成聖，陳跡休令後視今。", "欲餌流膏種松子，參天會見一千尋。"]'),
('c4c0d496-748c-4377-8c1a-3552858f45f4','楊先高題漱玉軒','聞九成','宋','宋诗','song-poetry','','[]','二龍觸鬬一不支，化爲怪石簷之垂。',160,'全唐诗/poet.song.252000.json','["二龍觸鬬一不支，化爲怪石簷之垂。", "神泉內溢石齒迸，漱激猶作瓊瑶飛。", "琴高赤鱓或在邇，借我一跨邀安期。", "遠來相就盥靈液，六腑共浥清凉滋。", "玉泉細度玉樓去，不礙丹元中守威。", "黄金隄邊審依護，視之則微聽則希。", "俯窺溟渤正澄澹，海若仰望朱靈旗。", "彼妄人子誇飲玉，死誑愚婦何所稽。", "何如隨我飲此水，辨玉別石俱忘機。", "真忘乃是大奇事，身可如木心可灰。"]'),
('aff0b056-3d97-45bc-96ab-30f8ae7ae99a','遊大滌','俞茂實','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','未了煙霞痼，來從大滌游。',144,'全唐诗/poet.song.252000.json','["未了煙霞痼，來從大滌游。", "一區藏世界，九鎖閟林丘。", "寒翠霏霏起，春波慢慢流。", "人間空岱嶽，海上謾瀛洲。", "隠迹悲猿鶴，祥光射斗牛。", "有人相領略，何地不夷猶。", "好景行行得，遺蹤細細搜。", "山根雲欲滃，石罅鳳仍留。", "琴瑟聽泉奏，珠璣看瀑流。", "山靈應有識，鄙句含包羞。", "逸興那能已，奇觀謾此酬。", "會須尋石室，相繼築菟裘。"]'),
('63a4fc75-604e-4707-8aec-1b1bafd1db6b','游大滌洞','程鏜','宋','宋诗','song-poetry','','[]','松風吹客衣，縹緲凌絕境。',60,'全唐诗/poet.song.252000.json','["松風吹客衣，縹緲凌絕境。", "古洞不見日，篝燈入幽暝。", "蒼苔暈石花，奔泉弄雲影。", "仙游願初遂，秋山魂未省。", "我生有宿約，結屋天柱頂。"]'),
('1dd7d296-cd0b-4b4f-88a9-1f927be0d77f','游大滌山','上官辰','宋','宋诗','song-poetry','','[]','山蟠鼇足雲千丈，溪折羊腸路九迴。',64,'全唐诗/poet.song.252000.json','["山蟠鼇足雲千丈，溪折羊腸路九迴。", "神石肯穿秦斧鑿，古壇曾見漢樓臺。", "秋山風雨銀河下，月夜笙簫玉佩來。", "山自青青泉自潔，百年蹤跡幾蒼苔。"]'),
('d2af5475-79e3-440d-b346-8040877c16fd','遊九鎖山','姚顯','宋','宋诗','song-poetry','','[]','九鎖碧陰凉，行人古道長。',48,'全唐诗/poet.song.252000.json','["九鎖碧陰凉，行人古道長。", "四山松雨過，一路稻雲香。", "怪瀑驚危磴，殘蟬亂夕陽。", "長安金屋好，夢不到山房。"]'),
('77b5aa22-0272-47b8-bb24-76e036ad8af5','游九鎖','沈中行','宋','宋诗','song-poetry','','[]','青山倚天分九峰，或踞虎豹蟠蛟龍。',112,'全唐诗/poet.song.252000.json','["青山倚天分九峰，或踞虎豹蟠蛟龍。", "奔霆白晝鞭玉虹，鐵花冰激青濛濛。", "中有浩劫元皇宮，彷彿崑閬雙衡嵩。", "洞門誰掣烟霞封，玉鼠石燕巢嵌空。", "列炬仰見仙人蹤，枰棋布子局未終。", "冥懷欲喚洪崖翁，共翳紫鳳驂飛鴻。", "一笑弱水三萬里，他年相見方壺中。"]'),
('ffbea076-4b72-48de-9de6-9398fa12c0c5','游大滌','曹誠明','宋','宋诗','song-poetry','','[]','天風吹我來洞天，青山九折溪迴環。',96,'全唐诗/poet.song.252000.json','["天風吹我來洞天，青山九折溪迴環。", "金堂玉室在何處，天壇石洞餘千年。", "鳳鳴朝陽凡鳥息，猿啼夜月空林寒。", "萬仞雲開湧翠壁，六月秋生飛玉泉。", "振衣長歌登絕頂，俯視浮世纖塵閒。", "吟成一笑欲飛去，千巖萬壑生雲烟。"]'),
('4c4ae8df-74d5-47e4-a757-151c3fa250c9','大滌洞天留題','曹誠明','宋','宋诗','song-poetry','','[]','好風吹我來洞天，雲山九折相回旋。',144,'全唐诗/poet.song.252000.json','["好風吹我來洞天，雲山九折相回旋。", "蒼虬綰結鎖清潤，翠蛟飛舞鳴潺湲。", "一從大滌豁心目，披蒙躡徑登來賢。", "棲真亭結翠微頂，臨風一嘯卑塵寰。", "鳳鳴曉靄群籟息，龍眠夜月山雲連。", "雙臺疊翠鎖空洞，危峰屹柱嶄蒼煙。", "金堂玉室亙萬古，蘭林蕙帳餘千年。", "三更雨滴傍簷石，六月秋生飛玉泉。", "瀹泉烹玉雋餘味，但覺兩腋如飛仙。"]'),
('2745a5e9-7339-4073-8028-d0461ed60d7e','呈貝懶雲先生','程浚','宋','宋诗','song-poetry','','[]','一片閒心祇在山，故將疏懶傲塵寰。',32,'全唐诗/poet.song.252000.json','["一片閒心祇在山，故將疏懶傲塵寰。", "白雲猶有往來意，師獨蕭然天壤間。"]'),
('e8245bd5-d5d1-42d6-8230-676ed8558a29','龔菊巖房清境堂即事','俞昕','宋','宋诗','song-poetry','','[]','物外神仙窟，巾車爲小停。',48,'全唐诗/poet.song.252000.json','["物外神仙窟，巾車爲小停。", "一泓寒玉境，四面翠微屏。", "清境詩無盡，紅塵眼頓醒。", "我來謀此住，把酒問山靈。"]'),
('bdf2e926-36d9-47f6-b258-c8a7fc637a3c','洞霄宮','皇甫介','宋','宋诗','song-poetry','','[]','大滌雲深日月遲，羽人曾作帝王師。',64,'全唐诗/poet.song.252000.json','["大滌雲深日月遲，羽人曾作帝王師。", "鼎中絳雪成千日，巖下幽花占四時。", "玉仗已乘鸞鶴去，青山難使鬼神移。", "人間萬事惟閒好，山頂誅茅待幾時。"]'),
('1417159c-1ad5-4207-8079-148f9ada33b3','遊洞霄','皇甫介','宋','宋诗','song-poetry','','[]','九曲煙霞染畫圖，羽人曾作帝王師。',64,'全唐诗/poet.song.252000.json','["九曲煙霞染畫圖，羽人曾作帝王師。", "鼎中絳雪成千日，巖下幽花占四時。", "仙客已驂鸞鶴去，青山難使鬼神移。", "何當繼踵長生地，疏瀹靈根出有爲。"]'),
('6973b447-4d97-4c92-b610-6ecb1d1ada07','自紫極觀過天柱','陳良孫','宋','宋诗','song-poetry','','[]','道在吾身宇宙寬，朝踰雲岫暮雲關。',32,'全唐诗/poet.song.252000.json','["道在吾身宇宙寬，朝踰雲岫暮雲關。", "丹靈不服春風轉，欲度世人那得閒。"]'),
('873b1583-5b84-43ee-97b8-97b6bb5b6fd3','雪中浴冷泉示諸友','陳良孫','宋','宋诗','song-poetry','','[]','風鼓空林雪蔽山，身如鐵石不知寒。',32,'全唐诗/poet.song.252000.json','["風鼓空林雪蔽山，身如鐵石不知寒。", "塵埃豈是相隨物，付與溪流出世間。"]'),
('9caa79da-147e-4014-88bf-d52151f05d71','洞霄宮','王介','宋','宋诗','song-poetry','','[]','飄飄遼鶴去難尋，野客重來嘆復吟。',64,'全唐诗/poet.song.252000.json','["飄飄遼鶴去難尋，野客重來嘆復吟。", "許邁林中丹竈冷，郭文山上白雲深。", "南陵事蹟都非昔，北嶺歸期直到今。", "珍重玉京無限意，待將功節養高岑。"]'),
('84c49af8-c71a-4bf0-bf10-816a243242aa','九日和杜子美韻','章至謙','宋','宋诗','song-poetry','','[]','九日登高眼界寬，羽衣雲集盡清歡。',64,'全唐诗/poet.song.252000.json','["九日登高眼界寬，羽衣雲集盡清歡。", "黄花滿泛淵明酒，白髪仍簪子夏冠。", "庭下流泉趨澗急，座間清氣逼人寒。", "不須更問明年健，但向眉頭鬢角看。"]'),
('7c669a23-419e-4560-8c31-b55507128964','山中紀詠  其一','龔文煥','宋','宋诗','song-poetry','','[]','勝地棲遲慣，青山耐久看。',48,'全唐诗/poet.song.252000.json','["勝地棲遲慣，青山耐久看。", "雲煙五洞古，泉石九峰寒。", "已化巖前虎，猶藏箬下丹。", "黄花生意別，秋老不凋殘。"]'),
('311e5215-d85b-425f-98b3-733b613c5d6f','山中紀詠  其二','龔文煥','宋','宋诗','song-poetry','','[]','白日幽情愜，閒門到者稀。',48,'全唐诗/poet.song.252000.json','["白日幽情愜，閒門到者稀。", "嗜茶和月煮，採藥带雲歸。", "春樹餘花落，天壇獨鶴飛。", "年華自來往，慵換薜蘿衣。"]'),
('eb80b920-5bc6-4f51-a7a1-30e2f2aaa91b','仙人隠跡  其一','吳洞明','宋','宋诗','song-poetry','','[]','上古有神仙，一去無消息。',24,'全唐诗/poet.song.252000.json','["上古有神仙，一去無消息。", "峨峨碧巖前，獨遺隠仙跡。"]'),
('e4acd33a-a518-4007-ae4f-2021aba0dabe','仙人隠跡  其二','吳洞明','宋','宋诗','song-poetry','','[]','長生玄牝門，目擊而道存。',24,'全唐诗/poet.song.252000.json','["長生玄牝門，目擊而道存。", "班班實可考，老澗生雲根。"]'),
('a96d45a5-7703-4083-8259-99e058411e70','仙人隠跡  其三','吳洞明','宋','宋诗','song-poetry','','[]','游人摩蒼崖，滿手聞異馨。',24,'全唐诗/poet.song.252000.json','["游人摩蒼崖，滿手聞異馨。", "不垂身後芳，何以知仙靈。"]'),
('15373e6e-0dde-48c2-87eb-ce790e58e7cc','和章清隠山居','吳洞明','宋','宋诗','song-poetry','','[]','物外無寒暑，從教歲月深。',48,'全唐诗/poet.song.252000.json','["物外無寒暑，從教歲月深。", "虛閒渾屬我，寵辱不驚心。", "貧樂知書味，詩豪借酒吟。", "山居何所有，萬籟奏清音。"]'),
('d7930796-13c3-47ec-b7c2-39465ad270c9','留春','吳洞明','宋','宋诗','song-poetry','','[]','柴門深閉莫嫌猜，爲怕春歸不敢開。',64,'全唐诗/poet.song.252000.json','["柴門深閉莫嫌猜，爲怕春歸不敢開。", "幾樹好花風𢬵去，一池新水雨添來。", "冥搜秀色增詩料，款挹晴光入酒杯。", "試問東君來復去，何如休去且徘徊。"]'),
('e9fd4ad3-cf23-49ea-a100-788ef699bc1c','晚春','吳洞明','宋','宋诗','song-poetry','','[]','瘦盡紅英綠已肥，杜鵑何事苦催歸。',32,'全唐诗/poet.song.252000.json','["瘦盡紅英綠已肥，杜鵑何事苦催歸。", "未甘淑景堂堂去，更挈壺觴上翠微。"]'),
('37eeae8f-b1d9-449a-a9a9-a0a0b2cc6750','遊洞霄得鄉友道士鄧君德清話因成古語','釋自彰','宋','宋诗','song-poetry','','[]','亂山倚伏龍蛇蟠，蒼藤古木門徑寒。',96,'全唐诗/poet.song.252000.json','["亂山倚伏龍蛇蟠，蒼藤古木門徑寒。", "蘂宮潭潭列萬礎，碧樓朱戶參雲端。", "吾聞上界足官府，謫下名山作仙侶。", "我來尋仙訪泉石，落日浮雲隨杖屨。", "道士鄧君吾故人，汲泉煮茗慰酸辛。", "笑談未厭樵柯爛，回首人間五百春。"]'),
('9d3b854f-6342-4e26-98ed-84349b333283','寓宿洞霄','釋淨珪','宋','宋诗','song-poetry','','[]','當年許郭棲真地，暇日尋幽獨往來。',64,'全唐诗/poet.song.252000.json','["當年許郭棲真地，暇日尋幽獨往來。", "九轉還丹藏箬底，千年遺迹寄巖隈。", "巍巍玉殿圍青嶂，寂寂瑶壇鎖綠苔。", "假榻壺天追勝集，尚憐歸興更徘徊。"]'),
('88b284a8-1299-47ab-9c69-204a79a416ee','偈','上官道人','宋','宋诗','song-poetry','','[]','處世紅塵五十八，混世獨存今始沒。',32,'全唐诗/poet.song.252000.json','["處世紅塵五十八，混世獨存今始沒。", "時人若問吾歸處，掃盡雲霞一輪月。"]'),
('c16ef256-077b-493b-b098-47d1e4e0c823','絕句','洞庭老人','宋','宋诗','song-poetry','','[]','八十滄浪一老翁，蘆花江上水連空。',32,'全唐诗/poet.song.252000.json','["八十滄浪一老翁，蘆花江上水連空。", "世間多少乘除事，良夜月明收釣筒。"]'),
('9c1b307c-62ef-4499-af2b-384d715b18c3','壽母','怡軒','宋','宋诗','song-poetry','','[]','又見梅妝碧玉枝，弟兄相聚著萊衣。',64,'全唐诗/poet.song.252000.json','["又見梅妝碧玉枝，弟兄相聚著萊衣。", "西方佛慶明朝誕，南極星勝壽日暉。", "百歲阿㜷開九秩，兩房孫子戲重闈。", "年年得侍高堂醉，對坐天花散漫飛。"]'),
('d49ce97b-9be4-4729-86e7-4a0693a77f97','北行作','杜氏','宋','宋诗','song-poetry','','[]','江淮幼女別鄉閭，好似明妃遠嫁無。',64,'全唐诗/poet.song.252000.json','["江淮幼女別鄉閭，好似明妃遠嫁無。", "默默一心歸故國，區區千里逐狂夫。", "慵拈簫管吹羌曲，懶繫羅裙舞鷓鴣。", "多少眼前悲泣事，不如花柳舊江都。"]'),
('d3782630-1e46-4dc2-a11b-81d6997e2e29','琴','周芝田','宋','宋诗','song-poetry','','[]','膝上橫陳玉一枝，此音唯獨此心知。',32,'全唐诗/poet.song.252000.json','["膝上橫陳玉一枝，此音唯獨此心知。", "夜深斷送鶴先睡，彈到空山月落時。"]'),
('4cefbb89-2221-42d3-a8b8-77cfa135533a','句  其一','周芝田','宋','宋诗','song-poetry','','[]','淋漓滿腹藏春雨，突兀半拳生曉雲。',16,'全唐诗/poet.song.252000.json','["淋漓滿腹藏春雨，突兀半拳生曉雲。"]'),
('3409988c-533f-4175-b3fb-5a8dff023cdc','句  其二','周芝田','宋','宋诗','song-poetry','','[]','草香花落後，雲黑雨來時。',12,'全唐诗/poet.song.252000.json','["草香花落後，雲黑雨來時。"]'),
('96c2b3f0-f501-4e5b-b039-232446788444','重陽','釋德豐','宋','宋诗','song-poetry','','[]','戰盡今秋見太平，西風多作北風聲。',32,'全唐诗/poet.song.252000.json','["戰盡今秋見太平，西風多作北風聲。", "不吹烏帽吹氈帽，籬下黄花笑不成。"]'),
('c2bd3a55-69db-4730-8bd1-b695bc8eba05','爲被虜婦作  其一','潘文虎','宋','宋诗','song-poetry','','[]','交交桑扈，交交桑扈，桑滿牆陰三月暮。',66,'全唐诗/poet.song.252000.json','["交交桑扈，交交桑扈，桑滿牆陰三月暮。", "去年蠶時處深閨，今年蠶時涉遠路。", "路傍忽聞人采桑，恨不相與携傾筐。", "一身不蠶甘凍死，祇憶兒女無衣裳。"]'),
('1b48783c-fe05-4d4b-9a34-948c2bdf49c7','爲被虜婦作  其二','潘文虎','宋','宋诗','song-poetry','','[]','不如歸去，不如歸去，家在浙江東畔住。',66,'全唐诗/poet.song.252000.json','["不如歸去，不如歸去，家在浙江東畔住。", "離家一程遠一程，飲食不同言語異。", "今之眷聚昔寇仇，開口强笑心懷憂。", "家鄉欲歸歸未得，不如狐死猶首丘。"]'),
('86eeb710-04c1-48ec-a3b1-8c5c07f87663','爲被虜婦作  其三','潘文虎','宋','宋诗','song-poetry','','[]','泥滑滑，泥滑滑，脫了繡鞋脫羅襪。',64,'全唐诗/poet.song.252000.json','["泥滑滑，泥滑滑，脫了繡鞋脫羅襪。", "前營上馬忙起行，後隊搭駝疾催發。", "行來數里日已低，北望燕京在天末。", "朝來傳令更可怪，落後行遲都砍殺。"]'),
('b13cf476-a16d-468e-9bd4-4f443bf6229a','爲被虜婦作  其四','潘文虎','宋','宋诗','song-poetry','','[]','鵓鴣鴣，鵓鴣鴣，帳房徧野相喧呼。',64,'全唐诗/poet.song.252000.json','["鵓鴣鴣，鵓鴣鴣，帳房徧野相喧呼。", "阿姊含羞對阿妹，大嫂揮淚看小姑。", "一家不幸俱被虜，猶幸同處爲妻孥。", "願言相憐莫相妬，這箇不是親丈夫。"]'),
('2cee2393-0d6e-487d-aa2e-ce5c51e45510','聯句','楊氏','宋','宋诗','song-poetry','','[]','珠簾半窗月，修竹一簾風。',24,'全唐诗/poet.song.252000.json','["珠簾半窗月，修竹一簾風。", "何事今宵景，無人解與同。"]'),
('8fb45d9a-c99c-41af-ad4d-dc7df111452e','寒','藍元威','宋','宋诗','song-poetry','','[]','朔風陣陣送將來，日午柴門寂不開。',64,'全唐诗/poet.song.252000.json','["朔風陣陣送將來，日午柴門寂不開。", "靈照只教添短褐，孟光重喚暖深杯。", "苦吟簷角玲瓏玉，閑撥爐頭榾柮灰。", "移步東籬紅日晚，細看凍蝶尚依梅。"]'),
('827fd359-55e3-4463-b6d4-d284313ff0e3','句','藍元威','宋','宋诗','song-poetry','','[]','潤松盡作龍鍾結，匝地渾銷雁齒高。',16,'全唐诗/poet.song.252000.json','["潤松盡作龍鍾結，匝地渾銷雁齒高。"]'),
('b6346395-a707-4f1c-844b-5897ffdc9093','贈令狐使','趙郡守','宋','宋诗','song-poetry','','[]','□城昔有山，登臨倚空闊。',120,'全唐诗/poet.song.252000.json','["□城昔有山，登臨倚空闊。", "震淩誰負舟，荆榛披雉堞。", "朅來亦期年，每每念陳迹。", "雖當補苴時，忍使勝覽絕。", "度材倣飛翬，開逕通遊轍。", "盍簪領嘉賓，舉酬及良夕。", "風清無規塵，夜寒聽伊笛。", "茫渺挹天根，淡蕩浮月魄。", "景色逐時新，詩聯懷古刻。", "樓成且志喜，平疇賸秋穡。"]'),
('72fe52e8-ac90-428f-996d-a18ee559bd6d','題資福院平綠軒','曾揆','宋','宋诗','song-poetry','','[]','終日勞勞雁鶩行，偶然來訪贊公房。',64,'全唐诗/poet.song.252000.json','["終日勞勞雁鶩行，偶然來訪贊公房。", "扶疏草木四圍合，縈繞溪流一带長。", "倚檻豈能成傑句，把杯多是說名方。", "問師乞取安心法，宴坐蒲團對佛香。"]'),
('c2dfb612-6f99-48cb-8078-10e2c058a91b','題資福院平綠軒','張掞','宋','宋诗','song-poetry','','[]','禪窗虛敞瞰西南，野色溪光接畫簷。',32,'全唐诗/poet.song.252000.json','["禪窗虛敞瞰西南，野色溪光接畫簷。", "雲去碧天無間斷，一看依約見山尖。"]'),
('24072af2-8dbe-4f80-82ee-fa4bafca4c14','寄題壽師塔南軒','何昌弼','宋','宋诗','song-poetry','','[]','焚修七十載，內外已圓成。',48,'全唐诗/poet.song.252000.json','["焚修七十載，內外已圓成。", "教相論因果，冥心契死生。", "紙窗應自白，花砌本無情。", "燕坐觀浮世，誰非走利名。"]'),
('21d6e384-2209-46b5-90f7-53402e5da88e','壽公禪老遊宴','何昌弼','宋','宋诗','song-poetry','','[]','不學參禪不學文，百年知樂任天真。',32,'全唐诗/poet.song.252000.json','["不學參禪不學文，百年知樂任天真。", "曾聞神定踰三日，疑是今生再世人。"]'),
('5b5c556e-bc04-4fd3-8666-ae4bf8598ae1','橫塘道中','何昌弼','宋','宋诗','song-poetry','','[]','一舸凌風去，縈紆幾度村。',48,'全唐诗/poet.song.252000.json','["一舸凌風去，縈紆幾度村。", "水清魚引子，田美稻生孫。", "山近塵埃遠，秋晴枕席溫。", "悠悠迷處所，疑是武陵源。"]'),
('e1efe209-8429-42c7-be9e-e5df52a63eda','詩一首','本之','宋','宋诗','song-poetry','','[]','一篙春水滑無聲，一葉輕舟過短亭。',64,'全唐诗/poet.song.252000.json','["一篙春水滑無聲，一葉輕舟過短亭。", "飛藹晚樓迷紫翠，夕陽孤塔認丹青。", "懷人遠折三花樹，何日相携雙玉瓶。", "欲喚漁郎問風色，鳬鷖飛處酒初醒。"]'),
('13d5fd28-74e5-435e-9e51-9a1244799818','項羽廟災','無名氏','宋','宋诗','song-poetry','','[]','嬴秦久矣酷斯民，羽入關中又火秦。',32,'全唐诗/poet.song.252000.json','["嬴秦久矣酷斯民，羽入關中又火秦。", "父老莫嗟遺廟毀，咸陽三月是何人。"]'),
('d4700c7b-ea67-4fba-a451-66b9932e8a04','題壁','無名氏','宋','宋诗','song-poetry','','[]','白塔橋邊賣地經，長亭短驛甚分明。',32,'全唐诗/poet.song.252000.json','["白塔橋邊賣地經，長亭短驛甚分明。", "如何祇說臨安路，不較中原有幾程。"]'),
('13da01b9-c069-4f49-8a52-24c0111ee4e6','題廣信道中','金麗卿','宋','宋诗','song-poetry','','[]','家住錢塘山水圖，梅邊柳外識林蘇。',32,'全唐诗/poet.song.252000.json','["家住錢塘山水圖，梅邊柳外識林蘇。", "平生慣占清凉國，豈料人間有暑途。"]'),
('a12a220c-24fb-4d91-bbd5-0ca1911a1a89','楊白花','魚潜','宋','宋诗','song-poetry','','[]','楊白花，誰教度簾幕。',42,'全唐诗/poet.song.252000.json','["楊白花，誰教度簾幕。", "摇蕩春風能幾何，不比無情自漂泊。", "人生祇合作支離，長秋鴉啼江水落。"]'),
('04cd5f6a-b146-4c3e-b805-f1217a2ca41d','古意  其一','魚潜','宋','宋诗','song-poetry','','[]','青青陵上柏，落落勁不摧。',84,'全唐诗/poet.song.252000.json','["青青陵上柏，落落勁不摧。", "人生百年內，朝夕變所懷。", "斗酒命同好，萬里不顧回。", "聞有昌國君，談笑黄金臺。", "柔言更長跪，信是富貴媒。", "但恐氣習移，古今不同才。", "寄言去國者，歲晚有餘哀。"]'),
('ae34a4c3-fe3e-43a9-9160-cd8465e6434b','古意  其二','魚潜','宋','宋诗','song-poetry','','[]','權衡豈公平，天駟但伏櫪。',48,'全唐诗/poet.song.252000.json','["權衡豈公平，天駟但伏櫪。", "東井不救渴，倉庫何時實。", "元工肯假借，名器甚可惜。", "如何萬萬古，不行督責術。"]'),
('39ae2fd5-bf69-4337-b21f-4272367da261','送鄭秘書南歸','魚潜','宋','宋诗','song-poetry','','[]','垂老乃如此，憑高俱惘然。',48,'全唐诗/poet.song.252000.json','["垂老乃如此，憑高俱惘然。", "空能正幾字，好去作千年。", "童子歌鴝鵒，幽人拜杜鵑。", "江花獨爛熳，春去得誰憐。"]'),
('ee7e65cc-d09d-4b5c-b2e2-4c415045f9c9','聞歌','魚潜','宋','宋诗','song-poetry','','[]','流雲行水出名姝，酒盡花前雙玉壺。',32,'全唐诗/poet.song.252000.json','["流雲行水出名姝，酒盡花前雙玉壺。", "此曲江南都忘却，春風轉調小單于。"]'),
('7ad5b19a-a274-40df-90be-36ba39c027f2','絕句','閩清野人','宋','宋诗','song-poetry','','[]','偶與雲水會，不與雲水同。',24,'全唐诗/poet.song.252000.json','["偶與雲水會，不與雲水同。", "雲散水流去，杳然天地空。"]'),
('e43c87ed-fbde-40a8-90ac-fa02234e45e3','書中山驛壁','番陽布衣','宋','宋诗','song-poetry','','[]','回頭四十五年非，無頼秋光滿客衣。',32,'全唐诗/poet.song.252000.json','["回頭四十五年非，無頼秋光滿客衣。", "可惜吳中蓴菜好，陸機張翰不同歸。"]'),
('ce8da568-daf1-4080-bd88-c842ff7517a3','遊山','朱景獻','宋','宋诗','song-poetry','','[]','凌雲峻嶺隔凡塵，嶺外湖天別是春。',64,'全唐诗/poet.song.252000.json','["凌雲峻嶺隔凡塵，嶺外湖天別是春。", "一千丈巖人已往，五百年事跡徒陳。", "自傳道貌今無垢，不脫禪衣句尚新。", "信是飛仙游戲處，何須雲外望三神。"]'),
('7b1961fc-fe9c-49ed-9409-e6947c45ed91','鴻門行','袁瓘','宋','宋诗','song-poetry','','[]','少年買意氣，百金不辭費。',264,'全唐诗/poet.song.252000.json','["少年買意氣，百金不辭費。", "學劍西入秦，結交北遊魏。", "秦魏多畸人，結交亦殊倫。", "由來不相識，皆是暗相親。", "寶馬金絲轡，狐裘貂鼠服。", "晨過劇孟遊，暮投咸陽宿。", "然諾本云云，諸侯莫不聞。", "猶思百戰術，更逐李將軍。", "始從灞陵下，遥遥度朔野。", "北風聞楚歌，南庭見胡馬。", "胡馬秋正肥，相邀夜合圍。", "戰酣烽火滅，路斷救兵稀。", "白刃縱橫逼，黄昏戰不息。", "虜騎血灑衣，單于淚沾臆。", "獻凱雲臺中，自言塞上雄。", "將軍行失職，部曲遂無功。", "新人不如舊，舊人不相救。", "萬里長飄飄，十年計不就。", "棄置難重論，驅馬度鴻門。", "行看楚漢事，不覺風塵昏。", "寶劍中夜撫，悲歌聊自舞。", "此曲不可終，曲終淚如雨。"]'),
('6fa16d26-9fcf-4cb1-b0f9-6eb975b61411','句  其一','袁瓘','宋','宋诗','song-poetry','','[]','芳草不復綠，王孫今又歸。',12,'全唐诗/poet.song.252000.json','["芳草不復綠，王孫今又歸。"]'),
('f91cd5d8-75d3-4939-9d89-09ef05a30388','句  其二','袁瓘','宋','宋诗','song-poetry','','[]','青州熟鐵不足數，衛公結鄰差可方。',16,'全唐诗/poet.song.252000.json','["青州熟鐵不足數，衛公結鄰差可方。"]'),
('d14edf56-c4cb-41ae-b17d-b32fad5111f7','仙都山','劉參','宋','宋诗','song-poetry','','[]','古帝此登仙，霓旌不復還。',120,'全唐诗/poet.song.252000.json','["古帝此登仙，霓旌不復還。", "孤標蒼嶺外，屹立紫煙間。", "上下形端柱，周迴影轉環。", "根疑連海嶠，頂欲突天關。", "蓮出湖心逈，苔漫轍迹斑。", "傍存鍊丹釜，低瞰步虛山。", "猿狖何能到，鸞凰自可攀。", "畫矜名手眇，吟怯鉅題艱。", "雁蕩非靈異，蘭巖鄙宴閑。", "縉雲遊覽處，勝概甲人寰。"]'),
('fa10064f-b994-4fca-94af-f964fff146b7','王徵君松陰獨坐圖','郭禮','宋','宋诗','song-poetry','','[]','盤石走新蘿，飛流下層巘。',48,'全唐诗/poet.song.252000.json','["盤石走新蘿，飛流下層巘。", "抱琴如有期，心與孤雲遠。", "鳥來天際微，林光澹將晚。", "受此松氣清，坐嘯不知返。"]'),
('2f69bd1b-85be-432f-9938-e95e4038bf0b','訪徐道人','郭禮','宋','宋诗','song-poetry','','[]','爲覓扁舟問隠淪，白雲何處是通津。',32,'全唐诗/poet.song.252000.json','["爲覓扁舟問隠淪，白雲何處是通津。", "瑶華滿地君堪拾，始信青山不負人。"]'),
('4ef10909-8fe2-4d30-b399-9655e218b0d5','揚州送別','薛廷玉','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','匹馬揚州路，香開幾樹花。',48,'全唐诗/poet.song.252000.json','["匹馬揚州路，香開幾樹花。", "春光無揀擇，淮地亦繁華。", "日沸長江水，風昏古戰沙。", "爭雄舊時事，君去莫思家。"]'),
('d2740fa8-de56-47e9-b684-970cf6c74cde','春夜宿山家','郭遠','宋','宋诗','song-poetry','','[]','嶂插清溪靜蓽門，數椽茅屋正黄昏。',32,'全唐诗/poet.song.252000.json','["嶂插清溪靜蓽門，數椽茅屋正黄昏。", "主人醉卧松間石，自繞梨花認月痕。"]'),
('12e97eae-e081-4b96-96a3-77a474a89505','馬家山','車瑾','宋','宋诗','song-poetry','','[]','山頭紅日生，山下螘蛙爭。',48,'全唐诗/poet.song.252000.json','["山頭紅日生，山下螘蛙爭。", "朝市誰能問，烟雲我自耕。", "胡麻調紫蕨，黄獨煮香秔。", "無意隨園綺，逃名更得名。"]'),
('003d5a1f-6270-45ad-95bc-cb0337780eec','豫章臺','況志寧','宋','宋诗','song-poetry','','[]','城陰零落豫章臺，平地晴沙捲雪來。',32,'全唐诗/poet.song.252000.json','["城陰零落豫章臺，平地晴沙捲雪來。", "欲訪鄰翁問塵跡，小園荒徑長莓苔。"]'),
('5fb2ad82-b87a-45e3-a887-d406795359ca','天寶洞','況志寧','宋','宋诗','song-poetry','','[]','風雨池邊古木寒，千年枸芑當晨餐。',32,'全唐诗/poet.song.252000.json','["風雨池邊古木寒，千年枸芑當晨餐。", "巖前石壁誰扃鎖，歲歲秋風長蕙蘭。"]'),
('b75a86fc-2c16-4465-adc3-dcb0df03da91','梅仙壇','況志寧','宋','宋诗','song-poetry','','[]','上疏歸來事可歎，嶺頭誰爲築星壇。',32,'全唐诗/poet.song.252000.json','["上疏歸來事可歎，嶺頭誰爲築星壇。", "先生不食炎劉祿，自拾松花當晚餐。"]'),
('e011f91f-8ace-4c00-9c6a-36db94996f3a','百花橋','況志寧','宋','宋诗','song-poetry','','[]','波光清淺玉虹橫，過客誰題柱上名。',32,'全唐诗/poet.song.252000.json','["波光清淺玉虹橫，過客誰題柱上名。", "錦鏽鋪張春色滿，小車花下麗人行。"]'),
('519324bc-06aa-4993-8597-5d31f24875e3','春風樓','況志寧','宋','宋诗','song-poetry','','[]','晴日遊絲拂畫欄，酒帘輕颺碧雲端。',32,'全唐诗/poet.song.252000.json','["晴日遊絲拂畫欄，酒帘輕颺碧雲端。", "春風蝴蝶知何處，愁切江南曲已殘。"]'),
('f859a7c8-da57-4092-bdd5-d763ff6ede74','杜貴墓','曹安','宋','宋诗','song-poetry','','[]','東出共城門，古墓何纍纍。',84,'全唐诗/poet.song.252000.json','["東出共城門，古墓何纍纍。", "就中如夏屋，下馬讀銘碑。", "始知太尉名，富擅政和時。", "詎知邑境中，倉皇來赤眉。", "敢勇率子弟，肆殺力弗支。", "編氓頼保全，迄今令名垂。", "潺潺百泉流，日夕聲猶悲。"]'),
('1b29c58b-bc92-4ea0-bc68-d18069b43836','玉柱峰','曹安','宋','宋诗','song-poetry','','[]','青山有石柱，直插浮雲杪。',24,'全唐诗/poet.song.252000.json','["青山有石柱，直插浮雲杪。", "月明鶴飛來，渾疑舊華表。"]'),
('14be40da-ef4b-4cc6-9be2-d86706b56583','七夕','薛秉','宋','宋诗','song-poetry','','[]','紅蕖爛熳碧池香，羅綺三千侍漢皇。',32,'全唐诗/poet.song.252000.json','["紅蕖爛熳碧池香，羅綺三千侍漢皇。", "阿母暫來成底事，茂陵宮樹已蒼蒼。"]'),
('f04b1950-8fc8-40b5-ab8e-65d216eca1ac','趙宰別業','吳澗所','宋','宋诗','song-poetry','','[]','幾樹柳陰合，空階一半遮。',48,'全唐诗/poet.song.252000.json','["幾樹柳陰合，空階一半遮。", "破琴長在壁，老鶴不離家。", "客至時供茗，官閒吏管花。", "有時成獨步，門外看蜂衙。"]'),
('2399cf31-4c81-45f0-bab0-13a47dabb930','過盤山','吳澗所','宋','宋诗','song-poetry','','[]','盤迴六七里，天色冷颼颼。',48,'全唐诗/poet.song.252000.json','["盤迴六七里，天色冷颼颼。", "石壁無平地，山雲隔遠洲。", "清笳悲送日，老卒病眠秋。", "行望酒家出，青山映碧流。"]'),
('c1ada646-f06a-41e0-ad61-0c1ef4afc508','躍馬泉','李景遹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','南山突兀橫青空，鹿豕禽魚得所宮。',256,'全唐诗/poet.song.252000.json','["南山突兀橫青空，鹿豕禽魚得所宮。", "修鱗于此亦養德，光怪夜發山川紅。", "風雲變化事已矣，獨有崖嶠留餘雄。", "至今山泉脈四溢，噴薄聲撼枯枬楓。", "填然下與石壁會，萬斛一竅投雲中。", "跳珠散玉虎鬚怒，烈日不照霜雪融。", "前賢作亭久已廢，後俗爲弊詞相蒙。", "匡廬老禪來立錫，攝衣思見前賢風。", "乃將爐峰三峽眼，坎井聊視海若同。", "搜奇剔怪勇興創，我爲一洗學古胸。", "叱開萬狀伏草獸，飛出百尺經天虹。", "桃花亂流春態度，明月淨寫秋形容。", "豈無白蛟尚蟠蟄，靈犀不燬無由通。", "平生赤手攬鯨鱷，長鋏自笑遺崆峒。", "邇來但餘觀水志，每到勝處難藏鋒。", "欲借天瓢添半水，醉騎赤鯶訪龍公。"]'),
('43a8bc46-b5a9-4259-b16f-e77a159ca850','妙庭觀  其一','祝鑄','宋','宋诗','song-poetry','','[]','石磴飛橋轉古壇，鐘聲敲斷水雲寒。',32,'全唐诗/poet.song.252000.json','["石磴飛橋轉古壇，鐘聲敲斷水雲寒。", "道人不復誇盤鼎，自得心傳養內丹。"]'),
('0d12c930-fec0-4ecc-af10-ee77b99b0197','妙庭觀  其二','祝鑄','宋','宋诗','song-poetry','','[]','風雨連山松竹鳴，宦途牢落若爲情。',32,'全唐诗/poet.song.252000.json','["風雨連山松竹鳴，宦途牢落若爲情。", "中宵嘹喨驚殘夢，疑是雲和重度聲。"]'),
('ccfde540-3e46-4a57-940f-2efba63e4d6e','天台石梁','趙清源','宋','宋诗','song-poetry','','[]','何處覓靈蹤，天台第一峰。',48,'全唐诗/poet.song.252000.json','["何處覓靈蹤，天台第一峰。", "雲深唯見寺，夜靜忽聞鐘。", "卓錫隨飛鶴，談玄起蟄龍。", "石橋如有約，跨月坐從容。"]'),
('1a2c9255-5724-4f1a-a0fe-5d943f4df31a','潯州行部','曹亨伯','宋','宋诗','song-poetry','','[]','冬來行部駕軺車，一日之間氣候殊。',32,'全唐诗/poet.song.252000.json','["冬來行部駕軺車，一日之間氣候殊。", "朝服駝裘暮揮扇，未應嵐瘴得全無。"]'),
('e852bb84-4979-4dd0-b431-759b21863c18','白石山','葉原賀','宋','宋诗','song-poetry','','[]','雲梯連石磴，香樹鎖松關。',24,'全唐诗/poet.song.252000.json','["雲梯連石磴，香樹鎖松關。", "林壑疑無路，神仙別有山。"]'),
('09aeb004-e9c3-4150-9789-5f28e3c8a4a6','野色','林東嶼','宋','宋诗','song-poetry','','[]','蒼茫一片誰能畫，不着雲烟態自殊。',64,'全唐诗/poet.song.252000.json','["蒼茫一片誰能畫，不着雲烟態自殊。", "漠漠平田新雨後，悠悠芳草夕陽餘。", "水光低映濃如染，天影遥連淡欲無。", "可恨風塵棲易混，石橋人斷竹蕭疏。"]'),
('db8dbdd1-9f0a-41d9-b255-ef8a596dafa1','讀書','薛仲庚','宋','宋诗','song-poetry','','[]','憂來驅我行，困來驅我睡。',132,'全唐诗/poet.song.252000.json','["憂來驅我行，困來驅我睡。", "文章堆案頭，時復一開視。", "豈能皆通說，偶然聊適意。", "駿馬驟平途，里程何足計。", "萬象羅目前，忽爲塵所昧。", "虎豹貴搜獵，狐兔從委棄。", "五鼎雖共珍，聞名豈知味。", "均此一卷書，今日與昨異。", "求名無欲速，要當畢斯世。", "古人不爲經，言動人偶記。", "悲哉漢諸儒，白首闇文義。"]'),
('08e4213e-b35f-4088-a9dd-e07dcbf1e845','春日','薛仲庚','宋','宋诗','song-poetry','','[]','晨遊每及晡，夜遊不知旦。',84,'全唐诗/poet.song.252000.json','["晨遊每及晡，夜遊不知旦。", "春風似醇醪，盎盎消我悶。", "春月似新茗，泠泠清我困。", "人生能幾逢，月圓花爛漫。", "何爲守幽獨，忽忽音容換。", "沂水舞雩人，天機自遊玩。", "叔子登峴山，浮名何足嘆。"]'),
('8925b376-86e2-4b42-a1d9-53612c53c070','搗衣曲','翟澥','宋','宋诗','song-poetry','','[]','寒蛩何處棲，棲傍砧石月。',68,'全唐诗/poet.song.252000.json','["寒蛩何處棲，棲傍砧石月。", "停砧問蛩鳴，砧動蛩復歇。", "似鳴辛苦心，欲替征人說。", "去年舊衣寄誰去，今年新衣織到曙。", "却移砧石來支機，蛩鳴復在支機處。"]'),
('93db8fe0-8fcb-4404-9a5e-da9e17a97ec6','秋日雜興  其一','謝雋伯','宋','宋诗','song-poetry','','[]','西風運金氣，萬籟含商聲。',72,'全唐诗/poet.song.252000.json','["西風運金氣，萬籟含商聲。", "寒蛩亦何爲，微音最凄清。", "幽人倦長夜，拊枕難爲情。", "朱門沸歌鐘，醉卧鴛鴦屏。", "晨鷄喚不醒，况乃聞蛩鳴。", "蛩聲自酸悽，頼有幽人聽。"]'),
('6276e46b-200a-48f2-8786-e498c3593cda','秋日雜興  其二','謝雋伯','宋','宋诗','song-poetry','','[]','高槐墮疏花，梁燕感時節。',60,'全唐诗/poet.song.252000.json','["高槐墮疏花，梁燕感時節。", "神飈駕輕翮，行計夙已决。", "飛鳴繞前簷，似與主人別。", "烏衣隔海雲，去去避霜雪。", "故壘尚未歸，相期杏花月。"]'),
('5e03d540-eb5a-4219-abf4-5091a2d4c14f','西湖偶成','謝雋伯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','思遠樓西平嶼東，會昌湖上藕花風。',32,'全唐诗/poet.song.252000.json','["思遠樓西平嶼東，會昌湖上藕花風。", "水亭隔岸湘簾捲，人倚闌干憶謝公。"]'),
('e9b9c8c4-ec80-4001-b423-dbaaa7be3b67','中宮院','熊道裕','宋','宋诗','song-poetry','','[]','我昨投文清泠淵，稍責老龍多睡眠。',160,'全唐诗/poet.song.252000.json','["我昨投文清泠淵，稍責老龍多睡眠。", "鐵笛穿雲久寂寞，作詩喚起劉高禪。", "劉高豢龍與龍語，一夜風雷共謀雨。", "雨師荷鍤破天河，阿香應門覓桴鼓。", "不用欒巴西噀酒，那用出龍煩魯叟。", "殷勤寄語望雲人，高僧自是調元手。", "今朝夏抵明日秋，一夕不雨還自休。", "南陌沾濡北阡渴，東鄰感激西家愁。", "安得黑雲如漏巵，處處家家田作池。", "予有鉢飯便可飽，雨我公田遂及私。"]'),
('393b01cd-7284-4881-b655-fabb448b83b2','偕康子雍州季子東所遊虔州通天巖','伍餘幹','宋','宋诗','song-poetry','','[]','山靈不爲紅塵掃，仙竇玲瓏自天巧。',192,'全唐诗/poet.song.252000.json','["山靈不爲紅塵掃，仙竇玲瓏自天巧。", "或開或合誰主張，元氣淋漓出蓬島。", "壓服坡陀萬象高，平鋪練带三江繞。", "水西接軫到斜陽，勒馬回□問遲早。", "不見真仙只爲仙，猶嫌禿髪頭顱老。", "三生豈必石點頭，三晉何□石言好。", "行先之後更幾人，龍奔虎噬爭雲擾。", "吳山但見楚山高，豈知砥柱千金寶。", "山崩雨蝕不知年，各得帡幪各相□。", "出門小吏驚且呼，虔州刺史心生惱。", "急著歸鞭信馬蹄，春風猶带蘭香草。", "燒燈更上鬰孤臺，吳楚東西春未了。"]'),
('8e635dd9-fb1b-4625-9d84-86ab4e88b583','疎山','俞鼐','宋','宋诗','song-poetry','','[]','路入千巖紫翠深，溪山好向夢中尋。',64,'全唐诗/poet.song.252000.json','["路入千巖紫翠深，溪山好向夢中尋。", "松風洗淨笙歌耳，泉石挽回花柳心。", "曲水流觴追禊事，茂林修竹是山陰。", "蘭亭舊墨空磨滅，俛仰人間成古今。"]'),
('f3567727-1fea-4ea4-8ae1-b5ea4ff82434','白水寺','李彌素','宋','宋诗','song-poetry','','[]','白水水逾白，疎山山不疎。',48,'全唐诗/poet.song.252000.json','["白水水逾白，疎山山不疎。", "林迷鐘遞響，路久衲分裾。", "寤寐念丘壑，征行懷簡書。", "西來有意否，試與問何如。"]'),
('a885779a-f93a-44e6-a347-057095ad3abd','和別駕蕭世範贈玉巖詩四首  其一','無名氏','宋','宋诗','song-poetry','','[]','莫守陳編學蠹魚，筌蹄真似古人書。',64,'全唐诗/poet.song.252000.json','["莫守陳編學蠹魚，筌蹄真似古人書。", "利名滄海浮漚聚，身世乾坤逆旅居。", "懶向明庭陳一得，還留故館積三餘。", "塵埃滿足崎嶇地，羨子摶風上日車。"]'),
('1acf3a63-cf05-4627-bd59-b00199602c62','和別駕蕭世範贈玉巖詩四首  其二','無名氏','宋','宋诗','song-poetry','','[]','折腰五斗信非天，薦禰徒勞一鶚書。',64,'全唐诗/poet.song.252000.json','["折腰五斗信非天，薦禰徒勞一鶚書。", "淵底縱鱗誇水泳，林間宿鳥樂巢居。", "心隨俯仰緣無慊，身任行藏自有餘。", "試問通衢何處是，聖門無限指南車。"]'),
('fcc881a6-297d-4b2b-b20b-1268f5b32bfb','和別駕蕭世範贈玉巖詩四首  其三','無名氏','宋','宋诗','song-poetry','','[]','堪笑先生四壁無，寒窗剩有五車書。',64,'全唐诗/poet.song.252000.json','["堪笑先生四壁無，寒窗剩有五車書。", "一童只許長鬚伴，半世長同隻影居。", "白屋不嫌藜藿少，朱門却厭稻粱餘。", "枕流漱石多佳趣，不羨人閒駟馬車。"]'),
('5af3b739-8e04-494b-ae5c-4375d9261893','和別駕蕭世範贈玉巖詩四首  其四','無名氏','宋','宋诗','song-poetry','','[]','富貴須論命有無，謀身只是半行書。',64,'全唐诗/poet.song.252000.json','["富貴須論命有無，謀身只是半行書。", "饑腸不羨千鍾粟，廣厦何如一畝居。", "世路茫茫終偃蹇，生涯處處是贏餘。", "蕭條此道誰爲助，掩卷時過長者居。"]'),
('57d825f9-0ae8-41ec-8231-dc7deb776768','疎山','艾申','宋','宋诗','song-poetry','','[]','夾道蒼松六月寒，塵埃只隔白雲閒。',64,'全唐诗/poet.song.252000.json','["夾道蒼松六月寒，塵埃只隔白雲閒。", "重遊恰是十年後，往事空驚一夢間。", "傑閣漫誇新卜築，危亭不似舊躋攀。", "憑誰說與矮師叔，投老求分一半山。"]'),
('f4378143-e7fa-4dab-b7bf-525475af0bd2','石茝','艾申','宋','宋诗','song-poetry','','[]','突兀倚蒼穹，誰云巧妙工。',48,'全唐诗/poet.song.252000.json','["突兀倚蒼穹，誰云巧妙工。", "滴□巖已竭，神運□常空。", "人入嵌□裏，春歸秋□中。", "□翁何處在，孤塔凜高風。"]'),
('3cd8c600-a189-45e9-8488-5c221101e038','白土寺','艾申','宋','宋诗','song-poetry','','[]','正爾炎官火傘張，幅巾來此坐僧房。',32,'全唐诗/poet.song.252000.json','["正爾炎官火傘張，幅巾來此坐僧房。", "箇中豈是全無暑，畢竟心清身自凉。"]'),
('c99b644a-ec91-40f3-8859-b17950c5eb2c','曉睡','郭儼','宋','宋诗','song-poetry','','[]','村巷閴無事，天明憩黑鄉。',48,'全唐诗/poet.song.252000.json','["村巷閴無事，天明憩黑鄉。", "草生詩意足，花落夢魂香。", "地迥秋供爽，雨餘風薦凉。", "休令山鳥閙，吾欲傲羲皇。"]'),
('787ce586-0e36-4a2e-a652-55bf141d1e82','蘭溪','郭儼','宋','宋诗','song-poetry','','[]','蘭陵山下翠烟浮，溪水潺湲九曲流。',32,'全唐诗/poet.song.252000.json','["蘭陵山下翠烟浮，溪水潺湲九曲流。", "落盡江梅聞鐵笛，烟波何處問垂鈎。"]'),
('3b75139c-5691-49b3-8c1f-bb5ca10a2a15','長沙','周光嶽','宋','宋诗','song-poetry','','[]','江上南風起白蘋，長沙城郭異咸秦。',32,'全唐诗/poet.song.252000.json','["江上南風起白蘋，長沙城郭異咸秦。", "故鄉猶自嫌卑濕，何況當時賦鵩人。"]'),
('ee749196-4414-449f-b8e6-a81d2bafb022','與周思伯明上人集慶善禪房','郭仲敬','宋','宋诗','song-poetry','','[]','可怪蓮花宇，相將倒玉瓶。',48,'全唐诗/poet.song.252000.json','["可怪蓮花宇，相將倒玉瓶。", "談來雲吐偈，煮罷石爲心。", "鳥過花陰亂，龍歸海氣腥。", "長齋呼米汁，應見佛眉青。"]'),
('a069b08f-998f-4a0e-87cc-558cec0dbcf3','壽淩元春宗伯六十','郭仲敬','宋','宋诗','song-poetry','','[]','舊是瑶階玉筍班，早乘白鹿出人間。',64,'全唐诗/poet.song.252000.json','["舊是瑶階玉筍班，早乘白鹿出人間。", "朝依漢殿參玄典，夕護仙爐煉大還。", "三月崆峒傳帝籙，千年姑射駐童顔。", "馬家仙井家園在，何事青牛遠渡關。"]'),
('6455521e-c77f-4b58-990b-ec2494b0fe9c','遊龍隠巖  其一','陳叔信','宋','宋诗','song-poetry','','[]','幾年鱗甲蟄清淵，一旦飛騰石自穿。',32,'全唐诗/poet.song.252000.json','["幾年鱗甲蟄清淵，一旦飛騰石自穿。", "遺跡漫存離舊隠，定應銜雨去朝天。"]'),
('251f72b9-b981-48a2-8060-cf83651d8483','遊龍隠巖  其二','陳叔信','宋','宋诗','song-poetry','','[]','洞口岩高著數椽，秋鈴聽法護金仙。',32,'全唐诗/poet.song.252000.json','["洞口岩高著數椽，秋鈴聽法護金仙。", "騰身一躍天池後，雲霧於今尚滃然。"]'),
('a8b82e02-f4f1-45cf-84f1-540a145e28a4','石橋','魏宗','宋','宋诗','song-poetry','','[]','聞說招提景，曇花結翠雲。',48,'全唐诗/poet.song.252000.json','["聞說招提景，曇花結翠雲。", "晴光朝更合，嵐氣晚來分。", "梵語微茫韻，鐘聲杳靄聞。", "無由問禪法，坐對柏爐薰。"]'),
('802a54dc-f77a-4fbc-be30-2f56c7ce75c7','陳山龍湫','卜祖仁','宋','宋诗','song-poetry','','[]','陳山蒼蒼東海頭，石壁裂缺藏靈湫。',128,'全唐诗/poet.song.252000.json','["陳山蒼蒼東海頭，石壁裂缺藏靈湫。", "老髯出水欻萬丈，青山倒挂黄金虬。", "神光上騰接烟靄，挾子攖珠浴滄海。", "雨公載雨推雷車，閶闔門開叩真宰。", "今年亢旱民罹殃，我侯憫憫心若傷。", "精誠披露動寥廓，沛然甘澤來滂滂。", "侯今官轉吳興去，回首神峰隔天宇。", "願言變化從雲龍，大爲蒼生作霖雨。"]'),
('9a0301d6-3426-4048-beb2-5c22cbb1a772','白雲寺','王商翁','宋','宋诗','song-poetry','','[]','幽人何處住，古寺白雲高。',48,'全唐诗/poet.song.252000.json','["幽人何處住，古寺白雲高。", "問路不知遠，到山方覺勞。", "半窗看竹石，一枕聽松濤。", "我亦清幽者，煮茶讀楚騷。"]'),
('a915357c-4d8a-41bf-b5f5-7f1381784027','過梧州','易謙','宋','宋诗','song-poetry','','[]','城空花熳爛，樓向雨蕭條。',48,'全唐诗/poet.song.252000.json','["城空花熳爛，樓向雨蕭條。", "毒草春生瘴，蠻江晚上潮。", "魚肥堪把釣，鳳去不聞韶。", "萬里雙持節，恩波頼聖朝。"]'),
('87e402e2-45d4-4fb1-ae2c-e86d0dcdb93f','遊玉巖  其一','陳謹','宋','宋诗','song-poetry','','[]','預作重陽半日遊，行厨望客屬鰲頭。',64,'全唐诗/poet.song.252000.json','["預作重陽半日遊，行厨望客屬鰲頭。", "樽前綠橘當時果，嶺下清泉徹夜流。", "新竹未斑秋正好，晚禾纔熟歲仍收。", "使君須盡登臨興，行捧天書未許留。"]'),
('fc06bd10-e5bb-4728-8053-38ff50ab49bc','遊玉巖  其二','陳謹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','同向天巖最上游，詩翁來見九螭頭。',64,'全唐诗/poet.song.252000.json','["同向天巖最上游，詩翁來見九螭頭。", "僧房爲映川原好，野水空隨歲月流。", "玉節朝天行日促，金風驅雨暮雲收。", "已摹大字鎸山骨，要與匡廬萬古留。"]'),
('6ea24209-7fdf-437a-82d4-b05f493f4580','相湖','朱升之','宋','宋诗','song-poetry','','[]','世路羊腸淹客遊，塵纓來此濯清流。',64,'全唐诗/poet.song.252000.json','["世路羊腸淹客遊，塵纓來此濯清流。", "半窗修竹翠含雨，一片澄湖冷清秋。", "地僻莓苔侵石几，機忘鷗鷺近漁舟。", "夜凉酒醒未能睡，詩句欲成搔白頭。"]'),
('3397d584-194f-4399-9813-1132bcf9e4eb','龍隠岩  其一','張金','宋','宋诗','song-poetry','','[]','何年此地蟄飛龍，石壁蜿蜒尚有蹤。',32,'全唐诗/poet.song.252000.json','["何年此地蟄飛龍，石壁蜿蜒尚有蹤。", "爲報龍公莫貪睡，郡人於爾卜凶豐。"]'),
('92c9572f-2b52-44ce-b736-1bdac642dbb7','龍隠岩  其二','張金','宋','宋诗','song-poetry','','[]','欲訪真仙小有天，路窮崖絕俯靈泉。',32,'全唐诗/poet.song.252000.json','["欲訪真仙小有天，路窮崖絕俯靈泉。", "相君聊試濟川手，翳鳳驂鸞盡有緣。"]'),
('09e3712d-1d70-4ad1-9a46-c15d9eb723f1','題玉岩次韻  其一','鄭藴','宋','宋诗','song-poetry','','[]','亂山環繞疑無路，却望人家嶺上村。',64,'全唐诗/poet.song.252000.json','["亂山環繞疑無路，却望人家嶺上村。", "古寺性躭泉石趣，孤城不見水烟昏。", "早行携杖雪初起，夜誦挑燈景尚暄。", "遥問隠居何處是，滿巖松竹至今存。"]'),
('e3c5b38d-3249-43b5-bb14-19f63a09a42f','題玉岩次韻  其二','鄭藴','宋','宋诗','song-poetry','','[]','世路從來疏散甚，江山好處且歸休。',64,'全唐诗/poet.song.252000.json','["世路從來疏散甚，江山好處且歸休。", "飯餘正好遠尋景，棋罷何妨閒倚樓。", "嶺外梅疏初破臘，岩前松老不知秋。", "晚風落日催歸興，更約閑時取次遊。"]'),
('0237c384-56aa-4a15-bb6d-d5015d9290a2','遊金精次謝東野韻','廖斯任','宋','宋诗','song-poetry','','[]','跨鶴仙妹已九霄，尚餘勝地景偏饒。',64,'全唐诗/poet.song.252000.json','["跨鶴仙妹已九霄，尚餘勝地景偏饒。", "石盤洞口疑無路，水繞山根忽有橋。", "樓殿雲栖迷曉日，筠松風度響寒潮。", "番君可笑成癡絕，妄擬陽臺佩輦邀。"]'),
('a2718350-94fa-4828-8dbd-ee8870568ef5','全州尹氏觀','鄒野夫','宋','宋诗','song-poetry','','[]','不嫁當年自薄情，一朝跨鶴上青冥。',32,'全唐诗/poet.song.252000.json','["不嫁當年自薄情，一朝跨鶴上青冥。", "人間有女能如此，羞殺天邊織女星。"]'),
('70a0609b-7198-4e15-bfa1-5495285faa77','夜寓舟中','徐德輝','宋','宋诗','song-poetry','','[]','秋氣清如水，推篷夜不眠。',48,'全唐诗/poet.song.252000.json','["秋氣清如水，推篷夜不眠。", "蘆花新有雁，莎葉尚鳴蟬。", "斷夢疑堪續，哀吟最可憐。", "漁童看月上，吹笛舵樓前。"]'),
('b6a4fbec-054c-4990-8e45-b8c6dd466394','夏日和韻','徐德輝','宋','宋诗','song-poetry','','[]','方沼晴波動，虛堂午蔭新。',48,'全唐诗/poet.song.252000.json','["方沼晴波動，虛堂午蔭新。", "夏衣誰賜葛，午食自烹鱗。", "山近書多潤，窗開硯易塵。", "試茶燃石鼎，汲井就西鄰。"]'),
('a9c94acf-7e47-49c3-8d0c-cbd08a51de09','初夏遊謝公巖','徐德輝','宋','宋诗','song-poetry','','[]','又取紗衣換，天時起細風。',48,'全唐诗/poet.song.252000.json','["又取紗衣換，天時起細風。", "清陰花落後，長日鳥啼中。", "水國乘舟樂，巖扉有路通。", "州民多到此，猶自憶髯公。"]'),
('a8076438-3f88-4402-afc4-536e324725a7','寄隠士','徐德輝','宋','宋诗','song-poetry','','[]','亭深自無暑，苔徑復縈紆。',48,'全唐诗/poet.song.252000.json','["亭深自無暑，苔徑復縈紆。", "賓客不長到，兒童足可娛。", "荷花晴带粉，蒲葉晚凝珠。", "與爾城闉隔，茲歡想不殊。"]'),
('05bfab83-be0c-4bb8-885d-e985aa161c06','釣臺','徐德輝','宋','宋诗','song-poetry','','[]','歸把灘頭舊釣竿，帝王只作故人看。',64,'全唐诗/poet.song.252000.json','["歸把灘頭舊釣竿，帝王只作故人看。", "此身合向丘林著，漢祚已如磐石安。", "流水無情千古在，客星有影九天寒。", "到頭笑殺鴟夷子，便下扁舟去也難。"]'),
('2c4e06bb-41ed-4e68-82d9-8fd5cad30f3a','全州南城','馮岵','宋','宋诗','song-poetry','','[]','全州城南何壯觀，石崖爲趾江爲濠。',240,'全唐诗/poet.song.252000.json','["全州城南何壯觀，石崖爲趾江爲濠。", "凌落渡江騎馬去，空濛瘴霧漫綈袍。", "邐迤過灘水，小艇浮桐槽。", "半渡急雨雪，舟師失飛篙。", "雨飛山路水如注，石齒犖确森戈刀。", "馬蹄轉側不得過，有力如虎空皮毛。", "地窮路盡處，橫絕青山高。", "褰衣扶杖躡天險，十步九顧愁猿猱。", "長沙頓伏幾百折，背膂菌蠢盤鯨鰲。", "馬瘦人力倦，野闊風怒號。", "薄暮投宿驅濕厲，析薪爨鼎燒村醪。", "一杯酸澀不可嚥，平原督郵羞兒曹。", "我行湖湘歷八郡，政欲閲實寧辭勞。", "才疏病懶事多廢，南山何日接蓬蒿。", "清風明月共三友，山猿野鶴來二豪。", "一江春水澄葡萄，蘆花萬頃眠漁舠。"]'),
('3397f455-eeba-4451-95cf-8994dd7a34ec','過全州','陶金','宋','宋诗','song-poetry','','[]','南北東西幾萬峰，郡城如在畫圖中。',32,'全唐诗/poet.song.252000.json','["南北東西幾萬峰，郡城如在畫圖中。", "何人裁斷湘妃竹，半蘸秋江作釣筒。"]'),
('0b27ea4f-1126-4538-8463-d117b8669411','雲安玉虛觀南軒感事二首  其一','杜柬之','宋','宋诗','song-poetry','','[]','樨梧殖歲首，擢起青琅玕。',108,'全唐诗/poet.song.252000.json','["樨梧殖歲首，擢起青琅玕。", "其葉大如掌，其陰勻若攤。", "弱幹尋丈展，氣已風雲干。", "期之四五載，定足容棲鸞。", "我老無定居，僦屋蝸螺跧。", "平生輞川宅，面勢胸中盤。", "何當遂誅茆，規庭十步寬。", "非無松柏堅，未易蒼龍摶。", "種此南窗下，醉眠風雨寒。"]'),
('ddd5d0a1-2002-4baf-9f8b-db0bb65607af','雲安玉虛觀南軒感事二首  其二','杜柬之','宋','宋诗','song-poetry','','[]','念我蓄一櫛，間關走西東。',120,'全唐诗/poet.song.252000.json','["念我蓄一櫛，間關走西東。", "携持三十年，出處靡不同。", "朝梳带殘月，暮理含清風。", "戶樞既日運，何由生蠹蟲。", "今晨無故折，脆響猶春葱。", "物理有定數，吾生得無窮。", "即事感百慮，撫躬悲一翁。", "空囊乏贐鐵，閙市多良工。", "鸞膠墮渺茫，秋扇慚初終。", "從渠老齒豁，稱我醉顱童。"]'),
('6ca5e1e0-1ed9-4992-a48d-cc20a9c822f4','雲安下巖','杜柬之','宋','宋诗','song-poetry','','[]','濤江翻雪卷湖灘，晚泊巖扉暫解顔。',64,'全唐诗/poet.song.252000.json','["濤江翻雪卷湖灘，晚泊巖扉暫解顔。", "夙有淨緣逢寺喜，老無生理伴僧閑。", "殘雲已斷獨飛雨，落日將沈却照山。", "半夜秋聲驚客夢，一簾珠貝冷珊珊。"]'),
('b0d09e41-1652-4860-9440-ca837f01f196','雲安玉虛觀南軒感事偶書五首  其一','杜柬之','宋','宋诗','song-poetry','','[]','二儀鼓爐鞴，四山塞氣煙。',96,'全唐诗/poet.song.252000.json','["二儀鼓爐鞴，四山塞氣煙。", "豈惟草木焦，坐恐土石然。", "巴峽再不登，逡巡又無年。", "流殍竟何歸，卒死填溝淵。", "哆吻魏佛貍，積粟窺淮堧。", "僥倖一水旱，乘饑擾吾邊。", "小人不及夕，妄憂杞國天。", "敢謂赫赫楚，而無蔿賈賢。"]'),
('57521f27-3b74-4e09-b997-a2de1833eea8','雲安玉虛觀南軒感事偶書五首  其二','杜柬之','宋','宋诗','song-poetry','','[]','古觀久荒凉，寂然外人境。',120,'全唐诗/poet.song.252000.json','["古觀久荒凉，寂然外人境。", "草木既蓁蕪，風雨亦頹隕。", "我來一糞除，地凈窗爲冋。", "晨光散桐陰，夕照落柏影。", "置以六尺床，度此三伏永。", "終朝饜清凉，半夜或淒冷。", "客至共浮瓜，睡餘獨煮茗。", "遥聞斗筲兒，爭奪沸蛙黽。", "街頭米十千，旱井費縻綆。", "對我脫粟盤，徐餐休祝鯁。"]'),
('57c39138-5356-4d83-b257-4fb0b0e78034','雲安玉虛觀南軒感事偶書五首  其三','杜柬之','宋','宋诗','song-poetry','','[]','嗟余何不辰，備極生人凶。',216,'全唐诗/poet.song.252000.json','["嗟余何不辰，備極生人凶。", "偶全摺脅范，屢脫南冠鍾。", "再醮亦何爲，孫枝發枯桐。", "鬼猶果求食，寧吐殺與豐。", "兩兒如我長，無田學圃農。", "鄭忽敢辭昏，冗食哀我翁。", "茲外尚難言，二女累橋公。", "荆笄嫁不售，誰論德與容。", "幼也抱奇疾，此歲日尪癃。", "亦既就膏肓，二豎不可攻。", "而我事奔走，過家如狂風。", "豈無旬浹留，奈此旦夕暮。", "吞酸一執手，掣去如飛蓬。", "心知不再見，衰淚紛無從。", "書來報哀訃，齎恨歸亡窮。", "莫聞忍死言，藁葬青蓮宮。", "爲父我安忍，爲兒汝何逢。", "興言一及此，鏃刃戕心胸。"]'),
('6478a5bd-48c9-4ac0-b70a-ab0030ed3601','至自雲安題凈戒院二首  其一','杜柬之','宋','宋诗','song-poetry','','[]','山口出雲鳩喚雨，三月巴山蒸溽暑。',96,'全唐诗/poet.song.252000.json','["山口出雲鳩喚雨，三月巴山蒸溽暑。", "濁流來作虎眼文，一葉孤舟命如縷。", "道傍綠樹清陰凉，中有金仙古道場。", "去家纔餘二百里，且復看此青篔簹。", "出門滿目傷覊旅，歸舍還煎碎兒女。", "欲問闍黎借榻眠，卧對龕燈淡無語。"]'),
('2d04eb96-0d52-4ab6-88ea-5ee6ec4977fa','至自雲安題凈戒院二首  其二','杜柬之','宋','宋诗','song-poetry','','[]','麥芒焦，桑椹紫，田家夫婦忙欲死。',96,'全唐诗/poet.song.252000.json','["麥芒焦，桑椹紫，田家夫婦忙欲死。", "蠶入簇，麥登場，夫婦飽煖孰可當。", "道旁書生空有婦，不蠶而衣真汝負。", "功名富貴老不來，書劍風塵一生誤。", "何時郎買百株桑，身耕婦織策最良。", "董生莫厭徵租吏，蘇子無由黑貂弊。"]'),
('b8734eec-3303-42be-9553-fb72fe07d734','入山','胡圭','宋','宋诗','song-poetry','','[]','擺落世塵縛，願結巖栖緣。',48,'全唐诗/poet.song.252000.json','["擺落世塵縛，願結巖栖緣。", "一層復一層，古道多迴旋。", "白雲隨我後，幽鳥鳴我前。", "雲禽亦佳侶，一見即忻然。"]'),
('9cec7831-9793-4bc5-9e64-1773c46f6441','春行南村','胡圭','宋','宋诗','song-poetry','','[]','鳥語知春晨，晨起行阡陌。',48,'全唐诗/poet.song.252000.json','["鳥語知春晨，晨起行阡陌。", "雨晴氣已變，崖澗嵐猶積。", "雜花林際明，新水田中白。", "時逢耦耕人，問我將何適。"]'),
('7982be80-02e5-4fb4-b188-6621707617dc','山池','胡圭','宋','宋诗','song-poetry','','[]','鑿山成小池，貯茲一泓綠。',48,'全唐诗/poet.song.252000.json','["鑿山成小池，貯茲一泓綠。", "參差散石髪，清淺浮碧玉。", "光風時動摇，漣漪細相續。", "我常遶池行，衣無塵可濯。"]'),
('75f9487e-7784-4876-8f88-22ff705cca9f','宿蔣庵','胡圭','宋','宋诗','song-poetry','','[]','松色聳寒青，雲庵夜未扃。',48,'全唐诗/poet.song.252000.json','["松色聳寒青，雲庵夜未扃。", "行吟滿林葉，坐聽一僧經。", "江獺鳴如鬼，山燈遠似星。", "自能消冷漠，不用酒盈瓶。"]'),
('1783e5d4-bf0d-42c9-8dc4-cbf3b9c5654c','鄜臺','杜純祐','宋','宋诗','song-poetry','','[]','兩載低眉著小冠，一臺高築地平寬。',32,'全唐诗/poet.song.252000.json','["兩載低眉著小冠，一臺高築地平寬。", "向陽花木齊教放，天下無春似此間。"]'),
('c3b3fc77-7d68-4f9d-9719-75bb29bb262c','瀛巖','董荆楚','宋','宋诗','song-poetry','','[]','巖根商舸集高桅，巖頂朱門小殿開。',64,'全唐诗/poet.song.252000.json','["巖根商舸集高桅，巖頂朱門小殿開。", "未信瀛洲環弱水，始知鼇背負蓬萊。", "青山到海重重小，白鳥隨潮兩兩來。", "坐久松風吹骨冷，此身渾覺在瑶臺。"]'),
('2b7e9f76-3607-4b2f-9bcf-25318ef3b397','妙庭觀','范良龔','宋','宋诗','song-poetry','','[]','我昔遨遊周八極，玉京金闕俱經歷。',224,'全唐诗/poet.song.252000.json','["我昔遨遊周八極，玉京金闕俱經歷。", "翩然騎鳳下瑶池，如與雙成獲相識。", "雙成侍燕王母旁，道貌方瞳照人碧。", "玉笙吹徹奉瓊觴，范子從旁丐餘瀝。", "東方曼倩謂余言，汝亦名在地仙籍。", "鳳城南望好溪山，此是元君故仙宅。", "琉璃槃上存金鼎，鼎內丹砂如琥珀。", "汝能服食早歸來，與予同是逍遥客。", "我時貪醉蟠桃春，不記當年說仙蹟。", "一朝酒醒人世非，盤碎丹飛杳難覓。", "香風堂上久徘徊，蘇李題詩掛空壁。", "孤雲野鶴謾興怨，我獨摩挲問金狄。", "世人勸我舐丹鼎，我亦何嘗苦營役。", "丈夫自有大還丹，得道不分今與昔。"]'),
('92b9bfaf-85c4-4439-8c43-166e38f1d2d8','洪遂良自京師東歸贈以詩','姜大民','宋','宋诗','song-poetry','','[]','故山西郭有園林，之子東歸抱短琴。',64,'全唐诗/poet.song.252000.json','["故山西郭有園林，之子東歸抱短琴。", "衣錦未論當日事，首丘聊慰阿翁心。", "春風桑梓歡娛極，秋雨松楸感慨深。", "莫寫渭陽圖畫裏，令人披閲重沾襟。"]'),
('a4fe17fb-e6d6-4e97-b567-3bc59b6e352c','客居嶺南','張子龍','宋','宋诗','song-poetry','','[]','天風吹白波，歸客欲如何。',48,'全唐诗/poet.song.252000.json','["天風吹白波，歸客欲如何。", "炎國逢花早，春船載雨過。", "畏蛇焚癭木，防蠱種衰荷。", "洞口商人婦，時時送夜歌。"]'),
('d9b72390-2ae3-4ce4-bfee-78d283f4b933','碧筒','張子龍','宋','宋诗','song-poetry','','[]','翠作浮漥玉作觴，連蜷浮動玉生香。',64,'全唐诗/poet.song.252000.json','["翠作浮漥玉作觴，連蜷浮動玉生香。", "手中風露分炎國，竅裏乾坤入醉鄉。", "滿座爭誇賽鸚鵡，可人曾憶蓋鴛鴦。", "江長月白空痕在，一夜花神怨索郎。"]'),
('3ecb72f3-0b45-49f8-85ba-a5c31a64e2aa','白雞冠花圖','張子龍','宋','宋诗','song-poetry','','[]','鹿葱花盡鳳仙空，一種奇葩色不同。',64,'全唐诗/poet.song.252000.json','["鹿葱花盡鳳仙空，一種奇葩色不同。", "似带冰霜歸老筆，肯隨籬落鬬群雄。", "太平瑞映園林外，清白名歸草木中。", "留向山窗伴幽獨，半綃斜月五更風。"]'),
('47301e1d-d82f-4912-a981-23f73b8d0db7','高山堂','梁佐厚','宋','宋诗','song-poetry','','[]','危巔層閣倚雲平，一凭闌干醉魄醒。',64,'全唐诗/poet.song.252000.json','["危巔層閣倚雲平，一凭闌干醉魄醒。", "霽雨亂山生淡碧，带風寒竹有餘青。", "孤猿傍石來深澗，幽鳥衝烟入畫屏。", "却讓高僧占仙境，蓬萊不獨在滄溟。"]'),
('d874671f-b402-453e-abad-1da5a24aa951','曉色','陳在山','宋','宋诗','song-poetry','','[]','荒鷄遞寒鳴，寥廓弄清曙。',48,'全唐诗/poet.song.252000.json','["荒鷄遞寒鳴，寥廓弄清曙。", "初陽未離海，薄雲尚籠樹。", "沙明宿鷺驚，巷白行人語。", "瓦瓶自持汲，正在月落處。"]'),
('6cc43a33-9b91-4637-9722-ebb6b55e2737','哭朱龜巖','徐鼎','宋','宋诗','song-poetry','','[]','掩涕愁相向，風淒日滿籬。',48,'全唐诗/poet.song.252000.json','["掩涕愁相向，風淒日滿籬。", "舊交無一在，哭子有餘悲。", "暗竹扃書牖，孤燈上蕙帷。", "寡妻惟抱子，具說病來時。"]'),
('d0806d87-03ad-46e1-b34e-82ce0310c7f1','國清寺','史藴','宋','宋诗','song-poetry','','[]','十里松關路，門開對洞天。',48,'全唐诗/poet.song.252000.json','["十里松關路，門開對洞天。", "山神曾獻地，海衆此安禪。", "鐘磬開巖谷，樓臺跨石泉。", "高峰智者塔，長與赤城連。"]'),
('e847ebaa-731f-42be-b32a-290d509f7f58','效香奩體','謝無競','宋','宋诗','song-poetry','','[]','臙脂濕透污羅衣，春盡蕭郎又不歸。',32,'全唐诗/poet.song.252000.json','["臙脂濕透污羅衣，春盡蕭郎又不歸。", "香冷篆盤簷影轉，一簾紅雨燕雙飛。"]'),
('4bc08b81-e0e8-4206-83d0-59367db78eed','旅中','林某','宋','宋诗','song-poetry','','[]','一劍隨孤影，風霜道路長。',48,'全唐诗/poet.song.252000.json','["一劍隨孤影，風霜道路長。", "何人忽橫笛，有客正思鄉。", "古驛自芳草，空山又夕陽。", "啼猿莫添恨，今夜宿瀟湘。"]'),
('e3835545-144e-4ce5-b34b-d528d0ec0b55','寧壽寺','張湖山','宋','宋诗','song-poetry','','[]','丹級纔升四望賒，香銷無復夢豪華。',64,'全唐诗/poet.song.252000.json','["丹級纔升四望賒，香銷無復夢豪華。", "向來馬氏殫禪力，要擬龍宮作佛家。", "樹老烟霜臺殿古，石封苔蘚井欄斜。", "上人不用蓮花漏，自有林梢報曉鴉。"]'),
('e636cf75-07d0-4809-a759-c2b377e77439','答王學士','林石田','宋','宋诗','song-poetry','','[]','已著山人屐，那能遠入城。',48,'全唐诗/poet.song.252000.json','["已著山人屐，那能遠入城。", "艱難思變姓，老大畏爭名。", "病葉兼蟲下，閑雲背雨行。", "長懷陶靖節，出處意分明。"]'),
('dd2309b9-72dc-43c7-9d21-197af2188a90','茅屋','吳肖巖','宋','宋诗','song-poetry','','[]','茅屋三間小，春風長草芽。',48,'全唐诗/poet.song.252000.json','["茅屋三間小，春風長草芽。", "故園經積雨，老樹不多花。", "黄髪長垂釣，古書猶滿車。", "近來人事別，亦懶問桑麻。"]'),
('fb3c5238-1b79-4bd9-b3a2-93da4fdba31c','陸象山先生墓','郭波','宋','宋诗','song-poetry','','[]','大道久荆榛，歧路苦未併。',216,'全唐诗/poet.song.252000.json','["大道久荆榛，歧路苦未併。", "博約豈不賢，末學恣馳騁。", "口耳謾紛紜，徒知響與影。", "吾心自神明，一掬涵萬境。", "昔者斯文麾，紫陽已獨秉。", "厥德天不孤，時生陸子靜。", "陸朱夫何殊，性天俱炳炳。", "議論偶異同，吁咈豈爲痙。", "考亭任重資，汲多費深綆。", "象山直劈豪，舉手提要領。", "一起跬步間，循循登峻嶺。", "一從百仞巔，洞視下萬頃。", "轍迹隨入途，金蘭同有永。", "何知好事徒，紛紛自燕郢。", "古人亦有言，聞過乃爲幸。", "二翁九京中，豈不重炯炯。", "低頭古墓下，想象見光景。", "有劍不敢懸，爲君發深省。"]'),
('baa41563-010e-4014-b707-5585b8f93a1b','雁山','陳壺中','宋','宋诗','song-poetry','','[]','山川秘靈迹，海近氣常陰。',48,'全唐诗/poet.song.252000.json','["山川秘靈迹，海近氣常陰。", "尊者何年在，樵人去路深。", "雲龍歸絕頂，花鳥傍禪心。", "十八前朝寺，哀猿空夜吟。"]'),
('e412e6fa-098b-4db6-9ec6-f2e3bd06385d','宿連雲樓','陳壺中','宋','宋诗','song-poetry','','[]','自愛山樓宿，微吟此興濃。',48,'全唐诗/poet.song.252000.json','["自愛山樓宿，微吟此興濃。", "凭闌最深處，見月在高峰。", "清唳來孤鶴，新凉生數松。", "葛壇名已遠，何處覓仙蹤。"]'),
('bcbab2aa-eaa9-4a99-831d-0c31e6f5e8ca','春日','宋可菊','宋','宋诗','song-poetry','','[]','門掩東風老，無人載酒過。',48,'全唐诗/poet.song.252000.json','["門掩東風老，無人載酒過。", "半窗春夢短，深竹雨聲多。", "朽樹濕生菌，殘蠶已化蛾。", "因思舊遊地，臺榭廢笙歌。"]'),
('c5094527-bad4-4e72-8517-c2ef4284871e','石橋寺','彭應壽','宋','宋诗','song-poetry','','[]','石磴盤空別島開，深林蒼翠拂衣來。',64,'全唐诗/poet.song.252000.json','["石磴盤空別島開，深林蒼翠拂衣來。", "曇華映日千峰曉，瀑布凌風萬壑哀。", "野寺無人猿自嘯，危梁駭客鶴頻回。", "桃源洞杳知何處，翠髻雲房亦浪猜。"]'),
('5340a43c-a597-48b6-80c9-5b72682538bc','贈西山磊泉庵僧','周自中','宋','宋诗','song-poetry','','[]','門掩古崖碧，霜欺苔逕斑。',48,'全唐诗/poet.song.252000.json','["門掩古崖碧，霜欺苔逕斑。", "去城無一里，此地若深山。", "留客吟松下，驅泉過竹間。", "羨師無外事，相伴白雲閒。"]'),
('511a24cf-1748-4e26-b6cf-dab35b53fa86','山居','周自中','宋','宋诗','song-poetry','','[]','又是閒中一日過，明朝活計看如何。',32,'全唐诗/poet.song.252000.json','["又是閒中一日過，明朝活計看如何。", "拾薪童子歸來晚，報說南山野菜多。"]'),
('6805da9e-3c21-4dc7-9435-7394e2dc2420','陽朔鑑山寺','劉坦齋','宋','宋诗','song-poetry','','[]','鑑山最有登臨勝，門巷縈迴知幾重。',64,'全唐诗/poet.song.252000.json','["鑑山最有登臨勝，門巷縈迴知幾重。", "此日樓頭瞻御墨，何時天上臯飛龍。", "關河痛隔魚紋斷，臣子遥申虎拜恭。", "欲托離騷寫愁思，涉江何處采芙蓉。"]'),
('8fb04fc3-3ddd-4a29-abe9-9794631e96b2','濯纓石','吳朝奉','宋','宋诗','song-poetry','','[]','乘興滄浪水際行，江澄如練接天平。',64,'全唐诗/poet.song.252000.json','["乘興滄浪水際行，江澄如練接天平。", "玉樽暮舉頻添酒，石砥浮簰就濯纓。", "夜月浸潭冰鑑冷，密星沉水浦珠明。", "南山環峙相輝映，直聳蓬萊侍玉清。"]'),
('4c021d05-c538-4361-8462-c9e7a930f38a','水簾洞','張國衡','宋','宋诗','song-poetry','','[]','洞口鮫綃薄，山心玉蕊浮。',48,'全唐诗/poet.song.252000.json','["洞口鮫綃薄，山心玉蕊浮。", "殘雲掛練影，新月下空鈎。", "白鶴仙人去，蒼苔石磴幽。", "奇蹤看不倦，旬日爲淹留。"]'),
('b82514cd-84bf-4a3a-90cd-8f2f0be9457d','詠瀑布','趙至道','宋','宋诗','song-poetry','','[]','飛落寒泉一派高，初聞響似浙江潮。',64,'全唐诗/poet.song.252000.json','["飛落寒泉一派高，初聞響似浙江潮。", "松陰無雨雲長潤，石竇雖晴雪未消。", "素練幾時懸絕壁，白虹千尺跨層霄。", "丹山自是神仙府，弱水流來故不遥。"]'),
('94297f4b-8b6d-45ce-af06-7ded6d4dc80f','賀侍郎  其一','游志甫','宋','宋诗','song-poetry','','[]','松竹青青耐歲寒，長隨初度喜相看。',64,'全唐诗/poet.song.252000.json','["松竹青青耐歲寒，長隨初度喜相看。", "操同一節冰霜勁，身直三朝柱石安。", "顧問正資持從橐，佚閑堅乞領祠官。", "扶危筋力知尤健，肯向風濤袖手觀。"]'),
('8d8c2f22-06f8-4371-ad09-4e93ff0b053b','賀侍郎  其二','游志甫','宋','宋诗','song-poetry','','[]','預喜新元八秩逢，渭川曾說兆非熊。',64,'全唐诗/poet.song.252000.json','["預喜新元八秩逢，渭川曾說兆非熊。", "清癯骨相今迂叟，純雅文章昔醉翁。", "喬木舊推清望重，植槐新長綠陰豐。", "都將祝頌無窮意，寫入金盃壽酒中。"]'),
('90a72608-5bac-4ea1-ba83-24a8027794bf','賀侍郎  其一','王其','宋','宋诗','song-poetry','','[]','寬碧高樓上倚天，等閑蟻垤視凌烟。',64,'全唐诗/poet.song.252000.json','["寬碧高樓上倚天，等閑蟻垤視凌烟。", "歸飛華表三千歲，砥柱中流五百年。", "擺脫浮雲閑富貴，逍遥長日散神仙。", "天公已定乘除計，八十春秋到八千。"]'),
('d0e86053-8538-424b-9206-7c8b7a33dba8','賀侍郎  其二','王其','宋','宋诗','song-poetry','','[]','懸車高蹈姓名香，化得東陽似洛陽。',64,'全唐诗/poet.song.252000.json','["懸車高蹈姓名香，化得東陽似洛陽。", "節亞薌林仍峻潔，貌如笠澤更精强。", "丰標留作耆英樣，壽命應同國祚長。", "歲歲梅花開臘五，來陪青鹿奉霞觴。"]'),
('5c471e9c-e52b-443d-8f58-fb19c12fc6a6','壽先生  其一','丁正持','宋','宋诗','song-poetry','','[]','明善堂前香矗雲，諸生再拜祝莊椿。',64,'全唐诗/poet.song.252000.json','["明善堂前香矗雲，諸生再拜祝莊椿。", "芹香藻綠涵和氣，楓老梅疏健小春。", "有道可爲明主佐，無氈休歎廣文貧。", "烹羔壓酒稱千壽，會看仙桃着子新。"]'),
('293bd83b-0aa2-4804-b20c-ac4c6f960492','壽先生  其二','丁正持','宋','宋诗','song-poetry','','[]','今年生日勝常年，一佛中間萬佛緣。',64,'全唐诗/poet.song.252000.json','["今年生日勝常年，一佛中間萬佛緣。", "善念纔興方寸地，恩光便下九重天。", "花香作供圍方丈，粟粒成功福大千。", "長壽如來更多寶，飽參住世小乘禪。"]'),
('7bbe74ca-bdb4-42ef-bcb3-2dad583b13b8','壽傅守  其一','釋若芬','宋','宋诗','song-poetry','','[]','仙游舍人聲建中，正論久矣排群雄。',32,'全唐诗/poet.song.252000.json','["仙游舍人聲建中，正論久矣排群雄。", "令子賢孫俱有耀，皇天兩耳元非聾。"]'),
('301e3a93-e8fe-4aa3-8cb2-c42930d673d9','壽傅守  其二','釋若芬','宋','宋诗','song-poetry','','[]','鶴髪仙人年德尊，大賢之後更多聞。',32,'全唐诗/poet.song.252000.json','["鶴髪仙人年德尊，大賢之後更多聞。", "風流異日窺前輩，議論班班總不群。"]'),
('67665781-2f3d-4d1e-9fd8-a35207e88aff','壽傅守  其三','釋若芬','宋','宋诗','song-poetry','','[]','當年膴仕早標纓，不共兒曹校疾行。',32,'全唐诗/poet.song.252000.json','["當年膴仕早標纓，不共兒曹校疾行。", "居易獨能遵坦路，未妨六十到名卿。"]'),
('65f5822d-0cc2-4f83-950e-4ff79e1031ce','壽傅守  其四','釋若芬','宋','宋诗','song-poetry','','[]','十年澤國泛吳航，袖有新硎試未嘗。',32,'全唐诗/poet.song.252000.json','["十年澤國泛吳航，袖有新硎試未嘗。", "聊把一麾施老手，便教千里作津梁。"]'),
('53c16a9f-92de-4b0a-8c01-cc6e82c244e9','壽傅守  其五','釋若芬','宋','宋诗','song-poetry','','[]','教令浮民一歲期，只將平易抗澆漓。',32,'全唐诗/poet.song.252000.json','["教令浮民一歲期，只將平易抗澆漓。", "朝廷若用循良課，換取樵川老吏歸。"]'),
('5cac46e5-e3bd-4c4b-872d-57ec9c55dc69','壽傅守  其六','釋若芬','宋','宋诗','song-poetry','','[]','桃花綵綬儼仙衣，寶带垂金腹十圍。',32,'全唐诗/poet.song.252000.json','["桃花綵綬儼仙衣，寶带垂金腹十圍。", "五馬人生真可貴，更欣桑梓共分輝。"]'),
('53a21ee2-a6bd-4de1-b1d1-6591a2e41617','壽傅守  其七','釋若芬','宋','宋诗','song-poetry','','[]','精藏烱目氣藏神，笑語溫然與物春。',32,'全唐诗/poet.song.252000.json','["精藏烱目氣藏神，笑語溫然與物春。", "面骨如拳攙兩耳，此公壽相等銅人。"]'),
('eeef6756-4199-403f-b480-996aa8e7a3a4','壽傅守  其八','釋若芬','宋','宋诗','song-poetry','','[]','堂前三鳳戲斑衣，堂下三槐擢秀枝。',32,'全唐诗/poet.song.252000.json','["堂前三鳳戲斑衣，堂下三槐擢秀枝。", "一歲倦遊歸綠野，榮華鼎鼎看吾兒。"]'),
('bb187553-7704-416f-940e-f8479c9b04d2','壽傅守  其九','釋若芬','宋','宋诗','song-poetry','','[]','寧武堂中白日長，公庭訟息炷爐香。',32,'全唐诗/poet.song.252000.json','["寧武堂中白日長，公庭訟息炷爐香。", "禪床不作蛾眉夢，一枕清風到壽鄉。"]'),
('15e288b2-a3b5-4c0f-8bfe-c901be8d18c4','壽傅守  其一○','釋若芬','宋','宋诗','song-poetry','','[]','秋入東籬破曉霜，黄花不肯媚重陽。',32,'全唐诗/poet.song.252000.json','["秋入東籬破曉霜，黄花不肯媚重陽。", "花神愛惜緣何事，要向今朝薦壽觴。"]'),
('06f40eb6-8688-406d-94b3-840c1f5a40eb','句','釋若芬','宋','宋诗','song-poetry','','[]','不是老僧親寫，曉來誰報平安。',14,'全唐诗/poet.song.252000.json','["不是老僧親寫，曉來誰報平安。"]'),
('059cd2f7-3962-4206-8866-1cc5c82bd46c','壽運使  其一','芹庵','宋','宋诗','song-poetry','','[]','炎蒸忽逐火雲斂，爽氣俄隨玉露瀼。',32,'全唐诗/poet.song.252000.json','["炎蒸忽逐火雲斂，爽氣俄隨玉露瀼。", "不是真賢生間世，爭教煩暑變清凉。"]'),
('dd6050ae-8991-476d-9292-3a65c4e82b05','壽運使  其二','芹庵','宋','宋诗','song-poetry','','[]','玉節煌煌擁使星，泉流地上富全閩。',32,'全唐诗/poet.song.252000.json','["玉節煌煌擁使星，泉流地上富全閩。", "光華勳業知何自，咸詠崧高降甫申。"]'),
('a54506c1-6180-4df3-ac5f-aa946e18a840','壽運使  其三','芹庵','宋','宋诗','song-poetry','','[]','總計寧專借遠方，高勳盟府要深藏。',32,'全唐诗/poet.song.252000.json','["總計寧專借遠方，高勳盟府要深藏。", "明年今日歸清禁，天語傳宣勸壽觴。"]'),
('2769c4c7-2c6a-4a54-8728-5300ded599ca','壽運使  其四','芹庵','宋','宋诗','song-poetry','','[]','白叟黄童喜色開，誕辰喜遇福星來。',32,'全唐诗/poet.song.252000.json','["白叟黄童喜色開，誕辰喜遇福星來。", "滿城牽挽問衙探，祝壽明晨薦幾杯。"]'),
('d396e877-eb00-4acc-9045-b03dcf14c18b','壽運使  其五','芹庵','宋','宋诗','song-poetry','','[]','發糴轉溝蒙厚德，葬枯橫野荷深恩。',32,'全唐诗/poet.song.252000.json','["發糴轉溝蒙厚德，葬枯橫野荷深恩。", "當知仁者從來壽，鶴算龜齡不足論。"]'),
('c22291d0-f81a-4b46-8a74-493c500afff6','壽運使  其六','芹庵','宋','宋诗','song-poetry','','[]','龐眉相對講英猷，盡說當年氣食牛。',32,'全唐诗/poet.song.252000.json','["龐眉相對講英猷，盡說當年氣食牛。", "六十重新開甲子，八千從此富春秋。"]'),
('c764b866-07f8-4cfd-8bc2-7ab9463054d2','壽運使  其七','芹庵','宋','宋诗','song-poetry','','[]','鵬程九萬翼方展，桃實三千花正開。',32,'全唐诗/poet.song.252000.json','["鵬程九萬翼方展，桃實三千花正開。", "再拜願伸難老頌，仙風定合繼蓬萊。"]'),
('c8f23ece-a3bf-4698-b32e-8421dd038e81','壽運使  其八','芹庵','宋','宋诗','song-poetry','','[]','父老偏憐最小官，晚來爭借壽詩看。',32,'全唐诗/poet.song.252000.json','["父老偏憐最小官，晚來爭借壽詩看。", "般門盡說難揮斧，句法丁寧子細安。"]'),
('6a01e59c-01b5-4007-b060-a3b9c41b250d','惠山泉','劉達','宋','宋诗','song-poetry','','[]','靈脈發山根，涓涓才一滴。',96,'全唐诗/poet.song.252000.json','["靈脈發山根，涓涓才一滴。", "寶劍護深源，蒼珉環甃壁。", "鑒影鬚眉分，當暑挹寒冽。", "一酌舉瓢空，過齒如激雪。", "不異醴泉甘，宛同神瀵潔。", "快飲可洗胸，所惜姑濯熱。", "品第冠寰中，名色固已揭。", "世無陸子知，淄澠誰與別。"]'),
('bc46880e-1b07-45a9-a9fe-0ca08509b789','冰泉洞','劉達','宋','宋诗','song-poetry','','[]','飛泉落巍巍，湍水去激激。',48,'全唐诗/poet.song.252000.json','["飛泉落巍巍，湍水去激激。", "未若洞中源，靜淵如得適。", "清潤挹千岩，冷凝涵四壁。", "幽討會有時，煩襟聊與滌。"]'),
('38c32e59-2177-479d-8045-cceaf99328a6','龍淵','劉達','宋','宋诗','song-poetry','','[]','巖巖白石嵌，深泉適此止。',72,'全唐诗/poet.song.252000.json','["巖巖白石嵌，深泉適此止。", "夜雨半山回，春風蟄龍起。", "清明無遁形，溥博有餘美。", "受濁不傷清，納汙非所恥。", "趣操比幽人，泓澄如得己。", "山林乃挺途，真復誰洗耳。"]'),
('6cb12c65-23c3-4c64-ab56-4e703621a5fc','綉嶺亭','劉達','宋','宋诗','song-poetry','','[]','絕境隔囂紛，烟霞張綵繪。',48,'全唐诗/poet.song.252000.json','["絕境隔囂紛，烟霞張綵繪。", "遠目入無中，高情馳物外。", "春田發英華，秋林橫紫翠。", "何時杖屨遊，利名聊委蛻。"]'),
('7ef26e89-62a4-40bd-b44e-02c633680591','題惠山寺','張理','宋','宋诗','song-poetry','','["\u592a\u6e56"]','九山朝暮雲，摇落少游墳。',48,'全唐诗/poet.song.252000.json','["九山朝暮雲，摇落少游墳。", "野蔓碑全沒，晴庵磬亦聞。", "洞偏泉路細，松折鶴巢分。", "高視太湖近，雪濤鷗起群。"]'),
('f2391338-91e1-433e-a43b-fb9e0aeef559','題惠山泉','楊旻','宋','宋诗','song-poetry','','[]','世治山藏錫，山靈地溢泉。',48,'全唐诗/poet.song.252000.json','["世治山藏錫，山靈地溢泉。", "石飴寒不減，水液暑常蠲。", "薦茗能全味，援琴欲絕絃。", "誰言到池盡，餘響更潺湲。"]'),
('c16891da-2336-4a5c-a3af-2f0f124525bb','題惠山翠麓亭','蘇臺父','宋','宋诗','song-poetry','','[]','山勢叢叢向北盤，高僧平日爲開軒。',64,'全唐诗/poet.song.252000.json','["山勢叢叢向北盤，高僧平日爲開軒。", "莫嫌長有車馬到，真愛都無鳥雀喧。", "剩長松篁留日脚，少移桃杏破雲根。", "十年往返未曾厭，煮茗嘗泉到酒樽。"]'),
('e8e0ebb9-9aff-4e14-829e-088edf4810d2','環翠軒','楊介','宋','宋诗','song-poetry','','[]','一上十餘里，携筇始可尋。',48,'全唐诗/poet.song.252000.json','["一上十餘里，携筇始可尋。", "山形三面合，林影四邊深。", "壁暗苔爭長，階荒草亂侵。", "凭高獨覽處，烟靄滿衣襟。"]'),
('40e80cc3-59f9-4c65-adc4-9233cbfcd459','題膠山寺壁','元掔','宋','宋诗','song-poetry','','[]','崗頭鵓鳩鳴，定欲喚晴雨。',60,'全唐诗/poet.song.252000.json','["崗頭鵓鳩鳴，定欲喚晴雨。", "驅車指東山，山下寺亦古。", "道人雙眼青，雪齒起柔語。", "松回萬壑風，落絮趁輕舞。", "日薄詠歸歟，扁舟在烟渚。"]'),
('4da9f35f-ff9d-4cc8-b4f5-5668f0451d54','木芙蓉','李公明','宋','宋诗','song-poetry','','[]','孤芳照寒水，婉娩自幽閑。',48,'全唐诗/poet.song.252000.json','["孤芳照寒水，婉娩自幽閑。", "萬木碧無色，一花紅獨殷。", "秋蓮多綠子，晚槿亦朱顔。", "却笑淵明宅，於今五柳殘。"]'),
('2c905a36-1d9a-4472-9dc8-2c999f52eb55','芙蓉','李公明','宋','宋诗','song-poetry','','[]','野花能白又能紅，也在天工長育中。',32,'全唐诗/poet.song.252000.json','["野花能白又能紅，也在天工長育中。", "長對秋烟顔色好，豈知人世有春風。"]'),
('5600f465-5095-481b-94a0-2a4e25c770d2','中庸','李公明','宋','宋诗','song-poetry','','[]','要識中庸義，中庸乃是庸。',48,'全唐诗/poet.song.252000.json','["要識中庸義，中庸乃是庸。", "不須求勝解，只此是奇功。", "卓卓孤峰上，明明百草中。", "若將聲色捨，聲色却盲聾。"]'),
('1153e00e-1db5-47d5-bfa7-60fc78ebcdda','偶作  其一','李公明','宋','宋诗','song-poetry','','[]','石光火中寄此身，誰論北富與南貧。',32,'全唐诗/poet.song.252000.json','["石光火中寄此身，誰論北富與南貧。", "眼前正愛溪梅瘦，冰雪亭亭笑伴人。"]'),
('12016c04-9c3b-4b49-9068-181ad2ee7c45','偶作  其二','李公明','宋','宋诗','song-poetry','','[]','天涯地角古來傳，今在天涯地角邊。',32,'全唐诗/poet.song.252000.json','["天涯地角古來傳，今在天涯地角邊。", "日日江頭望江水，蠻風瘴雨又淒然。"]'),
('2d99f5eb-7d4e-41c0-9f74-5cd062882546','漫作  其一','李公明','宋','宋诗','song-poetry','','[]','測測日西去，去來無盡時。',48,'全唐诗/poet.song.252000.json','["測測日西去，去來無盡時。", "百年無半在，一事更何爲。", "草屋倚寒木，疏梅橫短籬。", "直能捐世慮，何處不忘歸。"]'),
('f8d16e7d-c2b7-4313-8af1-2fd26d7a7e0e','漫作  其二','李公明','宋','宋诗','song-poetry','','[]','煙冷風寒處，芙蓉三兩枝。',48,'全唐诗/poet.song.252000.json','["煙冷風寒處，芙蓉三兩枝。", "愁懷方換酒，秋意更催詩。", "不遇元白友，寧尋沈宋師。", "誰知苦吟處，髪落一絲絲。"]'),
('0d1d4c2d-f176-4871-a3a5-8d545ddb1816','早梅','李公明','宋','宋诗','song-poetry','','[]','東風才了又西風，群木山中葉葉空。',32,'全唐诗/poet.song.252000.json','["東風才了又西風，群木山中葉葉空。", "只有梅花吹不盡，依然新白抱新紅。"]'),
('f630b7bd-9022-46e3-858d-8c824ca4e2db','遇故人','李公明','宋','宋诗','song-poetry','','[]','虛窗桂子打風聲，夜酌沉沉夜氣清。',32,'全唐诗/poet.song.252000.json','["虛窗桂子打風聲，夜酌沉沉夜氣清。", "三十年間不須說，可堪相照髪星星。"]'),
('2fd881b7-5321-4394-9cdc-8991f7a36c3a','大安人至','李公明','宋','宋诗','song-poetry','','[]','凍雨雜零雪，柴門不敢開。',48,'全唐诗/poet.song.252000.json','["凍雨雜零雪，柴門不敢開。", "持來一片紙，說自大安來。", "元帥方歸沔，邊書又報階。", "忍寒再三問，老弟幾時回。"]'),
('9032e868-e0a5-425d-8944-b2740400b8f6','曉行青村','李公明','宋','宋诗','song-poetry','','[]','關關新鳥逐聲啼，群鷺衝寒帖水飛。',32,'全唐诗/poet.song.252000.json','["關關新鳥逐聲啼，群鷺衝寒帖水飛。", "最恨山雲去如織，不教春色着征衣。"]'),
('953b918a-5933-435c-98ef-c05acc31fd55','曉烟','李公明','宋','宋诗','song-poetry','','[]','曉出倚溪亭，溪煙四面生。',48,'全唐诗/poet.song.252000.json','["曉出倚溪亭，溪煙四面生。", "昏時山綠淺，濃處日紅輕。", "簇簇樹尤好，依依人未行。", "玄暉信蕭放，澄練有佳名。"]'),
('11d2f9d0-26cc-4b8f-832c-1f7bd35c62e9','過修誠館','李公明','宋','宋诗','song-poetry','','[]','敗館冷如許，修誠志已非。',48,'全唐诗/poet.song.252000.json','["敗館冷如許，修誠志已非。", "風光不曾改，人事故相違。", "寸碧雪山出，爭喧風葉飛。", "傷心舊時月，長是送人歸。"]'),
('ff197f9e-b6f1-4a94-954d-4f715a4748da','題曹坑鋪','李公明','宋','宋诗','song-poetry','','[]','明星落深水，晚電起孤雲。',48,'全唐诗/poet.song.252000.json','["明星落深水，晚電起孤雲。", "去去風前棹，迢迢竹外村。", "山回依草驛，岸落出蘆根。", "親月照人冷，今宵清夢魂。"]'),
('93f56510-ec78-487e-96e6-58527e7b9de4','宿鄭山鋪','李公明','宋','宋诗','song-poetry','','[]','行役苦行役，淒凉應奈何。',48,'全唐诗/poet.song.252000.json','["行役苦行役，淒凉應奈何。", "自從多事後，應恨一身多。", "草店張燈宿，石橋乘月過。", "曳裾悲我計，回首一煙簑。"]'),
('9c5c12cb-7bb3-40ad-ad27-49a3f0a60cdd','燈夕','李公明','宋','宋诗','song-poetry','','[]','江風淡淡放初晴，燈火明時月色明。',32,'全唐诗/poet.song.252000.json','["江風淡淡放初晴，燈火明時月色明。", "誰信姮娥要行樂，隨他女伴繞街行。"]'),
('3ee579a8-ea3c-47b4-ad20-6e9f394d5c79','西湖','劉信夫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','長樂鐘聲下九天，萬家春色柳摇烟。',32,'全唐诗/poet.song.252000.json','["長樂鐘聲下九天，萬家春色柳摇烟。", "山迎山送利名客，潮落潮生來去船。"]'),
('b478bbe6-c0ee-49c4-9378-9a1afedbccd4','西湖樂','柯氏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪花滿衣香欲融，王孫白馬金蟠胸。',64,'全唐诗/poet.song.252000.json','["雪花滿衣香欲融，王孫白馬金蟠胸。", "山南山北晚霞紅，須臾直下明珠宮。", "一樣越羅天水碧，亂插寶花長一尺。", "王孫大醉信船流，船尾船頭自吹笛。"]'),
('393fe2a4-d229-4522-b571-508a1bdc11e2','西湖','李氏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舞鳳翔龍拱帝城，秀涵積水駐川靈。',64,'全唐诗/poet.song.252000.json','["舞鳳翔龍拱帝城，秀涵積水駐川靈。", "青山樓觀排雲出，畫舫笙歌隔柳聽。", "撩亂花光浮綺陌，參差馬影繞旗亭。", "振衣直上南峰頂，誰似盤溪却獨醒。"]'),
('9a12f2f2-0f89-4693-b5e1-90a19e4769c0','寄西湖','房灝','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u897f\u6e56"]','昔年曾向西湖住，日夕閑行湖上路。',128,'全唐诗/poet.song.252000.json','["昔年曾向西湖住，日夕閑行湖上路。", "東風二月梅花開，香得孤山無著處。", "六尺瘦藤雙翠屨，眼前物物皆詩具。", "被人牽挽出山來，荷衣盡爲緇塵污。", "世態翻騰不如故，青鏡無情又衰暮。", "富貴浮雲何有哉，一盃且樂閑中趣。", "長江浩浩東流注，夢寐孤山飛不去。", "若見梅花頻寄音，黄金煉出相思句。"]'),
('0da539d4-39ba-466b-8969-f14125effd5c','別西湖  其一','房灝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聞說西湖可樂饑，十年勞我夢中思。',32,'全唐诗/poet.song.252000.json','["聞說西湖可樂饑，十年勞我夢中思。", "湖邊欲買三間屋，問遍人家不要詩。"]'),
('1de5d9de-0b33-4a8e-886b-730f6f76825b','別西湖  其二','房灝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滿城羅綺照青春，湖上風光日日新。',32,'全唐诗/poet.song.252000.json','["滿城羅綺照青春，湖上風光日日新。", "人在畫船泥樣醉，安知西北有兵塵。"]'),
('047db8db-3093-4dd1-b4b0-7357c5029315','別西湖  其三','房灝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','書生老眼厭風塵，天遣臨安看一回。',32,'全唐诗/poet.song.252000.json','["書生老眼厭風塵，天遣臨安看一回。", "便是西湖不留客，也曾身到日邊來。"]'),
('d232d61b-75ed-48d2-a60a-753533826507','梧','董天吉','宋','宋诗','song-poetry','','[]','一樹梧桐爛熳開，紫沉黄玉是花材。',32,'全唐诗/poet.song.252000.json','["一樹梧桐爛熳開，紫沉黄玉是花材。", "誰教著在朝陽地，勾引丹山老鳳來。"]'),
('da7fe0ae-4c84-43dd-96a4-739edc1d6a1d','項王廟','董天吉','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嬴氏亂天紀，群雄各飛揚。',120,'全唐诗/poet.song.252000.json','["嬴氏亂天紀，群雄各飛揚。", "子羽勇無敵，拔劍起戎行。", "熊羆八千士，飈舉度長江。", "威名震列國，斬嬰爇咸陽。", "神力摧萬夫，虎視邈四方。", "雄圖竟不就，楚歌有餘傷。", "故國父老憐，遺廟蒼山傍。", "莓苔生丹堊，蘿蔓延門堂。", "靈魂豈不怍，寧肯還故鄉。", "空令千載下，吊古增慨慷。"]'),
('c83c0143-35ef-4b79-90ab-db94adf82c5a','惠安橋','董天吉','宋','宋诗','song-poetry','','[]','涔陽山水壯南州，千尺飛梁速去郵。',64,'全唐诗/poet.song.252000.json','["涔陽山水壯南州，千尺飛梁速去郵。", "蛟鰐翻濤聲吼夜，虹蜺分雨氣橫秋。", "險疑雲棧通車馬，高比銀河挾女牛。", "鉅萬功成書太史，絕勝舟楫濟中流。"]'),
('33c051f6-a55f-449b-95cb-7e06d3c942ea','采石磯','董天吉','宋','宋诗','song-poetry','','[]','斷磯江上碧嶙峋，漠漠蘆花轉岸瀕。',64,'全唐诗/poet.song.252000.json','["斷磯江上碧嶙峋，漠漠蘆花轉岸瀕。", "舟小風微猶勝馬，山高石立宛如人。", "羨渠釣艇滄波闊，老我征途白髪新。", "寂寞蛾眉在天際，遠烟青處晚雙顰。"]'),
('b0ce60f7-73bd-4995-9550-116ee8033cdb','竹','董天吉','宋','宋诗','song-poetry','','[]','移家徒得竹成林，老節清陰歲月深。',32,'全唐诗/poet.song.252000.json','["移家徒得竹成林，老節清陰歲月深。", "近日孫枝殊聖長，風天雨夜學龍吟。"]'),
('5840b69f-7652-4258-a432-1b47ab6fe481','月中桂','董天吉','宋','宋诗','song-poetry','','[]','雲外仙花衆莫儔，廣寒宮殿足清幽。',64,'全唐诗/poet.song.252000.json','["雲外仙花衆莫儔，廣寒宮殿足清幽。", "根盤天上一輪古，香落人間八月秋。", "玉兔杵頻金粟碎，素娥佩濕露枝稠。", "史君方運吳剛斧，要放清光照此舟。"]'),
('26656579-2d51-4a33-b7f7-55e364fbb7cc','主簿年家丈游敬亭','董天吉','宋','宋诗','song-poetry','','[]','逆旅頻爭席，郊原一振衣。',48,'全唐诗/poet.song.252000.json','["逆旅頻爭席，郊原一振衣。", "聯鑣尋勝去，高蓋拂林飛。", "訪古江山是，懷人歲月非。", "禪林最安穩，棲鳥亦深依。"]'),
('dad898fd-511a-4a8a-b0bc-3534f1f9e2e6','柏山僧房賞花','董天吉','宋','宋诗','song-poetry','','[]','雲房閟孤賞，幽花杳誰攀。',96,'全唐诗/poet.song.252000.json','["雲房閟孤賞，幽花杳誰攀。", "春風不掩私，吹芬滿禪關。", "欣抃破沉寂，覓此芳菲顔。", "亭亭紫錦蓋，濟濟玉笋斑。", "風流冠群英，擢自蓬擢間。", "感物動嘉詠，飛觴且循環。", "上人滅華念，對之心自閑。", "一笑吾未領，夕烟沉遠山。"]'),
('0e36e784-a435-4617-91b8-d8e387a70a92','永慶寺松風亭','董天吉','宋','宋诗','song-poetry','','[]','長松蔭禪宇，柯葉何橚槮。',72,'全唐诗/poet.song.252000.json','["長松蔭禪宇，柯葉何橚槮。", "清風一披拂，奏作綠綺琴。", "虬龍舞空祠，鸞鳳相與吟。", "衆籟起幽聽，太虛本沉沉。", "翛然亭中人，宴坐歡妙音。", "心聞得深悟，明月生東林。"]'),
('d6872846-8592-468e-8d6c-8b322cb5449f','送任浙東廉使  其一','董天吉','宋','宋诗','song-poetry','','[]','曾聞鼻祖牧宣州，又見邦人送我侯。',64,'全唐诗/poet.song.252000.json','["曾聞鼻祖牧宣州，又見邦人送我侯。", "世閲雙旌相絢映，人生五馬自風流。", "西偏清嘯獨孤觀，北望高吟小謝樓。", "此去驊騮諳舊路，定知原隰望咨諏。"]'),
('f6f0510d-f507-4acb-8fbd-badb8465ed7e','送任浙東廉使  其二','董天吉','宋','宋诗','song-poetry','','[]','畫戟凝香禮數殊，敢勤屣履下庸愚。',64,'全唐诗/poet.song.252000.json','["畫戟凝香禮數殊，敢勤屣履下庸愚。", "有時小隊尋花柳，也枉前茅到竹梧。", "對客每曾蒙齒錄，問年直恐混泥塗。", "使君早晚朝天闕，還念滄江釣叟無。"]'),
('c21177dd-6ca2-4bec-a6e2-7860b0f5f151','送經歷龐世安','董天吉','宋','宋诗','song-poetry','','[]','鹿門培隠德，鳳穴産奇毛。',48,'全唐诗/poet.song.252000.json','["鹿門培隠德，鳳穴産奇毛。", "曳組全家貴，談兵此客豪。", "書籤沾雨濕，箭鏑入雲高。", "歸到荆花下，春缸醉玉醪。"]'),
('683b81c8-8914-4e17-a41c-d7c53f257cf9','壽千奴監司','董天吉','宋','宋诗','song-poetry','','[]','綠鬢貂蟬合殿中，輶車又過大江東。',64,'全唐诗/poet.song.252000.json','["綠鬢貂蟬合殿中，輶車又過大江東。", "九重行侍君王宴，五度曾乘御史驄。", "好學襟懷開霽月，愛民心事藹春風。", "夜深香火聽輿誦，好是稱觴壽母同。"]'),
('d3563af7-9f00-4802-97a7-7c47c41d4af0','懷古','王郡守','宋','宋诗','song-poetry','','[]','有唐曾擁萬家兵，節度西南十二城。',32,'全唐诗/poet.song.252000.json','["有唐曾擁萬家兵，節度西南十二城。", "此地得人無盜賊，昔之爲守便公卿。"]'),
('c281c598-5b45-4ae4-8905-068b5d9f8c6d','二疏','無名氏','宋','宋诗','song-poetry','','[]','賢者多財應損智，愚而殖貨易生嗔。',32,'全唐诗/poet.song.252000.json','["賢者多財應損智，愚而殖貨易生嗔。", "二疏教子無他祝，願向先疇加苦辛。"]'),
('7e9fb102-5fa4-4b4c-94f8-4cfba6cbf1da','營道齋','何棄仲','宋','宋诗','song-poetry','','[]','儒行篇中有至論，書齋鄉縣兩存存。',64,'全唐诗/poet.song.252000.json','["儒行篇中有至論，書齋鄉縣兩存存。", "南音楚國鍾儀操，仁術函人孟氏言。", "近信每隨流水到，舊廬凝望度雲屯。", "里非勝母泉君子，循取佳名睹聖門。"]'),
('706ada56-919b-40dd-a5a3-f1f6301c1a5d','舫齋','王宗賢','宋','宋诗','song-poetry','','[]','滿船載月歸時趣，泛宅浮家避世狂。',32,'全唐诗/poet.song.252000.json','["滿船載月歸時趣，泛宅浮家避世狂。", "趺坐舫齋能靜嘿，神馳遊宴無何鄉。"]'),
('e5015cfc-47ac-4130-89df-f1b9132a1624','題漱玉館','王宗賢','宋','宋诗','song-poetry','','[]','寓館欣傳漱玉名，泉流古竇響琮琤。',32,'全唐诗/poet.song.252000.json','["寓館欣傳漱玉名，泉流古竇響琮琤。", "幽窗偃息驚回夢，誤聽虛簷雨滴聲。"]'),
('268da7b3-5f48-4243-b402-ae92483067a8','茶嶺','王宗賢','宋','宋诗','song-poetry','','[]','秀鍾天柱産靈芝，造就仙芽發嫩旗。',32,'全唐诗/poet.song.252000.json','["秀鍾天柱産靈芝，造就仙芽發嫩旗。", "採向先春烟露裏，喊山鳳尾豈爲奇。"]'),
('a57a9b57-5ac2-47a5-ba69-e9c301525a35','九鎖山道中','王宗賢','宋','宋诗','song-poetry','','[]','山縈九鎖路幽深，古木高森積翠陰。',32,'全唐诗/poet.song.252000.json','["山縈九鎖路幽深，古木高森積翠陰。", "自是仙家風景異，欣欣杖策步雲林。"]'),
('5d4a51db-ed7e-45b1-9278-dfdd83bf9227','九鎖山路口','王宗賢','宋','宋诗','song-poetry','','[]','九鎖山深隠洞天，一峰柱聳現雲巔。',32,'全唐诗/poet.song.252000.json','["九鎖山深隠洞天，一峰柱聳現雲巔。", "從茲可達棲真境，透入青霄會衆仙。"]'),
('e255608f-7b42-40f4-b5c5-073b1dd94cdc','大滌山','王宗賢','宋','宋诗','song-poetry','','[]','穹崇千尺壓群巒，終日登臨興未闌。',32,'全唐诗/poet.song.252000.json','["穹崇千尺壓群巒，終日登臨興未闌。", "佳趣清幽塵自滌，昇天猶有許君壇。"]'),
('fb1df87c-9679-47dc-9175-972158eef98a','大滌洞','王宗賢','宋','宋诗','song-poetry','','[]','符札深投進玉函，琅琅震響穴難探。',32,'全唐诗/poet.song.252000.json','["符札深投進玉函，琅琅震響穴難探。", "隔凡不許遊人到，一竇中藏萬丈潭。"]'),
('6b769797-e006-4ba7-9762-f98e650895fa','天柱山','王宗賢','宋','宋诗','song-poetry','','[]','擎天一柱出群峰，時見真仙隠化中。',32,'全唐诗/poet.song.252000.json','["擎天一柱出群峰，時見真仙隠化中。", "瑞應中都成福地，伯元主宰有神功。"]'),
('5af922e2-b069-4165-9e5f-18d8367e0d18','龍蛻洞','王宗賢','宋','宋诗','song-poetry','','[]','羽人遊洞獲龍骸，知是鱗潜蛻骨來。',32,'全唐诗/poet.song.252000.json','["羽人遊洞獲龍骸，知是鱗潜蛻骨來。", "巖穴嵌巉深數丈，驚人蛇虺隔凡才。"]'),
('61bf0eec-2534-44e2-b311-662eaba37510','紅梅','牛士良','宋','宋诗','song-poetry','','[]','隴頭人未來，江南春幾許。',24,'全唐诗/poet.song.252000.json','["隴頭人未來，江南春幾許。", "惆悵玉笛聲，吹落臙脂雨。"]'),
('deda065f-b4a3-4e8b-8a0f-177977f0b3a0','紅梅花','高氏','宋','宋诗','song-poetry','','[]','带雪匆匆別楚雲，天寒依約見湘君。',32,'全唐诗/poet.song.252000.json','["带雪匆匆別楚雲，天寒依約見湘君。", "只疑不合瑶池去，引得春風八九分。"]'),
('bfca3020-b8d9-4070-8dca-dc63c2e9c56f','人日','高氏','宋','宋诗','song-poetry','','[]','雁已有歸心，雪深春未深。',48,'全唐诗/poet.song.252000.json','["雁已有歸心，雪深春未深。", "花風纔一信，人日故多陰。", "詩作平生夢，香添昨夜衾。", "不干書冊事，自怕薄愁侵。"]'),
('5a55e367-268f-45a6-b9fa-1f17b5734f4d','金華山人','無名氏','宋','宋诗','song-poetry','','[]','幽居倚翠巒，塵事不相干。',48,'全唐诗/poet.song.252000.json','["幽居倚翠巒，塵事不相干。", "天地醉來小，琴棋靜裏歡。", "雨苔春徑綠，風竹夜窗寒。", "若問長生術，金爐有寶丹。"]'),
('118de838-b02c-4bf3-8ad8-d251cc8fd5d1','贈人','張氏','宋','宋诗','song-poetry','','[]','雲鬢慵梳睡不忺，倚闌聽燕語虛簷。',32,'全唐诗/poet.song.252000.json','["雲鬢慵梳睡不忺，倚闌聽燕語虛簷。", "春愁自是無重數，生怕東風揭綉簾。"]'),
('1cef2aa6-344d-47cd-bea4-d1cb75cd4b50','擬人生不滿百','無名氏','宋','宋诗','song-poetry','','[]','人生不滿百，譬如朝露晞。',60,'全唐诗/poet.song.252000.json','["人生不滿百，譬如朝露晞。", "白日入虞淵，胡不秉燭嬉。", "大耋嗟晷短，多憂亦奚爲。", "君看玄廬道，轜車無停時。", "伺晨當及旦，佳會當及期。"]'),
('c74dbdfa-a518-4280-aba7-55943228f5e4','春三月過王氏村有感','周宗溥','宋','宋诗','song-poetry','','[]','甲子窮時喪亂頻，天教澤國着閑身。',64,'全唐诗/poet.song.252000.json','["甲子窮時喪亂頻，天教澤國着閑身。", "無情花柳自春色，不覺山河多塞塵。", "他日升平猶未老，此生流落且相親。", "江南江北經行處，莫話衣冠愁殺人。"]'),
('9cdf8798-daaf-4991-a87f-ef34b7c45e6a','見遠亭','魏某','宋','宋诗','song-poetry','','[]','金山鼇聳壓蓬宮，見遠堂開萬象空。',64,'全唐诗/poet.song.252000.json','["金山鼇聳壓蓬宮，見遠堂開萬象空。", "心與天遊身世外，眼隨雲到有無中。", "嶺頭樹接蒼梧北，海面帆來日本東。", "此景舂容吟不盡，丹青圖寫愧宗工。"]'),
('735855b0-2c91-470e-ac35-38c6c9c54484','鳳棲寺','許仲禮','宋','宋诗','song-poetry','','[]','迴環疊嶂倚長空，丹鳳曾棲晻靄中。',64,'全唐诗/poet.song.252000.json','["迴環疊嶂倚長空，丹鳳曾棲晻靄中。", "殿閣至今無燕雀，溪山隨處有梧桐。", "竹榮秀實籠晴景，瀑瀉寒泉潄應風。", "佇看來儀新樂府，吾皇勳德與虞同。"]'),
('5d337127-e3b3-489b-ab1b-0c868b01032f','鴨湖','盧廷輔','宋','宋诗','song-poetry','','[]','並山終日艤孤舟，深入桃蹊訪阮劉。',32,'全唐诗/poet.song.252000.json','["並山終日艤孤舟，深入桃蹊訪阮劉。", "流水落花無問處，居人云是古瀛洲。"]'),
('3af20192-aab4-4e0b-921f-531fc7af738a','湘陰','陳隆之','宋','宋诗','song-poetry','','[]','瀟湘天下景，絕勝是湖山。',48,'全唐诗/poet.song.252000.json','["瀟湘天下景，絕勝是湖山。", "水國三千界，烟光十二鬟。", "乾坤水鑑裏，樓閣畫屏間。", "有路憑風馭，心隨倦鳥還。"]'),
('4dae782b-1e3d-489f-9e3e-1f1aa5f4a9be','花障','姚中一','宋','宋诗','song-poetry','','[]','綠外穠黄白外紅，一屏香錦立春風。',32,'全唐诗/poet.song.252000.json','["綠外穠黄白外紅，一屏香錦立春風。", "天真步障豪難敵，借與王家賽石崇。"]'),
('6391abfc-5441-46d9-84cd-cb3ec7cf68f3','翻經臺白蓮池','包信','宋','宋诗','song-poetry','','[]','野蔓高臺下，前朝記不誣。',72,'全唐诗/poet.song.252000.json','["野蔓高臺下，前朝記不誣。", "金文翻古偈，漢字變胡書。", "綵綫風飄斷，緗簾火燼餘。", "破雲開白日，穿水照芙蕖。", "科斗頻更改，庵園幾遍鋤。", "真門兼逸韵，兩欲慕相如。"]'),
('64b5de9a-b2ae-4680-ae23-99fb7c9cfd10','句','鍾伯澹','宋','宋诗','song-poetry','','[]','百丈平湖一點山，碧琉璃湧小蒲團。',16,'全唐诗/poet.song.252000.json','["百丈平湖一點山，碧琉璃湧小蒲團。"]'),
('b51834c6-4a00-4314-865a-65815795ca88','武平十二峰','孫璋','宋','宋诗','song-poetry','','[]','蒼峰十二碧巖隈，豈是飛從海上來。',32,'全唐诗/poet.song.252000.json','["蒼峰十二碧巖隈，豈是飛從海上來。", "靈境莫將巫峽比，但令雲雨下陽臺。"]'),
('98d3bd45-0533-4376-8e0a-bfa7e3c781ac','鷲峰院','臧子常','宋','宋诗','song-poetry','','[]','望窮山下疑無路，行入壺中別有天。',32,'全唐诗/poet.song.252000.json','["望窮山下疑無路，行入壺中別有天。", "花落春巖朝带雨，月涵秋谷夜聞泉。"]'),
('c8c84cd5-bcdb-45b2-9d47-903c7515718f','白石巖','錢文婉','宋','宋诗','song-poetry','','[]','兩道蟠溪鎖碧山，飄然仙带綠回環。',64,'全唐诗/poet.song.252000.json','["兩道蟠溪鎖碧山，飄然仙带綠回環。", "千巖林木溝渠下，萬頃滄田指掌間。", "霜月天邊清興遠，金鍾雲裏夢魂閒。", "夕陽歸步饒仙騎，懶拂烟蘿下玉關。"]'),
('dbb88cb0-4a3d-476e-ba76-d3d5c0045aed','句','錢文婉','宋','宋诗','song-poetry','','[]','兩岸綺羅春縱目，一天星斗夜凭欄。',16,'全唐诗/poet.song.252000.json','["兩岸綺羅春縱目，一天星斗夜凭欄。"]'),
('0662c274-d73e-4119-a19b-7ca8a696526a','賦江西立上人中巖','李功父','宋','宋诗','song-poetry','','[]','一室在山心，君棲背俗深。',48,'全唐诗/poet.song.252000.json','["一室在山心，君棲背俗深。", "四傍通古道，八面見平林。", "禪有藏雲穴，吟無礙月岑。", "時情任偏黨，誰可浼幽襟。"]'),
('8b02d8a2-d240-47b5-aa20-f0d6ac5e74d1','奉贈德新知府并呈明德通守時中判府良心長司善卿知事','葉見泰','宋','宋诗','song-poetry','','[]','朝發瑞溪縣，夕憩蒼梧城。',96,'全唐诗/poet.song.252000.json','["朝發瑞溪縣，夕憩蒼梧城。", "蒼梧有賢牧，寮宷悉時英。", "宴我南薰樓，宿我嘉魚亭。", "珍肴既重列，美醖仍細傾。", "莫夜繼秉燭，優巫陳楚聲。", "酒闌吐肝膽，驩焉若平生。", "黽勉服王事，行邁有期程。", "贈言無誇解，因之寄深情。"]'),
('bcb2f819-4835-4820-a769-7e698634990b','寄潮州于公九流','無名氏','宋','宋诗','song-poetry','','[]','扁舟如葉路東西，一片灘聲下惡谿。',32,'全唐诗/poet.song.252000.json','["扁舟如葉路東西，一片灘聲下惡谿。", "當日亭臺舊時客，相逢莫惜醉如泥。"]'),
('df2166fa-dec6-416d-9847-581cd8f70e47','黄香梅','李龍高','宋','宋诗','song-poetry','','[]','雲葉重重護雪花，玉人隠隠隔窗紗。',32,'全唐诗/poet.song.252000.json','["雲葉重重護雪花，玉人隠隠隔窗紗。", "雖然不带微酸味，免與時人置齒牙。"]'),
('e186109d-fb6b-4ee5-8bbe-d9056b0ca94d','紙帳','李龍高','宋','宋诗','song-poetry','','[]','㲲巾幾幅蹙鱗鱗，四面清香擁幻身。',32,'全唐诗/poet.song.252000.json','["㲲巾幾幅蹙鱗鱗，四面清香擁幻身。", "夜半夢回花也笑，想君不是飲美人。"]'),
('6a5362fe-44c0-4263-bfec-106a5b5e7307','吟梅','李龍高','宋','宋诗','song-poetry','','[]','聳盡肩樓鶴樣癯，斷橋橫路撚冰鬚。',32,'全唐诗/poet.song.252000.json','["聳盡肩樓鶴樣癯，斷橋橫路撚冰鬚。", "梅花却笑君何事，鍛得詩來瘦似吾。"]'),
('8e7614c8-e9c9-4b37-b5c0-db237a7db44a','老梅','李龍高','宋','宋诗','song-poetry','','[]','雪裏孤根久屈蟠，巖前古貌太高寒。',32,'全唐诗/poet.song.252000.json','["雪裏孤根久屈蟠，巖前古貌太高寒。", "老來想不爲胡廣，免被人將糞土看。"]'),
('6f6b187b-27f9-4591-9932-dabbfee82060','重葉梅','李龍高','宋','宋诗','song-poetry','','[]','雪片層層簇玉林，寒窗光烱照人心。',32,'全唐诗/poet.song.252000.json','["雪片層層簇玉林，寒窗光烱照人心。", "春風著物須平等，那得工夫有淺深。"]'),
('2faf78e0-7427-4d65-ba1b-4e1ea30873dc','小梅','李龍高','宋','宋诗','song-poetry','','[]','小杜文章小李歌，詩名還有小東坡。',32,'全唐诗/poet.song.252000.json','["小杜文章小李歌，詩名還有小東坡。", "莫欺一點丰姿瘦，著得清香儘自多。"]'),
('6039fb2e-30c8-4c14-a4df-5b506035e6ce','瘦梅','李龍高','宋','宋诗','song-poetry','','[]','丰標病後維摩相，骨骼窮來賈島詩。',32,'全唐诗/poet.song.252000.json','["丰標病後維摩相，骨骼窮來賈島詩。", "我亦清臞花莫笑，相逢休要話輕肥。"]'),
('3d6c2d7f-cd52-4eff-8dca-deb6e39dd25d','疏梅','李龍高','宋','宋诗','song-poetry','','[]','瘦削丰姿淡竚妝，三三兩兩立冰霜。',32,'全唐诗/poet.song.252000.json','["瘦削丰姿淡竚妝，三三兩兩立冰霜。", "春風只愛私紅紫，可是梅花欠主張。"]'),
('102f36d2-3836-42c7-8000-2e00857e3706','消梅','李龍高','宋','宋诗','song-poetry','','[]','冰融雪化一須臾，清脆圓鬆壓塞酥。',32,'全唐诗/poet.song.252000.json','["冰融雪化一須臾，清脆圓鬆壓塞酥。", "我有牢愁三萬斛，問君消得幾分無。"]'),
('10a38346-5f89-4755-b263-6be43143b7d0','枯梅','李龍高','宋','宋诗','song-poetry','','[]','腸刳餘得龜皮在，意懶羞將粉面開。',32,'全唐诗/poet.song.252000.json','["腸刳餘得龜皮在，意懶羞將粉面開。", "莫笑老身柴立骨，年時幾費抹塗來。"]'),
('b980e3a9-76c9-4998-9c23-8c2f5067ae57','硬梅','李龍高','宋','宋诗','song-poetry','','[]','風稜玉面耿無塵，鐵脊今成老大身。',32,'全唐诗/poet.song.252000.json','["風稜玉面耿無塵，鐵脊今成老大身。", "莫怪一身多崛强，渠儂元是石心人。"]'),
('53403775-4113-4023-b0cd-c47f3ca7589a','卧梅','李龍高','宋','宋诗','song-poetry','','[]','月橫鶴膝影闌干，枕石眠雲幾歲寒。',32,'全唐诗/poet.song.252000.json','["月橫鶴膝影闌干，枕石眠雲幾歲寒。", "宇宙一身今老矣，瀟瀟風雪擁袁安。"]'),
('e63a3943-f1af-4284-8f3c-5a2c0536f765','品梅','李龍高','宋','宋诗','song-poetry','','[]','疏花鼎立睨霜風，二季居然侍一翁。',32,'全唐诗/poet.song.252000.json','["疏花鼎立睨霜風，二季居然侍一翁。", "生願素絲無點汙，黑衣人自作三公。"]'),
('7ed3c2a4-4742-454b-8593-26730f98a931','苔梅  其一','李龍高','宋','宋诗','song-poetry','','[]','一夜蟠龍裂翠鱗，土花深護玉精神。',64,'全唐诗/poet.song.252000.json','["一夜蟠龍裂翠鱗，土花深護玉精神。", "蒼寒滿樹黄昏月，碧老孤根太古春。", "姑射香薰荷製好，逋仙青入草衣新。", "料應不爲天風冷，自恐冰肌受點塵。"]'),
('f3ee56c3-a5b8-4a9d-aaf7-724c26d343ff','苔梅  其二','李龍高','宋','宋诗','song-poetry','','[]','鐵骨槎牙花四五，虬皮封裹暈爛斑。',32,'全唐诗/poet.song.252000.json','["鐵骨槎牙花四五，虬皮封裹暈爛斑。", "極知不似君芳潔，也要相依度歲寒。"]'),
('439998cc-446f-46b5-b619-56c75b7a82d9','菊梅','李龍高','宋','宋诗','song-poetry','','[]','千林摇落梅新蓓，萬卉披猖菊未莎。',32,'全唐诗/poet.song.252000.json','["千林摇落梅新蓓，萬卉披猖菊未莎。", "歲晚幽人空谷裏，淵明和靖不爭多。"]'),
('790fd294-c40e-42ff-8224-20773cf7d91d','桃梅','李龍高','宋','宋诗','song-poetry','','[]','素面何曾學艷妝，子肥剛带苦心腸。',32,'全唐诗/poet.song.252000.json','["素面何曾學艷妝，子肥剛带苦心腸。", "誰知剗被虛名誤，汙却蓮花是六郎。"]'),
('44bee435-e732-47d4-af38-dc146030d19d','杏梅','李龍高','宋','宋诗','song-poetry','','[]','淡把猩猩血染成，涴他玉雪一生身。',32,'全唐诗/poet.song.252000.json','["淡把猩猩血染成，涴他玉雪一生身。", "相形倘在驪黄外，未必張良似婦人。"]'),
('1a860f47-eb4a-4ba7-872d-f2ea06c86af8','松梅','李龍高','宋','宋诗','song-poetry','','[]','梅誇清節忒高寒，松受微封合駿彈。',32,'全唐诗/poet.song.252000.json','["梅誇清節忒高寒，松受微封合駿彈。", "畢竟兩君俱强項，大夫未必愛秦官。"]'),
('6efb2a0d-2ca9-4957-999d-fb6e4b1eef24','竹梅','李龍高','宋','宋诗','song-poetry','','[]','落落丰標霽月懷，稜稜寒碧隔風埃。',32,'全唐诗/poet.song.252000.json','["落落丰標霽月懷，稜稜寒碧隔風埃。", "耿恭也有孤高節，豈但蘇郎囓雪來。"]'),
('1145f8a1-9f28-4cb0-98bd-7ff0cb2fb573','半開梅','李龍高','宋','宋诗','song-poetry','','[]','雪弄新晴月带霜，風窗暗送幾分香。',32,'全唐诗/poet.song.252000.json','["雪弄新晴月带霜，風窗暗送幾分香。", "翠禽飛過偷相語，不是徐妃也半妝。"]'),
('cf554f0c-a508-4767-920c-6719ab058f77','梅蕊','李龍高','宋','宋诗','song-poetry','','[]','紅蘂盈盈費刻鏤，芳心未露似含羞。',32,'全唐诗/poet.song.252000.json','["紅蘂盈盈費刻鏤，芳心未露似含羞。", "俗兒鼻孔難憑據，只道無香剗恁休。"]'),
('261e1b16-15b6-4d56-b886-326b5a7fed93','梅實','李龍高','宋','宋诗','song-poetry','','[]','青子纍纍薦幾何，眉顰齒軟怎消磨。',32,'全唐诗/poet.song.252000.json','["青子纍纍薦幾何，眉顰齒軟怎消磨。", "可憐只識閑滋味，不道酸心事尚多。"]'),
('61b55fc8-aebc-4adc-92d5-123029fe6e69','梅初落','李龍高','宋','宋诗','song-poetry','','[]','身後傳芳自古難，回頭一笑旅空山。',32,'全唐诗/poet.song.252000.json','["身後傳芳自古難，回頭一笑旅空山。", "飛時莫過妝臺去，只可詩人筆硯間。"]'),
('06e7d7a6-c8f0-4219-9505-fa0dfff3a795','半落梅','李龍高','宋','宋诗','song-poetry','','[]','飄零大半委山坡，雨雪無情尚折磨。',32,'全唐诗/poet.song.252000.json','["飄零大半委山坡，雨雪無情尚折磨。", "縱有風流前輩在，貞元朝士想無多。"]'),
('e55375a9-f776-4a76-bef2-d75f5415f4d9','瓦瓶','李龍高','宋','宋诗','song-poetry','','[]','虛窗凈几坐劬書，姑射仙人伴我癯。',32,'全唐诗/poet.song.252000.json','["虛窗凈几坐劬書，姑射仙人伴我癯。", "誰笑月明家四壁，案頭猶自有珊瑚。"]'),
('5ee206ea-aa1c-4107-aa0e-bec7f4c491f4','梅角','李龍高','宋','宋诗','song-poetry','','[]','朝暮相催鬢易星，酸風無奈送悲聲。',32,'全唐诗/poet.song.252000.json','["朝暮相催鬢易星，酸風無奈送悲聲。", "丁寧莫過黄蘆塞，月落霜寒客半醒。"]'),
('1e67dc5f-6217-4973-9fe9-3eb57ef32a48','梅屏','李龍高','宋','宋诗','song-poetry','','[]','含冰茹鐵似枯槎，淡月濛濛四五花。',32,'全唐诗/poet.song.252000.json','["含冰茹鐵似枯槎，淡月濛濛四五花。", "多少人家誇富貴，數枝和雪寫山茶。"]'),
('e4b1a349-ba85-4dce-8a68-52b91e76bbe0','鄭箋','李龍高','宋','宋诗','song-poetry','','[]','老鄭東都一鉅儒，未知柟樹與梅殊。',32,'全唐诗/poet.song.252000.json','["老鄭東都一鉅儒，未知柟樹與梅殊。", "平生博識猶如此，何况兒曹不讀書。"]'),
('8bd6513b-5d0b-40a3-ad9e-9815559ede7e','仰山祠','李龍高','宋','宋诗','song-poetry','','[]','補之聲價塞江湖，似此村梅筆甚都。',32,'全唐诗/poet.song.252000.json','["補之聲價塞江湖，似此村梅筆甚都。", "近代殘縑零落盡，山靈猶解寶藏無。"]'),
('f286b4a9-4f4c-4f23-880c-a73e808585cc','禹廟','李龍高','宋','宋诗','song-poetry','','[]','古廟峨峨擁衮裳，蒼龍千載鎖飛梁。',32,'全唐诗/poet.song.252000.json','["古廟峨峨擁衮裳，蒼龍千載鎖飛梁。", "向來更有稽山穴，誰把梅花薦一觴。"]'),
('a2f6192a-0697-47f0-88e6-1b04c8ef4f06','成都','李龍高','宋','宋诗','song-poetry','','[]','峽江西去錦官城，聞說梅龍絕可人。',32,'全唐诗/poet.song.252000.json','["峽江西去錦官城，聞說梅龍絕可人。", "不識年來無恙否，武侯祠柏已成薪。"]'),
('196c9d57-1efe-4c57-be1b-ab95ad459a4e','揚州','李龍高','宋','宋诗','song-poetry','','[]','水曹江左一詩家，幾度哦梅到月斜。',32,'全唐诗/poet.song.252000.json','["水曹江左一詩家，幾度哦梅到月斜。", "二十四橋春色裏，相逢只是說瓊花。"]'),
('720be40d-5e47-427a-bbc2-5d8fa348826a','真州','李龍高','宋','宋诗','song-poetry','','[]','儀真誰種滿林梅，兵後危枝半草萊。',32,'全唐诗/poet.song.252000.json','["儀真誰種滿林梅，兵後危枝半草萊。", "便使蕭條君莫歎，也曾慣見太平來。"]'),
('688e2410-ab32-480e-8d99-24cfefa74839','羅浮','李龍高','宋','宋诗','song-poetry','','[]','謾說師雄醉月邊，稚川曾隠此山巔。',32,'全唐诗/poet.song.252000.json','["謾說師雄醉月邊，稚川曾隠此山巔。", "料伊不是丹砂力，只服梅花換得仙。"]'),
('f1dfa296-68fb-4cb2-8f18-22a27595891c','艮嶽','李龍高','宋','宋诗','song-poetry','','[]','鹿銜花去綵雲氣，萬歲山前夢已迷。',32,'全唐诗/poet.song.252000.json','["鹿銜花去綵雲氣，萬歲山前夢已迷。", "萼綠仙人何許覓，斷崖枯樹夜烏啼。"]'),
('5459b4fa-ad26-4134-bfc0-8bd5666c9257','清江','李龍高','宋','宋诗','song-poetry','','[]','玉雪繽紛數丈花，石湖老子極稱誇。',32,'全唐诗/poet.song.252000.json','["玉雪繽紛數丈花，石湖老子極稱誇。", "渠儂不是琴臺女，那得生來傍酒家。"]'),
('ccadccc7-c6eb-4467-877e-60e3c6dc121d','梅關','李龍高','宋','宋诗','song-poetry','','[]','南窺海嶺北江津，截斷青山客路塵。',32,'全唐诗/poet.song.252000.json','["南窺海嶺北江津，截斷青山客路塵。", "千載子真應冷笑，吾儂不是守門人。"]'),
('442f950b-9fa1-46da-ab92-68bb38b42376','梅籬','李龍高','宋','宋诗','song-poetry','','[]','廡下浮沈老伯鸞，樹間寂寞隠申蟠。',32,'全唐诗/poet.song.252000.json','["廡下浮沈老伯鸞，樹間寂寞隠申蟠。", "主翁倘解憐芳潔，莫作藤蘿枳棘看。"]'),
('ac657e76-99dd-4da3-93e1-16b50197b227','月梅','李龍高','宋','宋诗','song-poetry','','[]','仙姝擁珮出雲堆，光射瑶林萬蚌胎。',32,'全唐诗/poet.song.252000.json','["仙姝擁珮出雲堆，光射瑶林萬蚌胎。", "只可范家村裏照，不須移影過蘇臺。"]'),
('767eb1f5-c660-482e-b2ad-563179a0abd8','風梅','李龍高','宋','宋诗','song-poetry','','[]','一番摇曳一番空，香在山蹊野徑中。',32,'全唐诗/poet.song.252000.json','["一番摇曳一番空，香在山蹊野徑中。", "不是老枝藏處密，如何禁得許霜風。"]'),
('fc374c14-8d68-4b66-b09b-0a07b3c85cc4','霜梅','李龍高','宋','宋诗','song-poetry','','[]','青女欺花戰未分，花神直訴與東君。',32,'全唐诗/poet.song.252000.json','["青女欺花戰未分，花神直訴與東君。", "冰山回首知何許，依舊山人住白雲。"]'),
('ab25987b-a2b6-43c6-90c2-5741b37f6907','雪梅','李龍高','宋','宋诗','song-poetry','','[]','雪飛不到越王臺，萬樹千枝滿意開。',32,'全唐诗/poet.song.252000.json','["雪飛不到越王臺，萬樹千枝滿意開。", "花太清高天也妬，轉教滕六御風來。"]'),
('9f040902-d175-49db-a3d3-60940bdf56ce','江梅','李龍高','宋','宋诗','song-poetry','','[]','素衣縞袂影蹁躚，不是天仙是水仙。',32,'全唐诗/poet.song.252000.json','["素衣縞袂影蹁躚，不是天仙是水仙。", "老杜吟魂香禾歇，至今猶繞耒陽邊。"]'),
('677c52c2-6526-4e9d-92bc-505d0472792e','溪梅','李龍高','宋','宋诗','song-poetry','','[]','村北村南眩玉田，孤芳歲晚轉幽妍。',32,'全唐诗/poet.song.252000.json','["村北村南眩玉田，孤芳歲晚轉幽妍。", "老天恐被緇塵染，著在殘山剩水邊。"]'),
('8ee65aa6-92d6-47f0-8555-ff86811371f0','嶺梅','李龍高','宋','宋诗','song-poetry','','[]','雪立孤標不受霾，世間浪蘂等浮埃。',32,'全唐诗/poet.song.252000.json','["雪立孤標不受霾，世間浪蘂等浮埃。", "清高已是無儔伍，更向群山頂上開。"]'),
('742742bd-1c8e-4359-836a-02641b4c1247','村梅','李龍高','宋','宋诗','song-poetry','','[]','不入時妝輩行羞，一生槁淡乏風流。',32,'全唐诗/poet.song.252000.json','["不入時妝輩行羞，一生槁淡乏風流。", "任君約遍宮黄額，莫管村姑守白頭。"]'),
('6861fa8d-32fd-41e8-a60a-25ede1694e58','野梅','李龍高','宋','宋诗','song-poetry','','[]','千山木落澗風豪，十里瑶林月邑高。',32,'全唐诗/poet.song.252000.json','["千山木落澗風豪，十里瑶林月邑高。", "醉尉不來村墅冷，三更繞樹讀離騷。"]'),
('2a0549c3-2803-44f0-8013-88542b54f433','早梅','李龍高','宋','宋诗','song-poetry','','[]','賈少難逃賦鵩災，終童不載使纓回。',32,'全唐诗/poet.song.252000.json','["賈少難逃賦鵩災，終童不載使纓回。", "祇須浪作爭春態，留取孤芳殿後開。"]'),
('c5c35e71-108c-4770-aa27-dfb80101248f','二月梅','李龍高','宋','宋诗','song-poetry','','[]','明知身是雪霜姿，瘦骨稜稜不入時。',32,'全唐诗/poet.song.252000.json','["明知身是雪霜姿，瘦骨稜稜不入時。", "但得春風盈宇宙，老翁也要逐兒嬉。"]'),
('e0b280c7-052d-42c5-a31e-fd8421d4828c','十月梅','李龍高','宋','宋诗','song-poetry','','[]','風撼千林木葉摧，冰霜國裏早春回。',32,'全唐诗/poet.song.252000.json','["風撼千林木葉摧，冰霜國裏早春回。", "一枝參透乾坤緼，生意都從小雪來。"]'),
('b601d524-857e-4497-90e4-84138117582a','寒梅','李龍高','宋','宋诗','song-poetry','','[]','綿衣早覺汙陳子，冬服何能薄顧郎。',32,'全唐诗/poet.song.252000.json','["綿衣早覺汙陳子，冬服何能薄顧郎。", "不是生平誇强項，衆芳無奈怯風霜。"]'),
('bc6dfa1a-f2b2-4315-a89c-8f9354c19b31','鴛鴦梅','李龍高','宋','宋诗','song-poetry','','[]','莫是夷齊幻出身，又疑洛下見機雲。',32,'全唐诗/poet.song.252000.json','["莫是夷齊幻出身，又疑洛下見機雲。", "世人苦被風情累，也把妖名涴却君。"]'),
('bfc03585-1b93-4cc6-8601-c73c1eeffb2b','宮梅','李龍高','宋','宋诗','song-poetry','','[]','冰膚綽約活神仙，天上吹香幾許年。',32,'全唐诗/poet.song.252000.json','["冰膚綽約活神仙，天上吹香幾許年。", "見說額妝人去後，低頭無語懶春妍。"]'),
('ae7d096b-44ea-4f30-959b-72b8656dcb80','驛梅','李龍高','宋','宋诗','song-poetry','','[]','亭邊老樹影𣰦毿，閲盡犀珠壓去驂。',32,'全唐诗/poet.song.252000.json','["亭邊老樹影𣰦毿，閲盡犀珠壓去驂。", "歲晚行人風雪裏，也須障面過江南。"]'),
('362a4363-bb41-4a6d-8959-e282f89a1bf9','梅兄','李龍高','宋','宋诗','song-poetry','','[]','花萼相輝暗遞香，豈無難弟伴元方。',32,'全唐诗/poet.song.252000.json','["花萼相輝暗遞香，豈無難弟伴元方。", "水仙只可供奴隸，合得詩人作雁行。"]'),
('1e61519f-9b6c-494f-b650-0d38424196e7','梅友','李龍高','宋','宋诗','song-poetry','','[]','老子平生怕熱瞞，論心只可話餘酸。',32,'全唐诗/poet.song.252000.json','["老子平生怕熱瞞，論心只可話餘酸。", "劉郎枉了誇豪傑，甘向伾文托歲寒。"]'),
('2665c8de-c105-483d-992a-1f7d1e980824','蠟梅','李龍高','宋','宋诗','song-poetry','','[]','枝枝六出試新妝，色界何曾識許香。',32,'全唐诗/poet.song.252000.json','["枝枝六出試新妝，色界何曾識許香。", "只道單傳餐玉訣，不知還解服硫黄。"]'),
('bbbb34db-363f-420f-8da3-b500037bbee8','烏梅','李龍高','宋','宋诗','song-poetry','','[]','婦舌安能困董宣，曹郎那解汙張翰。',32,'全唐诗/poet.song.252000.json','["婦舌安能困董宣，曹郎那解汙張翰。", "任君百計相熏炙，本性依然带點酸。"]'),
('90a6e175-3cfb-4947-a79a-d47a4d7e3ffe','臙脂梅','李龍高','宋','宋诗','song-poetry','','[]','卸却雲衣明月璫，輕朱傅臉錦爲裳。',32,'全唐诗/poet.song.252000.json','["卸却雲衣明月璫，輕朱傅臉錦爲裳。", "古來美豔多招妬，不似臨風且淡妝。"]'),
('dc0edfbf-efa8-48c3-935c-20fbcc589e44','梅影','李龍高','宋','宋诗','song-poetry','','[]','月地雲階是畫圖，溪腰水面更工夫。',32,'全唐诗/poet.song.252000.json','["月地雲階是畫圖，溪腰水面更工夫。", "平生一片心如雪，爲問姮娥貌得無。"]'),
('b85d64ae-b314-49c6-aea7-b78a6813a9fb','梅香','李龍高','宋','宋诗','song-poetry','','[]','忍饑抱凍老窮崖，一點檀心未肯灰。',32,'全唐诗/poet.song.252000.json','["忍饑抱凍老窮崖，一點檀心未肯灰。", "夷甫彥回空似玉，却曾遺臭汗青來。"]'),
('324b528f-b1fc-41bb-809c-8e8e13092db3','黄香梅','李龍高','宋','宋诗','song-poetry','','[]','雲葉重重護雪花，玉人隠隠隔窗紗。',32,'全唐诗/poet.song.252000.json','["雲葉重重護雪花，玉人隠隠隔窗紗。", "雖然不带微酸味，免與時人置齒牙。"]'),
('dd0b9778-addb-4947-b597-23d026de8b3d','紫蔕梅','李龍高','宋','宋诗','song-poetry','','[]','外面看來本色非，香袍隠映省垣薇。',32,'全唐诗/poet.song.252000.json','["外面看來本色非，香袍隠映省垣薇。", "誰知傲睨風霜底，不改平生一布衣。"]'),
('3619dbb2-abba-4391-b081-a8b66431ff36','綠萼梅','李龍高','宋','宋诗','song-poetry','','[]','懶將冰萼試紅妝，也不隨宜傳蠟黄。',32,'全唐诗/poet.song.252000.json','["懶將冰萼試紅妝，也不隨宜傳蠟黄。", "當日瓊林消息斷，綠衣猶带舊時香。"]'),
('8501d0bb-84e6-41cc-9d3b-26be66f5d619','鹽梅','李龍高','宋','宋诗','song-poetry','','[]','世味明知可口難，到頭終不換寒酸。',32,'全唐诗/poet.song.252000.json','["世味明知可口難，到頭終不換寒酸。", "直須袖却和羹手，何必貪居鼎鼐間。"]'),
('b6fb819b-9b9f-446b-8cb7-4758329814ba','八出梅','李龍高','宋','宋诗','song-poetry','','[]','宣城妙品世無雙，不肯隨時一樣妝。',32,'全唐诗/poet.song.252000.json','["宣城妙品世無雙，不肯隨時一樣妝。", "黨錮諸賢銷鑠盡，至今千載骨猶香。"]'),
('4dbbc435-a9de-443b-81c1-0c3fc5cd1a7f','九英梅','李龍高','宋','宋诗','song-poetry','','[]','才子隨班下玉墀，精光九出射晴曦。',32,'全唐诗/poet.song.252000.json','["才子隨班下玉墀，精光九出射晴曦。", "看來不是文章瑞，似是梅花恨殺伊。"]'),
('99a16f9a-2cef-465a-9869-be9a712f017a','種梅','李龍高','宋','宋诗','song-poetry','','[]','別嶺移根置小園，半鋤明月半鋤雲。',32,'全唐诗/poet.song.252000.json','["別嶺移根置小園，半鋤明月半鋤雲。", "世間下是無花卉，若個清高得似君。"]'),
('fb48c228-d4f2-4be2-811f-4a3a42ed8066','接梅','李龍高','宋','宋诗','song-poetry','','[]','中條隠士裂唐麻，甪里先生就漢車。',32,'全唐诗/poet.song.252000.json','["中條隠士裂唐麻，甪里先生就漢車。", "一種寒酸真本色，羞將槁淡博繁華。"]'),
('d3a796fe-927b-4841-bca3-4ce04b81c1da','催梅','李龍高','宋','宋诗','song-poetry','','[]','笛聲未了鼓轟雷，盡道梅寒苦要催。',32,'全唐诗/poet.song.252000.json','["笛聲未了鼓轟雷，盡道梅寒苦要催。", "抵死爭春如許急，有花畢竟待時來。"]'),
('897c5d81-ec78-4739-a2c6-a5f402e51558','探梅','李龍高','宋','宋诗','song-poetry','','[]','問訊南枝開未開，花神許我日徘徊。',32,'全唐诗/poet.song.252000.json','["問訊南枝開未開，花神許我日徘徊。", "桐江一縷清風在，莫誤劉郎物色來。"]'),
('bfccbf31-d179-4b7a-8181-147cff59d624','買梅','李龍高','宋','宋诗','song-poetry','','["\u897f\u6e56"]','擔頭挑得幾枝斜，過我西湖處士家。',32,'全唐诗/poet.song.252000.json','["擔頭挑得幾枝斜，過我西湖處士家。", "莫向侯門高索價，貴人多愛牡丹花。"]'),
('38ad1659-446e-4c05-8d22-7448210d7bcb','看梅','李龍高','宋','宋诗','song-poetry','','[]','蹋雪迢迢過水涯，翠禽見客却咨嗟。',32,'全唐诗/poet.song.252000.json','["蹋雪迢迢過水涯，翠禽見客却咨嗟。", "此翁只識孤山路，不識玄都觀裏花。"]'),
('41c4f2d0-b530-4928-a32b-d58be895ff99','憶梅','李龍高','宋','宋诗','song-poetry','','[]','飄蓬萬里隔風沙，夢到江南未到家。',32,'全唐诗/poet.song.252000.json','["飄蓬萬里隔風沙，夢到江南未到家。", "料得夜深霜月苦，幾人揮淚說梅花。"]'),
('52474d56-c963-4dae-9415-e30c7e9dfb38','和任比部憶梅','李龍高','宋','宋诗','song-poetry','','[]','痛憶梅開易得殘，既殘憔悴不堪看。',32,'全唐诗/poet.song.252000.json','["痛憶梅開易得殘，既殘憔悴不堪看。", "年年長被清香誤，爭似閑栽竹數竿。"]'),
('55f5bc0c-c602-4491-9bec-442108f20b38','賞梅','李龍高','宋','宋诗','song-poetry','','[]','我愛溪橋半樹開，幾回覓句當銜杯。',32,'全唐诗/poet.song.252000.json','["我愛溪橋半樹開，幾回覓句當銜杯。", "江南不欠花如雪，自是遊人不看來。"]'),
('72693ffd-4ff0-43a4-8223-2c0642d2296c','射梅','李龍高','宋','宋诗','song-poetry','','[]','由基去後揮瞻來，不慣穿楊慣射梅。',32,'全唐诗/poet.song.252000.json','["由基去後揮瞻來，不慣穿楊慣射梅。", "寄語東居莫塗抹，犧樽自是木之災。"]'),
('9089856b-1bab-4feb-b2ce-ad6ffb5db0b6','折梅','李龍高','宋','宋诗','song-poetry','','[]','詩老流離蜀劍關，放臣憔悴楚江干。',32,'全唐诗/poet.song.252000.json','["詩老流離蜀劍關，放臣憔悴楚江干。", "爭如留取微酸味，莫逐浮花一笑殘。"]'),
('ffff6de8-0cff-44df-9434-fd5186174c30','寄梅','李龍高','宋','宋诗','song-poetry','','[]','范子經年別陸郎，陸郎遠致一枝香。',32,'全唐诗/poet.song.252000.json','["范子經年別陸郎，陸郎遠致一枝香。", "料伊正作關山夢，望見梅花也斷腸。"]'),
('9a92ea05-299b-4826-8b47-d29cfaeee4b9','道山堂','李龍高','宋','宋诗','song-poetry','','[]','疏花斜映玉玲瓏，曾見誠翁與放翁。',32,'全唐诗/poet.song.252000.json','["疏花斜映玉玲瓏，曾見誠翁與放翁。", "猶有舊時相識在，幾回搔首立春風。"]'),
('30d1eb7d-feae-4bd2-b70f-6df754c058fb','茅舍','李龍高','宋','宋诗','song-poetry','','[]','深村古木路三叉，路外溪流溪外沙。',32,'全唐诗/poet.song.252000.json','["深村古木路三叉，路外溪流溪外沙。", "背水短籬花似雪，遥知不是四娘家。"]'),
('fa3ff1b9-3996-4066-921e-80827fd27018','梅亭','李龍高','宋','宋诗','song-poetry','','[]','飛甍面面枕冰霜，雲抵輕紗月抵窗。',32,'全唐诗/poet.song.252000.json','["飛甍面面枕冰霜，雲抵輕紗月抵窗。", "莫怪能寒吟徹夕，一生無夢到沈香。"]'),
('2fdae35d-1e90-4091-8059-df56bdeface0','梅臺','李龍高','宋','宋诗','song-poetry','','[]','彈壓群芳不敢開，清高地位隔塵埃。',32,'全唐诗/poet.song.252000.json','["彈壓群芳不敢開，清高地位隔塵埃。", "擡頭一見風霜面，莫是花中御史來。"]'),
('7d8700b0-7209-44f0-a467-16bac5ea3626','梅窗','李龍高','宋','宋诗','song-poetry','','[]','月射雲綃印玉腮，風穿罅隙度香埃。',32,'全唐诗/poet.song.252000.json','["月射雲綃印玉腮，風穿罅隙度香埃。", "莫將易向花邊讀，惹得周公入夢來。"]'),
('63db4881-dbc3-4a9f-851c-33574df5ca80','綠珠樓','李龍高','宋','宋诗','song-poetry','','[]','危甍連綺百千株，人去鶑飛半朵無。',32,'全唐诗/poet.song.252000.json','["危甍連綺百千株，人去鶑飛半朵無。", "太白莫嗟金谷樹，絳霄樓外亦平蕪。"]'),
('f2b780b8-5724-42a7-a4dd-7e3e0eb0f26a','紅羅亭','李龍高','宋','宋诗','song-poetry','','[]','紅雲絳雪鏤繁華，侍宴流連徹暮鴉。',32,'全唐诗/poet.song.252000.json','["紅雲絳雪鏤繁華，侍宴流連徹暮鴉。", "車馬不來歌吹斷，春風一半屬誰家。"]'),
('492bad9a-43e8-4a6f-b295-c89da1af9f12','玉堂','李龍高','宋','宋诗','song-poetry','','[]','斗柄參旗插屋頭，巡簷繞樹儘風流。',32,'全唐诗/poet.song.252000.json','["斗柄參旗插屋頭，巡簷繞樹儘風流。", "誰知終带山林味，不涴些兒富貴羞。"]'),
('b400de76-a5d2-4e6e-ad8e-0d802fb1ca2a','東閣','李龍高','宋','宋诗','song-poetry','','[]','杜老花邊慣撚鬚，却憐花傍驛亭居。',32,'全唐诗/poet.song.252000.json','["杜老花邊慣撚鬚，却憐花傍驛亭居。", "德公便使遊城府，肯受紅塵半點無。"]'),
('1caa8e4a-4ba3-4fa9-a926-147b48f204a0','蘇詞','李龍高','宋','宋诗','song-poetry','','[]','翩翩綵筆賦梅花，只憶朝雲不憶家。',32,'全唐诗/poet.song.252000.json','["翩翩綵筆賦梅花，只憶朝雲不憶家。", "爲說坡仙休悵恨，昭君猶自弄琵琶。"]'),
('5265a263-fa15-465e-b796-6fad6d9339fe','宋賦','李龍高','宋','宋诗','song-poetry','','[]','姚子編文去取難，將渠例與白歌刪。',32,'全唐诗/poet.song.252000.json','["姚子編文去取難，將渠例與白歌刪。", "後人要識心如鐵，却向桃花賦裏看。"]'),
('f3c6152a-04c0-4db0-87a6-2af98d94f942','陶詩','李龍高','宋','宋诗','song-poetry','','[]','靖節當年不賦渠，僅題一字果何如。',32,'全唐诗/poet.song.252000.json','["靖節當年不賦渠，僅題一字果何如。", "分明詩是梅花樣，剩說梅花詩更癯。"]'),
('fe178de5-71a5-41e5-9a9f-9ec2728e214d','讀范譜','李龍高','宋','宋诗','song-poetry','','[]','劉叟空將芍藥誇，歐公浪譜牡丹花。',32,'全唐诗/poet.song.252000.json','["劉叟空將芍藥誇，歐公浪譜牡丹花。", "如君更把凡花品，俗了吳門一范家。"]'),
('9b44f8c4-7cb9-4f1b-8130-9bd294c7718b','白髪','傅夢得','宋','宋诗','song-poetry','','[]','勳業未能成，青銅照眼明。',48,'全唐诗/poet.song.252000.json','["勳業未能成，青銅照眼明。", "星霜驚入鬢，天地覺無情。", "纔近半百歲，漸生三兩莖。", "兒童勸休鑷，浪得老成名。"]'),
('0c9e844d-1c77-4d1d-a81e-28e7877be973','贈澄鑑','傅夢得','宋','宋诗','song-poetry','','[]','一見便忘形，生涯畫作屏。',48,'全唐诗/poet.song.252000.json','["一見便忘形，生涯畫作屏。", "心和秋水澈，眼带古銅青。", "客裏江湖闊，人間筆硯靈。", "他年重會面，我亦鬢星星。"]'),
('7712184f-fe44-421a-9386-7b0a9c65075f','皂鏡冊','傅夢得','宋','宋诗','song-poetry','','[]','依然一冊巧裝成，故紙爲胎越樣輕。',32,'全唐诗/poet.song.252000.json','["依然一冊巧裝成，故紙爲胎越樣輕。", "四畔黑雲都罩盡，中間只有月長明。"]'),
('6d50d706-1dae-4e02-8be8-e18c1bc771b0','伍林舟中','傅夢得','宋','宋诗','song-poetry','','[]','人生蹤跡抵浮萍，客裏行藏分外輕。',64,'全唐诗/poet.song.252000.json','["人生蹤跡抵浮萍，客裏行藏分外輕。", "酒力禁持風半日，櫓梢摇動月三更。", "暫携琴劍隨身去，且得溪山入眼清。", "著脚水鄉吟思苦，未知誰得與詩盟。"]'),
('40ed6185-7a9f-4958-a34a-80a5e6d33123','江湖偉觀','傅夢得','宋','宋诗','song-poetry','','[]','倚徧闌干指顧間，吟身恨不早生翰。',64,'全唐诗/poet.song.252000.json','["倚徧闌干指顧間，吟身恨不早生翰。", "幾多風月閑中占，一望江湖眼界寬。", "胥浪掀天秋際闊，逋梅得月夜深寒。", "有時聽得漁歌晚，驚起沙鷗雪一團。"]'),
('3a144d12-d642-4ff9-9072-1af9f0a994fe','逈居縣','傅夢得','宋','宋诗','song-poetry','','[]','經過太怱怱，山行去路通。',48,'全唐诗/poet.song.252000.json','["經過太怱怱，山行去路通。", "客衣沾曉露，縣陌带春風。", "沽酒從村市，騎牛任老翁。", "相逢有吟者，約我醉城中。"]'),
('6a8685d8-8ee3-4e8f-8cf6-420402f24f58','錢塘','傅夢得','宋','宋诗','song-poetry','','[]','蒼茫空闊海雲開，浙水東西隔岸隈。',64,'全唐诗/poet.song.252000.json','["蒼茫空闊海雲開，浙水東西隔岸隈。", "我到龍山呼渡晚，誰從漁浦趁潮回。", "驀驚塞雁聲嘹嚦，靜看沙鷗獨往來。", "山外中原皆在望，英雄誰肯便心灰。"]'),
('966ad48b-a3a5-417e-9d5c-f97639e95b03','許村','傅夢得','宋','宋诗','song-poetry','','[]','信步水之濱，閑中着此身。',48,'全唐诗/poet.song.252000.json','["信步水之濱，閑中着此身。", "蕭條僧寺近，來往客舟頻。", "村酒難成醉，山花亦有春。", "人生要行樂，何苦戀京塵。"]'),
('d6b7395e-76d7-4fac-b351-5dd019b9d2e8','元友山','傅夢得','宋','宋诗','song-poetry','','[]','清夢繞騷壇，相逢一笑間。',48,'全唐诗/poet.song.252000.json','["清夢繞騷壇，相逢一笑間。", "江湖無此友，聲價重於山。", "吟就髭猶撚，文窮鬢欲斑。", "移家離城市，世事不相關。"]'),
('625f0763-28f2-4b7e-8bb7-4f4c2d9b7793','水樂洞','傅夢得','宋','宋诗','song-poetry','','[]','踏破芒鞋客倦歸，暮雲深處夕陽西。',32,'全唐诗/poet.song.252000.json','["踏破芒鞋客倦歸，暮雲深處夕陽西。", "身如晚鶴無拘束，向此亭中獨自棲。"]'),
('a44f9d6b-0f17-400f-aa71-5cf2def0a9a9','江湖','傅夢得','宋','宋诗','song-poetry','','[]','落魄江湖上，人疑是謫仙。',48,'全唐诗/poet.song.252000.json','["落魄江湖上，人疑是謫仙。", "四時逢酒醉，長日擁書眠。", "點鬢惟添雪，知心只有天。", "林泉難久困，未整釣魚船。"]'),
('2bea8e24-afea-483f-bcf1-a7c5b6f01243','垂虹橋','傅夢得','宋','宋诗','song-poetry','','[]','一舸西風到水鄉，半痕殘月浸滄浪。',64,'全唐诗/poet.song.253000.json','["一舸西風到水鄉，半痕殘月浸滄浪。", "湖中有影渾如畫，天下無橋似此長。", "題品垂虹多古作，去來征雁带秋霜。", "三高千古英靈在，經過祠前菊正黄。"]'),
('9e2e05c1-33f1-48e4-951c-9a78f543f92b','后土祠瓊花','傅夢得','宋','宋诗','song-poetry','','[]','朱闌遮護石爲臺，只說揚州地可栽。',64,'全唐诗/poet.song.253000.json','["朱闌遮護石爲臺，只說揚州地可栽。", "若與八仙同日語，因何九蘂有香來。", "此花堪詠奚須辯，自舊曾移不肯開。", "得得無雙亭上望，臨祠酹酒葉爲盃。"]'),
('0ebaa388-70d5-49c4-84f0-4b48a7813f0f','齋中','傅夢得','宋','宋诗','song-poetry','','[]','惟有閑中日最長，薰風拂拂透脩廊。',64,'全唐诗/poet.song.253000.json','["惟有閑中日最長，薰風拂拂透脩廊。", "半窗槐影侵書葉，一曲蟬聲送夕陽。", "强把茶甌醒困眼，久無詩債抖枯腸。", "何妨自取離騷讀，且向齋爐爇晚香。"]'),
('dbbc0e7c-d781-4b97-8dee-1f7e836ba4c5','多景樓','傅夢得','宋','宋诗','song-poetry','','[]','自來京口足清游，天下聞名只此樓。',64,'全唐诗/poet.song.253000.json','["自來京口足清游，天下聞名只此樓。", "山結人愁成北固，江和客淚向東流。", "痕留很石傳千古，望斷中原知幾州。", "有景雖多非可樂，明朝準擬渡瓜洲。"]'),
('aa54fb89-0e2b-46e3-8e1d-9f0c75cb8f21','沖天樓','傅夢得','宋','宋诗','song-poetry','','[]','人生行樂是便宜，慣入深林細品題。',64,'全唐诗/poet.song.253000.json','["人生行樂是便宜，慣入深林細品題。", "有石兩行如壁立，登樓一望覺天低。", "亭前秋意驚松露，山外湖光拍柳堤。", "此景欲吟吟不盡，夜深分付野猿啼。"]'),
('6929516e-028e-4c1d-b943-d0d3b3edbb57','揚州竹西樓','傅夢得','宋','宋诗','song-poetry','','[]','自從騎鶴到，船泊畫橋堤。',48,'全唐诗/poet.song.253000.json','["自從騎鶴到，船泊畫橋堤。", "新酒斟花露，高樓傍竹西。", "拭盤將蟹擘，拂壁把詩題。", "早過瓜洲渡，秋深怕馬嘶。"]'),
('afd0af1e-7f77-46b0-afbf-b7f27c03f371','四山任鼓院','傅夢得','宋','宋诗','song-poetry','','[]','曾向西風把別盃，知君黄色上眉催。',32,'全唐诗/poet.song.253000.json','["曾向西風把別盃，知君黄色上眉催。", "浙江莫道音書隔，一日潮聲兩度來。"]'),
('0db53911-9722-426b-b5d1-67e7c4415a50','鄭松窗','傅夢得','宋','宋诗','song-poetry','','[]','相逢交未深，一笑便生春。',48,'全唐诗/poet.song.253000.json','["相逢交未深，一笑便生春。", "松作四時友，窗無半點塵。", "詩囊爲活計，廛隠着吟身。", "似此知音者，江湖能幾人。"]'),
('373586e0-a1bc-4bd4-9dc2-87357cd7fb4c','過蘭亭','傅夢得','宋','宋诗','song-poetry','','[]','右軍堂下過，尚有讀書壇。',48,'全唐诗/poet.song.253000.json','["右軍堂下過，尚有讀書壇。", "水曲觴何在，池荒墨未乾。", "人多尋古跡，我亦渡寒灘。", "要把蘭亭記，摩挲醉眼看。"]'),
('2ef09d79-aba8-490b-abfe-e9536e68f93f','宿鎮江丹陽館','傅夢得','宋','宋诗','song-poetry','','[]','暫泊喜天晴，丹陽住晚程。',48,'全唐诗/poet.song.253000.json','["暫泊喜天晴，丹陽住晚程。", "半窗留月色，隔岸送鐘聲。", "江繞金山寺，雲生鐵甕城。", "片帆催早發，莫待暗潮平。"]'),
('d8f8b80b-ffc2-4ec9-97d3-7ee8a95a7182','德清永興寺','傅夢得','宋','宋诗','song-poetry','','[]','蒼寒松竹滿，此地稱僧居。',48,'全唐诗/poet.song.253000.json','["蒼寒松竹滿，此地稱僧居。", "寺僻啼林鳥，廊空響木魚。", "煮茶燒樹葉，带雨翦園蔬。", "待了功名債，重來買地鋤。"]'),
('9f82f2d5-fd50-4f64-af20-1876dcb4a964','德清太善寺','傅夢得','宋','宋诗','song-poetry','','[]','西風吹客過唐栖，袖拂塵埃讀斷碑。',32,'全唐诗/poet.song.253000.json','["西風吹客過唐栖，袖拂塵埃讀斷碑。", "適意遶廊詢古跡，老僧引看建炎詩。"]'),
('2834e9af-60f1-4049-981a-d48e472d1107','金山寺','傅夢得','宋','宋诗','song-poetry','','[]','昨夜宿江口，客衣風已飄。',48,'全唐诗/poet.song.253000.json','["昨夜宿江口，客衣風已飄。", "兩峰參塔頂，一寺裹山腰。", "水拍瓜洲渡，煙生揚子橋。", "尋花并問柳，端的在明朝。"]'),
('ba164c34-7849-4e12-bd89-4eac1f716006','平江承天寺','傅夢得','宋','宋诗','song-poetry','','[]','古剎號承天，規模闊萬間。',48,'全唐诗/poet.song.253000.json','["古剎號承天，規模闊萬間。", "寺中重有寺，山外更無山。", "供佛香猶在，尋僧客亦閑。", "渡淮難久駐，此去別閶關。"]');
